window.NZ_OPISY=window.NZ_OPISY||{};window.NZ_OPISY["a"]={"Andrzej": "<b>Andrzej</b> – <a href=\"https://pl.wikipedia.org/wiki/Imi%C4%99\" target=\"_blank\" rel=\"noopener noreferrer\">imię</a> męskie pochodzenia <a href=\"https://pl.wikipedia.org/wiki/J%C4%99zyk_grecki\" target=\"_blank\" rel=\"noopener noreferrer\">greckiego</a>. Pochodzi od greckiego imienia Andréas, którego rdzeń <i>andr-</i> nawiązuje do znaczenia: „człowiek, mężczyzna, taki jak mężczyzna” (inne źródło tłumaczy go jako „dzielny, mężny”). To greckie imię Andréas nosił jeden z <a href=\"https://pl.wikipedia.org/wiki/Aposto%C5%82\" target=\"_blank\" rel=\"noopener noreferrer\">apostołów</a>, brat Szymona Piotra. Imię występuje także w <a href=\"https://pl.wikipedia.org/wiki/Biblia\" target=\"_blank\" rel=\"noopener noreferrer\">Biblii</a>. W języku polskim przybrał formę Andrzej<b>.</b>", "Adam": "<b>Adam</b> – <a href=\"https://pl.wikipedia.org/wiki/Imi%C4%99\" target=\"_blank\" rel=\"noopener noreferrer\">imię</a> męskie pochodzenia <a href=\"https://pl.wikipedia.org/wiki/Ludy_semickie\" target=\"_blank\" rel=\"noopener noreferrer\">semickiego</a>. W języku <a href=\"https://pl.wikipedia.org/wiki/J%C4%99zyk_hebrajski\" target=\"_blank\" rel=\"noopener noreferrer\">hebrajskim</a> אדום <i>adom</i> oznacza „czerwony”, od koloru ziemi, z której <a href=\"https://pl.wikipedia.org/wiki/Adam_i_Ewa\" target=\"_blank\" rel=\"noopener noreferrer\">Adam</a> był ulepiony. Bardziej jednak prawdopodobne, że <i>Adam</i> wywodzi się od hebrajskiego słowa <i>adamah</i>, które oznacza „ziemię, rolę”, wtedy znaczyłoby „rolnik”, albo „że człowiek, z ziemi powstały, do ziemi wróci”. W takim ujęciu, używane jest zazwyczaj w <a href=\"https://pl.wikipedia.org/wiki/Stary_Testament\" target=\"_blank\" rel=\"noopener noreferrer\">Starym Testamencie</a>, chociaż w początkowych rozdziałach Starego Testamentu przyjęło się traktować je jako imię własne. Także w <a href=\"https://pl.wikipedia.org/wiki/J%C4%99zyki_a%C5%82tajskie\" target=\"_blank\" rel=\"noopener noreferrer\">językach ałtajskich</a> słowo <i>adam</i> oznacza „człowiek”. Współcześnie dopatruje się pochodzenia imienia w <a href=\"https://pl.wikipedia.org/wiki/J%C4%99zyk_sumeryjski\" target=\"_blank\" rel=\"noopener noreferrer\">języku sumeryjskim</a>, w którym miał oznaczać „mój ojciec” (od <i>ada.mu</i>), <a href=\"https://pl.wikipedia.org/wiki/J%C4%99zyk_akadyjski\" target=\"_blank\" rel=\"noopener noreferrer\">akadyjskim</a> „zbudowany”, lub „zrodzony”', a także w <a href=\"https://pl.wikipedia.org/wiki/J%C4%99zyk_arabski\" target=\"_blank\" rel=\"noopener noreferrer\">arabskim</a> „łączyć się” (od <i>adama</i>).", "Antoni": "<b>Antoni</b> – <a href=\"https://pl.wikipedia.org/wiki/Imi%C4%99\" target=\"_blank\" rel=\"noopener noreferrer\">imię</a> męskie pochodzenia <a href=\"https://pl.wikipedia.org/wiki/%C5%81acina\" target=\"_blank\" rel=\"noopener noreferrer\">łacińskiego</a>. Pochodzi od <i>Antonii</i> (<a href=\"https://pl.wikipedia.org/wiki/Drzewo_genealogiczne_Antoniusz%C3%B3w\" target=\"_blank\" rel=\"noopener noreferrer\">Antoniuszów</a>), znaczącego rodu w starożytnym <a href=\"https://pl.wikipedia.org/wiki/Rzym\" target=\"_blank\" rel=\"noopener noreferrer\">Rzymie</a>. Wśród imion nadawanych nowo narodzonym dzieciom, Antoni w 2017, 2018, 2019, 2020, 2021 r. zajmował 1. miejsce w grupie imion męskich. W całej populacji Polaków Antoni zajmował w 2017 r. 51. miejsce (130 174 nadań).", "Artur": "<b>Artur</b> wymowa – <a href=\"https://pl.wikipedia.org/wiki/Imi%C4%99\" target=\"_blank\" rel=\"noopener noreferrer\">imię</a> męskie pochodzenia <a href=\"https://pl.wikipedia.org/wiki/Imiona_celtyckie\" target=\"_blank\" rel=\"noopener noreferrer\">celtyckiego</a>. Powstało ze złożenia dwóch wyrazów wywodzących się z <a href=\"https://pl.wikipedia.org/wiki/J%C4%99zyki_celtyckie\" target=\"_blank\" rel=\"noopener noreferrer\">języków celtyckich</a>: <i>Art</i> – niedźwiedź, <i>ur</i> – młody, piękny, kwitnący. Podstawę imienia może także stanowić celtyckie słowo ard – wysoki, szlachetny.", "Aleksander": "<b>Aleksander</b> (<a href=\"https://pl.wikipedia.org/wiki/J%C4%99zyk_grecki_klasyczny\" target=\"_blank\" rel=\"noopener noreferrer\">stgr.</a>&#160;Ἀλέξανδρος, <i>aleksandros</i> – obrońca ludzi) – <a href=\"https://pl.wikipedia.org/wiki/Imi%C4%99\" target=\"_blank\" rel=\"noopener noreferrer\">imię</a> męskie pochodzenia <a href=\"https://pl.wikipedia.org/wiki/J%C4%99zyk_grecki\" target=\"_blank\" rel=\"noopener noreferrer\">greckiego</a> składające się z dwóch członów: <a href=\"https://pl.wikipedia.org/wiki/J%C4%99zyk_grecki_klasyczny\" target=\"_blank\" rel=\"noopener noreferrer\">stgr.</a>&#160;αλέξειν (bronić, wspomagać) i ἀνδρός (od ἀνήρ – mąż, mężczyzna). Całość bywa interpretowana jako „broniący mężów, troszczący się o mężów, opiekujący się mężami”.", "Adrian": "<b>Adrian</b>, również <b>Hadrian</b> – <a href=\"https://pl.wikipedia.org/wiki/Imi%C4%99\" target=\"_blank\" rel=\"noopener noreferrer\">imię</a> męskie pochodzenia <a href=\"https://pl.wikipedia.org/wiki/%C5%81acina\" target=\"_blank\" rel=\"noopener noreferrer\">łacińskiego</a>. Wywodzi się od imienia cesarza <a href=\"https://pl.wikipedia.org/wiki/Hadrian\" target=\"_blank\" rel=\"noopener noreferrer\">Hadriana</a>, <a href=\"https://pl.wikipedia.org/wiki/%C5%81acina\" target=\"_blank\" rel=\"noopener noreferrer\">łac.</a> „Hadrianus”, czyli „pochodzący z Hadrii” lub „z regionu <a href=\"https://pl.wikipedia.org/wiki/Morze_Adriatyckie\" target=\"_blank\" rel=\"noopener noreferrer\">morza Adriatyckiego</a>”. Imię było noszone przez kilku wczesnochrześcijańskich świętych i męczenników m.in. <a href=\"https://pl.wikipedia.org/wiki/Adrian_z_Canterbury\" target=\"_blank\" rel=\"noopener noreferrer\">św. Adriana z Canterbury</a>.", "Arkadiusz": "<b>Arkadiusz</b> – <a href=\"https://pl.wikipedia.org/wiki/Imi%C4%99\" target=\"_blank\" rel=\"noopener noreferrer\">imię</a> męskie pochodzenia <a href=\"https://pl.wikipedia.org/wiki/J%C4%99zyk_grecki\" target=\"_blank\" rel=\"noopener noreferrer\">greckiego</a>. Wywodzi się od słowa Αρκαδικóς (Arkadikós) oznaczającego „pochodzący z <a href=\"https://pl.wikipedia.org/wiki/Arkadia_(kraina_historyczna)\" target=\"_blank\" rel=\"noopener noreferrer\">Arkadii</a>”.", "Alan": "<b>Alan</b> – <a href=\"https://pl.wikipedia.org/wiki/Imi%C4%99\" target=\"_blank\" rel=\"noopener noreferrer\">imię</a> męskie pochodzenia najprawdopodobniej <a href=\"https://pl.wikipedia.org/wiki/Celtowie\" target=\"_blank\" rel=\"noopener noreferrer\">celtyckiego</a>. Może też wywodzić się od nazwy irańskiego plemienia <a href=\"https://pl.wikipedia.org/wiki/Alanowie\" target=\"_blank\" rel=\"noopener noreferrer\">Alanów</a>. Znaczenie tego imienia nie jest dokładnie znane, prawdopodobne znaczenia:", "Albert": "<b>Albert</b> – <a href=\"https://pl.wikipedia.org/wiki/Imi%C4%99\" target=\"_blank\" rel=\"noopener noreferrer\">imię</a> męskie pochodzenia <a href=\"https://pl.wikipedia.org/wiki/J%C4%99zyki_germa%C5%84skie\" target=\"_blank\" rel=\"noopener noreferrer\">germańskiego</a>. Wywodzi się od słów oznaczających <i>adal</i> (ród szlachecki) i <i>beraht</i> (jasny, błyszczący), oznaczało „pochodzącego ze szlachetnego rodu”. Jest zredukowaną formą staroniemieckiego imienia <i>Athalbraht</i> (pol. <a href=\"https://pl.wikipedia.org/wiki/Adalbert\" target=\"_blank\" rel=\"noopener noreferrer\">Adalbert</a>). Alternatywną wersją Alberta jest <i><b>Olbracht</b></i> – por. <a href=\"https://pl.wikipedia.org/wiki/Jan_I_Olbracht\" target=\"_blank\" rel=\"noopener noreferrer\">Jan I Olbracht</a>, król Polski.", "Alojzy": "<b>Alojzy</b> – <a href=\"https://pl.wikipedia.org/wiki/Imi%C4%99\" target=\"_blank\" rel=\"noopener noreferrer\">imię</a> męskie pochodzenia <a href=\"https://pl.wikipedia.org/wiki/Germanie\" target=\"_blank\" rel=\"noopener noreferrer\">germańskiego</a>. Wywodzi się od słowa <i>alwisi</i> oznaczającego „mądry”. Popularne od <a href=\"https://pl.wikipedia.org/wiki/XVII_wiek\" target=\"_blank\" rel=\"noopener noreferrer\">XVII wieku</a>. Na gruncie <a href=\"https://pl.wikipedia.org/wiki/J%C4%99zyk_francuski\" target=\"_blank\" rel=\"noopener noreferrer\">francuskim</a> imię to zidentyfikowało się z imieniem <a href=\"https://pl.wikipedia.org/wiki/Ludwik\" target=\"_blank\" rel=\"noopener noreferrer\">Ludwik</a> (Chlodowich, Chlodwich) i przyjęło formę <i>Louis</i>, a w <a href=\"https://pl.wikipedia.org/wiki/J%C4%99zyk_w%C5%82oski\" target=\"_blank\" rel=\"noopener noreferrer\">języku włoskim</a> <i>Luigi</i> (również <i>Aloisio</i>).", "Alfred": "<b>Alfred</b> – <a href=\"https://pl.wikipedia.org/wiki/Imi%C4%99\" target=\"_blank\" rel=\"noopener noreferrer\">imię</a> męskie pochodzenia <a href=\"https://pl.wikipedia.org/wiki/J%C4%99zyki_germa%C5%84skie\" target=\"_blank\" rel=\"noopener noreferrer\">germańskiego</a>. Wywodzi się od słów oznaczających „mądry jak <a href=\"https://pl.wikipedia.org/wiki/Elf_(fantastyka)\" target=\"_blank\" rel=\"noopener noreferrer\">Elf</a>”.", "Aleks": "<b>Aleksy</b> – <a href=\"https://pl.wikipedia.org/wiki/Imi%C4%99\" target=\"_blank\" rel=\"noopener noreferrer\">imię</a> męskie pochodzenia <a href=\"https://pl.wikipedia.org/wiki/J%C4%99zyk_grecki\" target=\"_blank\" rel=\"noopener noreferrer\">późnogreckiego</a> (<a href=\"https://pl.wikipedia.org/wiki/J%C4%99zyk_grecki\" target=\"_blank\" rel=\"noopener noreferrer\">gr.</a> Αλέξιος, <i>Aléxios</i>). Zostało utworzone od czasownika <i>aléks</i>, czyli „bronić” lub „wspomagać”. Imię Aleksy zostało rozpowszechnione w różnych językach dzięki <a href=\"https://pl.wikipedia.org/wiki/Legenda_o_%C5%9Bwi%C4%99tym_Aleksym\" target=\"_blank\" rel=\"noopener noreferrer\">średniowiecznej legendzie</a> o <a href=\"https://pl.wikipedia.org/wiki/Aleksy_Wyznawca\" target=\"_blank\" rel=\"noopener noreferrer\">św. Aleksym</a>.", "Augustyn": "<b>Augustyn</b> – <a href=\"https://pl.wikipedia.org/wiki/Imi%C4%99\" target=\"_blank\" rel=\"noopener noreferrer\">imię</a> męskie pochodzenia <a href=\"https://pl.wikipedia.org/wiki/%C5%81acina\" target=\"_blank\" rel=\"noopener noreferrer\">łacińskiego</a> od łac. <i>Augustinus</i>, utworzone od przydomka ‘Augustus’, nadanego <a href=\"https://pl.wikipedia.org/wiki/Oktawian_August\" target=\"_blank\" rel=\"noopener noreferrer\">Oktawianowi</a> przez senat, oznaczające „należący do <a href=\"https://pl.wikipedia.org/wiki/August_(imi%C4%99)\" target=\"_blank\" rel=\"noopener noreferrer\">Augusta</a>”.", "Ariel": "<b>Ariel</b> (<a href=\"https://pl.wikipedia.org/wiki/J%C4%99zyk_hebrajski\" target=\"_blank\" rel=\"noopener noreferrer\">hebr.</a>&#160;&#8207;אֲרִיאֵל&#8206;) – <a href=\"https://pl.wikipedia.org/wiki/Imi%C4%99\" target=\"_blank\" rel=\"noopener noreferrer\">imię</a> męskie pochodzenia <a href=\"https://pl.wikipedia.org/wiki/Biblia\" target=\"_blank\" rel=\"noopener noreferrer\">biblijnego</a>. Wywodzi się od <a href=\"https://pl.wikipedia.org/wiki/J%C4%99zyk_hebrajski\" target=\"_blank\" rel=\"noopener noreferrer\">hebrajskich</a> słów oznaczających „lew Boga”. W <a href=\"https://pl.wikipedia.org/wiki/Stary_Testament\" target=\"_blank\" rel=\"noopener noreferrer\">Starym Testamencie</a> używane było jako alternatywna nazwa miasta <a href=\"https://pl.wikipedia.org/wiki/Jerozolima\" target=\"_blank\" rel=\"noopener noreferrer\">Jerozolima</a>.", "Aleksy": "<b>Aleksy</b> – <a href=\"https://pl.wikipedia.org/wiki/Imi%C4%99\" target=\"_blank\" rel=\"noopener noreferrer\">imię</a> męskie pochodzenia <a href=\"https://pl.wikipedia.org/wiki/J%C4%99zyk_grecki\" target=\"_blank\" rel=\"noopener noreferrer\">późnogreckiego</a> (<a href=\"https://pl.wikipedia.org/wiki/J%C4%99zyk_grecki\" target=\"_blank\" rel=\"noopener noreferrer\">gr.</a> Αλέξιος, <i>Aléxios</i>). Zostało utworzone od czasownika <i>aléks</i>, czyli „bronić” lub „wspomagać”. Imię Aleksy zostało rozpowszechnione w różnych językach dzięki <a href=\"https://pl.wikipedia.org/wiki/Legenda_o_%C5%9Bwi%C4%99tym_Aleksym\" target=\"_blank\" rel=\"noopener noreferrer\">średniowiecznej legendzie</a> o <a href=\"https://pl.wikipedia.org/wiki/Aleksy_Wyznawca\" target=\"_blank\" rel=\"noopener noreferrer\">św. Aleksym</a>.", "Amadeusz": "<b>Amadeusz</b> lub <b>Amedeusz</b> – <a href=\"https://pl.wikipedia.org/wiki/Imi%C4%99\" target=\"_blank\" rel=\"noopener noreferrer\">imię</a> męskie pochodzące od <a href=\"https://pl.wikipedia.org/wiki/%C5%81acina\" target=\"_blank\" rel=\"noopener noreferrer\">łacińskiego</a> imienia <i>Amadeus</i>, powstałego w kręgach zakonnych. Wywodzi się od słów <i>amare</i> (kochać), oraz <i>Deus</i> (Bóg), co oznacza „kochający Boga”.", "Albin": "<b>Albin</b> – <a href=\"https://pl.wikipedia.org/wiki/Imi%C4%99\" target=\"_blank\" rel=\"noopener noreferrer\">imię</a> męskie pochodzenia <a href=\"https://pl.wikipedia.org/wiki/%C5%81acina\" target=\"_blank\" rel=\"noopener noreferrer\">łacińskiego</a>. Wywodzi się od słowa oznaczającego „biały”. Ponadto istnieje germańskie imię <a href=\"https://pl.wikipedia.org/wiki/Albwin\" target=\"_blank\" rel=\"noopener noreferrer\">Albwin</a> (Albuin), od którego forma skrócona może być jednakowa z imieniem Albin.", "Arnold": "<b>Arnold</b> – <a href=\"https://pl.wikipedia.org/wiki/Imi%C4%99\" target=\"_blank\" rel=\"noopener noreferrer\">imię</a> męskie pochodzenia <a href=\"https://pl.wikipedia.org/wiki/J%C4%99zyki_germa%C5%84skie\" target=\"_blank\" rel=\"noopener noreferrer\">germańskiego</a>. Stanowi złożenie członów oznaczających „orzeł” i „panujący”. Jednym z patronów tego imienia w Kościele katolickim jest <a href=\"https://pl.wikipedia.org/wiki/Arnold_Janssen\" target=\"_blank\" rel=\"noopener noreferrer\">Arnold Janssen</a>.", "Adolf": "<b>Adolf</b> – <a href=\"https://pl.wikipedia.org/wiki/Imi%C4%99\" target=\"_blank\" rel=\"noopener noreferrer\">imię</a> męskie pochodzenia <a href=\"https://pl.wikipedia.org/wiki/J%C4%99zyki_germa%C5%84skie\" target=\"_blank\" rel=\"noopener noreferrer\">germańskiego</a>. Wywodzi się od słów: <i>adal</i> – „szlachetny” oraz <i>wolf</i> – „wilk”. W Polsce imię to spotykane jest od XII–XIII w. Inne formy: Adulf, Odolf. Od tego imienia wywodzi się także imię Ado (Adon, Addo, Addon), będące jego zdrobnieniem.", "Alfons": "<b>Alfons</b> – <a href=\"https://pl.wikipedia.org/wiki/Imi%C4%99\" target=\"_blank\" rel=\"noopener noreferrer\">imię</a> męskie pochodzenia <a href=\"https://pl.wikipedia.org/wiki/J%C4%99zyki_germa%C5%84skie\" target=\"_blank\" rel=\"noopener noreferrer\">germańskiego</a>, powstałe ze złożenia członów <i>al</i> („cały”) lub <i>adal</i> („szlachetny ród”) oraz <i>funs</i> („szybki, chętny, życzliwy”). Imię to zostało spopularyzowane w Polsce w <a href=\"https://pl.wikipedia.org/wiki/XVIII_wiek\" target=\"_blank\" rel=\"noopener noreferrer\">XVIII</a> i <a href=\"https://pl.wikipedia.org/wiki/XIX_wiek\" target=\"_blank\" rel=\"noopener noreferrer\">XIX wieku</a> przez zakon <a href=\"https://pl.wikipedia.org/wiki/Redemptory%C5%9Bci\" target=\"_blank\" rel=\"noopener noreferrer\">redemptorystów</a>, którego założycielem był św. <a href=\"https://pl.wikipedia.org/wiki/Alfons_Maria_Liguori\" target=\"_blank\" rel=\"noopener noreferrer\">Alfons Maria Liguori</a>. Popularność Alfonsa następnie spadła po przedstawieniu komedii <a href=\"https://pl.wikipedia.org/wiki/Alexandre_Dumas_(syn)\" target=\"_blank\" rel=\"noopener noreferrer\">Aleksandra Dumasa syna</a> „Monsieur Alphonse” z 1873 r., pod wpływem której <i>alfons</i> w roli rzeczownika pospolitego zyskał w Polsce znaczenie <i><a href=\"https://pl.wikipedia.org/wiki/Sutenerstwo\" target=\"_blank\" rel=\"noopener noreferrer\">sutener</a></i>. Taka konotacja imienia Alfons nie ma charakteru ogólnoświatowego i np. w <a href=\"https://pl.wikipedia.org/wiki/Hiszpania\" target=\"_blank\" rel=\"noopener noreferrer\">Hiszpanii</a>, w której imię to nosiło kilkunastu królów (d. prowincji hiszpańskich), również obecnie imię to jest dość często spotykane.", "Ali": "<b>Ali</b> (<a href=\"https://pl.wikipedia.org/wiki/J%C4%99zyk_arabski\" target=\"_blank\" rel=\"noopener noreferrer\">arab.</a>&#160;&#8207;علي&#8206;) – <a href=\"https://pl.wikipedia.org/wiki/Imi%C4%99\" target=\"_blank\" rel=\"noopener noreferrer\">imię</a> męskie pochodzenia <a href=\"https://pl.wikipedia.org/wiki/J%C4%99zyk_arabski\" target=\"_blank\" rel=\"noopener noreferrer\">arabskiego</a>. Wywodzi się od arabskiego słowa oznaczającego „wysoki”.", "Anatol": "<b>Anatol</b>, <b>Anatoliusz</b> (<a href=\"https://pl.wikipedia.org/wiki/J%C4%99zyk_grecki\" target=\"_blank\" rel=\"noopener noreferrer\">gr.</a>&#160;ἀνατολικός – pochodzący ze Wschodu; analogiczne pochodzenie ma nazwa <a href=\"https://pl.wikipedia.org/wiki/Anatolia\" target=\"_blank\" rel=\"noopener noreferrer\">Anatolii</a>, krainy w Azji Mniejszej) – męskie imię pochodzenia greckiego.", "Andreas": "Jest to młody Szwajcar polskiego pochodzenia. To jedyna osoba, z którą <a href=\"https://pl.wikipedia.org/wiki/Stefan_P%C4%99ka%C5%82a\" target=\"_blank\" rel=\"noopener noreferrer\">Stefan Pękała</a> miał możliwość nawiązać bliższy kontakt w <a href=\"https://pl.wikipedia.org/wiki/Zurych\" target=\"_blank\" rel=\"noopener noreferrer\">Zurychu</a>, posługując się językiem polskim.", "August": "<b>August</b> – <a href=\"https://pl.wikipedia.org/wiki/Imi%C4%99\" target=\"_blank\" rel=\"noopener noreferrer\">imię</a> męskie pochodzenia <a href=\"https://pl.wikipedia.org/wiki/%C5%81acina\" target=\"_blank\" rel=\"noopener noreferrer\">łacińskiego</a>. Wywodzi się od przymiotnika <i>augustus</i>, nadanego jako przydomek <a href=\"https://pl.wikipedia.org/wiki/Oktawian_August\" target=\"_blank\" rel=\"noopener noreferrer\">Oktawianowi</a> przez Senat i oznaczającego „dostojny, boski, majestatyczny, poświęcony, święty, czcigodny, pomyślny, wzniosły”. Przymiotnik ten pochodzi od rzeczownika <i>augur</i> i pierwotnie odnosił się tylko do rzeczy, tłumacząc się jako „uświęcony przez (dobre) przepowiednie, znaki” lub „przedsięwzięty pod sprzyjającymi znakami”. Po raz pierwszy imię August zostało poświadczone w Polsce w <a href=\"https://pl.wikipedia.org/wiki/1349\" target=\"_blank\" rel=\"noopener noreferrer\">1349</a> roku, w łac. formie <i>Augustus</i>.", "Ahmed": "<b>Ahmad</b>, Ahmed, Ahmet (<a href=\"https://pl.wikipedia.org/wiki/J%C4%99zyk_arabski\" target=\"_blank\" rel=\"noopener noreferrer\">arab.</a>&#160;&#8207;أحمد&#8206;, <i>Aḥmad</i>) – popularne wśród <a href=\"https://pl.wikipedia.org/wiki/Islam\" target=\"_blank\" rel=\"noopener noreferrer\">muzułmanów</a> <a href=\"https://pl.wikipedia.org/wiki/Imi%C4%99\" target=\"_blank\" rel=\"noopener noreferrer\">imię</a> pochodzenia <a href=\"https://pl.wikipedia.org/wiki/J%C4%99zyk_arabski\" target=\"_blank\" rel=\"noopener noreferrer\">arabskiego</a>.", "Aaron": "<b>Aaron</b>, <b>Aron</b> (<a href=\"https://pl.wikipedia.org/wiki/J%C4%99zyk_hebrajski\" target=\"_blank\" rel=\"noopener noreferrer\">hebr.</a> Aharon <b>אַהֲרֹן</b> – możliwa <a href=\"https://pl.wikipedia.org/wiki/Etymologia\" target=\"_blank\" rel=\"noopener noreferrer\">etymologia</a> <i>oświecony</i>, <i>wywyższony</i>, być może imię pochodzenia egipskiego) – <a href=\"https://pl.wikipedia.org/wiki/Biblia\" target=\"_blank\" rel=\"noopener noreferrer\">biblijne</a> <a href=\"https://pl.wikipedia.org/wiki/Imi%C4%99\" target=\"_blank\" rel=\"noopener noreferrer\">imię</a> męskie. Nosił je starszy brat i pomocnik <a href=\"https://pl.wikipedia.org/wiki/Moj%C5%BCesz\" target=\"_blank\" rel=\"noopener noreferrer\">Mojżesza</a> i <a href=\"https://pl.wikipedia.org/wiki/Miriam_(posta%C4%87_biblijna)\" target=\"_blank\" rel=\"noopener noreferrer\">Miriam</a> (<i>zobacz <a href=\"https://pl.wikipedia.org/wiki/Aaron_(posta%C4%87_biblijna)\" target=\"_blank\" rel=\"noopener noreferrer\">Aaron (postać biblijna)</a>).</i> Wśród świętych – m.in. św. Aaron, męczennik (<a href=\"https://pl.wikipedia.org/wiki/III_wiek\" target=\"_blank\" rel=\"noopener noreferrer\">III wiek</a>).", "Amir": "<b>Amir</b> (<a href=\"https://pl.wikipedia.org/wiki/J%C4%99zyk_arabski\" target=\"_blank\" rel=\"noopener noreferrer\">arab.</a>&#160;&#8207;أمير&#8206;) – <a href=\"https://pl.wikipedia.org/wiki/Imi%C4%99\" target=\"_blank\" rel=\"noopener noreferrer\">imię</a> męskie pochodzenia arabskiego, oznacza „książę” lub „dowódca”.", "Aureliusz": "<b>Aureliusz</b> – <a href=\"https://pl.wikipedia.org/wiki/Imi%C4%99\" target=\"_blank\" rel=\"noopener noreferrer\">imię</a> męskie pochodzące od nazwy rzymskiego rodu Aurelia, która z kolei pochodzi od <a href=\"https://pl.wikipedia.org/wiki/%C5%81acina\" target=\"_blank\" rel=\"noopener noreferrer\">łacińskiego</a> <i>aureolus</i> – \"złocisty\", co mogło znaczyć także \"wspaniały\". Imię to posiada licznych świętych patronów.", "Ahmad": "<b>Ahmad</b>, Ahmed, Ahmet (<a href=\"https://pl.wikipedia.org/wiki/J%C4%99zyk_arabski\" target=\"_blank\" rel=\"noopener noreferrer\">arab.</a>&#160;&#8207;أحمد&#8206;, <i>Aḥmad</i>) – popularne wśród <a href=\"https://pl.wikipedia.org/wiki/Islam\" target=\"_blank\" rel=\"noopener noreferrer\">muzułmanów</a> <a href=\"https://pl.wikipedia.org/wiki/Imi%C4%99\" target=\"_blank\" rel=\"noopener noreferrer\">imię</a> pochodzenia <a href=\"https://pl.wikipedia.org/wiki/J%C4%99zyk_arabski\" target=\"_blank\" rel=\"noopener noreferrer\">arabskiego</a>.", "Andrea": "<b>Andrea</b> – żeńska forma łacińskiego <a href=\"https://pl.wikipedia.org/wiki/Imi%C4%99\" target=\"_blank\" rel=\"noopener noreferrer\">imienia</a> <a href=\"https://pl.wikipedia.org/wiki/Andreas\" target=\"_blank\" rel=\"noopener noreferrer\">Andreas</a>, które w języku polskim rozwinęło się w imię <a href=\"https://pl.wikipedia.org/wiki/Andrzej\" target=\"_blank\" rel=\"noopener noreferrer\">Andrzej</a>. Polskim odpowiednikiem tego imienia jest <a href=\"https://pl.wikipedia.org/wiki/Andrzeja\" target=\"_blank\" rel=\"noopener noreferrer\">Andrzeja</a> (a także <a href=\"https://pl.wikipedia.org/wiki/Andrzeja\" target=\"_blank\" rel=\"noopener noreferrer\">Ondrzeja</a>).", "Armin": "<b>Armin</b> – oboczna forma imienia <a href=\"https://pl.wikipedia.org/wiki/Herman\" target=\"_blank\" rel=\"noopener noreferrer\">Herman</a>.", "Ambroży": "<b>Ambroży</b> (<a href=\"https://pl.wikipedia.org/wiki/J%C4%99zyk_grecki\" target=\"_blank\" rel=\"noopener noreferrer\">gr.</a> <i>ambrósios</i> – boski, nieśmiertelny, święty od <i>(am)brotós</i> – (nie)śmiertelny) – <a href=\"https://pl.wikipedia.org/wiki/Imi%C4%99\" target=\"_blank\" rel=\"noopener noreferrer\">imię</a> męskie pochodzenia <a href=\"https://pl.wikipedia.org/wiki/J%C4%99zyk_grecki\" target=\"_blank\" rel=\"noopener noreferrer\">greckiego</a>.", "Apolinary": "<b>Apolinary</b> – męskie <a href=\"https://pl.wikipedia.org/wiki/Imi%C4%99\" target=\"_blank\" rel=\"noopener noreferrer\">imię</a> pochodzenia <a href=\"https://pl.wikipedia.org/wiki/J%C4%99zyk_grecki\" target=\"_blank\" rel=\"noopener noreferrer\">greckiego</a>, powstałe od imienia boga <a href=\"https://pl.wikipedia.org/wiki/Apollo\" target=\"_blank\" rel=\"noopener noreferrer\">Apollina</a>.", "Armen": "<b>Armen</b> – <a href=\"https://pl.wikipedia.org/wiki/Imi%C4%99\" target=\"_blank\" rel=\"noopener noreferrer\">imię</a> męskie pochodzenia ormiańskiego, wywodzi się z mitologii ormiańskiej. Skrócona forma imienia Armenak, które wyszło z użycia w <a href=\"https://pl.wikipedia.org/wiki/XIX_wiek\" target=\"_blank\" rel=\"noopener noreferrer\">XIX</a> wieku. Żeński odpowiednik: Armenuhi (zdrobnienie: Armine lub Armina)", "Abdullah": "<b>Abdullah</b>, <b>Abdallah</b>, <b>Abd Allah</b> (<a href=\"https://pl.wikipedia.org/wiki/J%C4%99zyk_arabski\" target=\"_blank\" rel=\"noopener noreferrer\">arab.</a>&#160;&#8207;عبد ﷲ&#8206;) to popularne wśród <a href=\"https://pl.wikipedia.org/wiki/Islam\" target=\"_blank\" rel=\"noopener noreferrer\">muzułmanów</a> <a href=\"https://pl.wikipedia.org/wiki/Imi%C4%99\" target=\"_blank\" rel=\"noopener noreferrer\">imię</a> pochodzenia <a href=\"https://pl.wikipedia.org/wiki/J%C4%99zyk_arabski\" target=\"_blank\" rel=\"noopener noreferrer\">arabskiego</a> oznaczające <i>sługa <a href=\"https://pl.wikipedia.org/wiki/Allah\" target=\"_blank\" rel=\"noopener noreferrer\">Allaha</a></i>. Jest ono często przybierane przez osoby nowo nawrócone na <a href=\"https://pl.wikipedia.org/wiki/Islam\" target=\"_blank\" rel=\"noopener noreferrer\">islam</a>.", "Apoloniusz": "<b>Apoloniusz</b> – <a href=\"https://pl.wikipedia.org/wiki/Imi%C4%99\" target=\"_blank\" rel=\"noopener noreferrer\">imię</a> męskie pochodzenia <a href=\"https://pl.wikipedia.org/wiki/J%C4%99zyk_grecki\" target=\"_blank\" rel=\"noopener noreferrer\">greckiego</a>. Wywodzi się od imienia greckiego boga <a href=\"https://pl.wikipedia.org/wiki/Apollo\" target=\"_blank\" rel=\"noopener noreferrer\">Apollina</a>. Nosili je między innymi grecki poeta żyjący w <a href=\"https://pl.wikipedia.org/wiki/III_wiek_p.n.e.\" target=\"_blank\" rel=\"noopener noreferrer\">III wieku p.n.e.</a> i matematyk <a href=\"https://pl.wikipedia.org/wiki/Apoloniusz_z_Pergi\" target=\"_blank\" rel=\"noopener noreferrer\">Apoloniusz z Pergi</a>. Istnieją liczni święci o tym imieniu (m.in. <a href=\"https://pl.wikipedia.org/wiki/Ojcowie_Ko%C5%9Bcio%C5%82a\" target=\"_blank\" rel=\"noopener noreferrer\">Ojcowie Kościoła</a> Apoloniusz z Efezu i Apoloniusz senator). Jego żeńskim odpowiednikiem jest <a href=\"https://pl.wikipedia.org/wiki/Apolonia\" target=\"_blank\" rel=\"noopener noreferrer\">Apolonia</a>.", "Armand": "<b>Herman</b> – <a href=\"https://pl.wikipedia.org/wiki/Imi%C4%99\" target=\"_blank\" rel=\"noopener noreferrer\">imię</a> męskie pochodzenia <a href=\"https://pl.wikipedia.org/wiki/J%C4%99zyki_germa%C5%84skie\" target=\"_blank\" rel=\"noopener noreferrer\">germańskiego</a>. Wywodzi się od słowa oznaczającego „wojownik”. Innym jego wariantem jest <b><a href=\"https://pl.wikipedia.org/wiki/Armin\" target=\"_blank\" rel=\"noopener noreferrer\">Armin</a></b>, natomiast nazwisko <a href=\"https://pl.wikipedia.org/wiki/Menzel\" target=\"_blank\" rel=\"noopener noreferrer\">Menzel</a> stanowi podwójne zdrobnienie imienia Hermann. W średniowiecznej Polsce odnotowywano polskie formy Jerzman i Jirzman.", "Arian": "<b>Arian</b> – <a href=\"https://pl.wikipedia.org/wiki/Imi%C4%99\" target=\"_blank\" rel=\"noopener noreferrer\">imię</a> męskie, pochodzenia prawdopodobnie <a href=\"https://pl.wikipedia.org/wiki/J%C4%99zyk_grecki\" target=\"_blank\" rel=\"noopener noreferrer\">grecko</a>-<a href=\"https://pl.wikipedia.org/wiki/%C5%81acina\" target=\"_blank\" rel=\"noopener noreferrer\">łacińskiego</a>. Jego patronem jest św. Arian, wspominany razem ze św. <a href=\"https://pl.wikipedia.org/wiki/Teotyk_(m%C4%99czennik_egipski)\" target=\"_blank\" rel=\"noopener noreferrer\">Teotykiem</a>.", "Alvaro": "<b>Alwar</b> – <a href=\"https://pl.wikipedia.org/wiki/Imi%C4%99\" target=\"_blank\" rel=\"noopener noreferrer\">imię</a> męskie pochodzenia <a href=\"https://pl.wikipedia.org/wiki/J%C4%99zyki_germa%C5%84skie\" target=\"_blank\" rel=\"noopener noreferrer\">germańskiego</a>, oznaczające „strażnik wszystkiego/wszystkich”.", "Andrés": "<b>Andrzej</b> – <a href=\"https://pl.wikipedia.org/wiki/Imi%C4%99\" target=\"_blank\" rel=\"noopener noreferrer\">imię</a> męskie pochodzenia <a href=\"https://pl.wikipedia.org/wiki/J%C4%99zyk_grecki\" target=\"_blank\" rel=\"noopener noreferrer\">greckiego</a>. Pochodzi od greckiego imienia Andréas, którego rdzeń <i>andr-</i> nawiązuje do znaczenia: „człowiek, mężczyzna, taki jak mężczyzna” (inne źródło tłumaczy go jako „dzielny, mężny”). To greckie imię Andréas nosił jeden z <a href=\"https://pl.wikipedia.org/wiki/Aposto%C5%82\" target=\"_blank\" rel=\"noopener noreferrer\">apostołów</a>, brat Szymona Piotra. Imię występuje także w <a href=\"https://pl.wikipedia.org/wiki/Biblia\" target=\"_blank\" rel=\"noopener noreferrer\">Biblii</a>. W języku polskim przybrał formę Andrzej<b>.</b>", "Anastazy": "<b>Anastazy</b> – <a href=\"https://pl.wikipedia.org/wiki/Imi%C4%99\" target=\"_blank\" rel=\"noopener noreferrer\">imię</a> męskie pochodzenia <a href=\"https://pl.wikipedia.org/wiki/J%C4%99zyk_grecki\" target=\"_blank\" rel=\"noopener noreferrer\">greckiego</a>. Wywodzi się od słowa oznaczającego „wskrzeszenie”, „zmartwychwstanie”. Jego żeńskim odpowiednikiem jest <a href=\"https://pl.wikipedia.org/wiki/Anastazja\" target=\"_blank\" rel=\"noopener noreferrer\">Anastazja</a>.", "Amin": "<b>Amin</b> — <a href=\"https://pl.wikipedia.org/wiki/Imi%C4%99\" target=\"_blank\" rel=\"noopener noreferrer\">imię</a> męskie pochodzenia <a href=\"https://pl.wikipedia.org/wiki/J%C4%99zyk_arabski\" target=\"_blank\" rel=\"noopener noreferrer\">arabskiego</a>. Oznacza „godny zaufania” lub „prawdomówny”. Nosił je szósty <a href=\"https://pl.wikipedia.org/wiki/Kalif\" target=\"_blank\" rel=\"noopener noreferrer\">kalif</a> <a href=\"https://pl.wikipedia.org/wiki/Abbasydzi\" target=\"_blank\" rel=\"noopener noreferrer\">abbasydzki</a>.", "Abel": "<b>Abel</b> (hebr. הבל) – <a href=\"https://pl.wikipedia.org/wiki/Imi%C4%99\" target=\"_blank\" rel=\"noopener noreferrer\">imię</a> męskie wywodzące się z hebrajskiego <i>abhal</i> – „mgła, dym, tchnienie”. Być może wiązało się jednak z <a href=\"https://pl.wikipedia.org/wiki/J%C4%99zyk_akadyjski\" target=\"_blank\" rel=\"noopener noreferrer\">akadyjskim</a> <i>aplu || ibil</i> lub asyryjskim <i>ahbla || ablu</i> – „syn rodzony”. Nosiła je <a href=\"https://pl.wikipedia.org/wiki/Kain_i_Abel\" target=\"_blank\" rel=\"noopener noreferrer\">postać biblijna</a>, syn Adama i Ewy, który był pasterzem. Abel został zamordowany przez swego brata Kaina, rolnika. Imię to było notowane na terenie Polski już w średniowieczu, na przełomie <a href=\"https://pl.wikipedia.org/wiki/XIII_wiek\" target=\"_blank\" rel=\"noopener noreferrer\">XIII</a> i <a href=\"https://pl.wikipedia.org/wiki/XIV_wiek\" target=\"_blank\" rel=\"noopener noreferrer\">XIV wieku</a>, początkowo jako imię zakonne. Patronem tego imienia w Kościele katolickim są, obok Abla, syna Adama i Ewy, m.in. Abel, biskup Metzu, i <a href=\"https://pl.wikipedia.org/wiki/Abel_z_Reims\" target=\"_blank\" rel=\"noopener noreferrer\">Abel</a>, arcybiskup Reims.", "Aram": "<b>Aram</b> – jest to <a href=\"https://pl.wikipedia.org/wiki/Imi%C4%99\" target=\"_blank\" rel=\"noopener noreferrer\">imię</a> męskie popularne na <a href=\"https://pl.wikipedia.org/wiki/Bliski_Wsch%C3%B3d\" target=\"_blank\" rel=\"noopener noreferrer\">Bliskim Wschodzie</a>. W <a href=\"https://pl.wikipedia.org/wiki/J%C4%99zyk_kurdyjski\" target=\"_blank\" rel=\"noopener noreferrer\">języku kurdyjskim</a> oznacza \"spokojny\". W Polsce nie obchodzi <a href=\"https://pl.wikipedia.org/wiki/Imieniny\" target=\"_blank\" rel=\"noopener noreferrer\">imienin</a>. <a href=\"https://pl.wikipedia.org/wiki/Aram_(posta%C4%87_biblijna)\" target=\"_blank\" rel=\"noopener noreferrer\">Aram</a> był według <a href=\"https://pl.wikipedia.org/wiki/Biblia\" target=\"_blank\" rel=\"noopener noreferrer\">Biblii</a> synem <a href=\"https://pl.wikipedia.org/wiki/Sem_(posta%C4%87_biblijna)\" target=\"_blank\" rel=\"noopener noreferrer\">Sema</a> i wnukiem <a href=\"https://pl.wikipedia.org/wiki/Noe\" target=\"_blank\" rel=\"noopener noreferrer\">Noego</a>.", "Adem": "<b>Adem</b> – <a href=\"https://pl.wikipedia.org/wiki/Imi%C4%99\" target=\"_blank\" rel=\"noopener noreferrer\">imię</a> męskie będące <a href=\"https://pl.wikipedia.org/wiki/Turcy\" target=\"_blank\" rel=\"noopener noreferrer\">sturkizowaną</a> wersją imienia <a href=\"https://pl.wikipedia.org/wiki/Adam\" target=\"_blank\" rel=\"noopener noreferrer\">Adam</a>, występujące też jako nazwisko.", "Alessio": "<b>Aleksy</b> – <a href=\"https://pl.wikipedia.org/wiki/Imi%C4%99\" target=\"_blank\" rel=\"noopener noreferrer\">imię</a> męskie pochodzenia <a href=\"https://pl.wikipedia.org/wiki/J%C4%99zyk_grecki\" target=\"_blank\" rel=\"noopener noreferrer\">późnogreckiego</a> (<a href=\"https://pl.wikipedia.org/wiki/J%C4%99zyk_grecki\" target=\"_blank\" rel=\"noopener noreferrer\">gr.</a> Αλέξιος, <i>Aléxios</i>). Zostało utworzone od czasownika <i>aléks</i>, czyli „bronić” lub „wspomagać”. Imię Aleksy zostało rozpowszechnione w różnych językach dzięki <a href=\"https://pl.wikipedia.org/wiki/Legenda_o_%C5%9Bwi%C4%99tym_Aleksym\" target=\"_blank\" rel=\"noopener noreferrer\">średniowiecznej legendzie</a> o <a href=\"https://pl.wikipedia.org/wiki/Aleksy_Wyznawca\" target=\"_blank\" rel=\"noopener noreferrer\">św. Aleksym</a>.", "Adil": "<b>Adil</b> – arabskie <a href=\"https://pl.wikipedia.org/wiki/Imi%C4%99\" target=\"_blank\" rel=\"noopener noreferrer\">imię</a> męskie, pochodzące od słowa <i>adil</i> (<a href=\"https://pl.wikipedia.org/wiki/J%C4%99zyk_arabski\" target=\"_blank\" rel=\"noopener noreferrer\">arab.</a>&#160;&#8207;عدل&#8206;, <i>’adil</i>) – 'sprawiedliwy', 'uczciwy'.", "Arjun": "<b>Arjun</b> (<a href=\"https://pl.wikipedia.org/wiki/Sanskryt\" target=\"_blank\" rel=\"noopener noreferrer\">sanskr.</a> <i>अर्जुन</i>) – <a href=\"https://pl.wikipedia.org/wiki/Indie\" target=\"_blank\" rel=\"noopener noreferrer\">indyjski</a> <a href=\"https://pl.wikipedia.org/wiki/Czo%C5%82g_podstawowy\" target=\"_blank\" rel=\"noopener noreferrer\">czołg podstawowy</a>, produkowany od 2004 roku, w <a href=\"https://pl.wikipedia.org/wiki/Armia_indyjska\" target=\"_blank\" rel=\"noopener noreferrer\">armii indyjskiej</a> od 2007 roku. Nazwa czołgu pochodzi od <a href=\"https://pl.wikipedia.org/wiki/Ard%C5%BAuna\" target=\"_blank\" rel=\"noopener noreferrer\">Ardźuna</a> - jednego z bohaterów <a href=\"https://pl.wikipedia.org/wiki/Epos\" target=\"_blank\" rel=\"noopener noreferrer\">eposu</a> <i><a href=\"https://pl.wikipedia.org/wiki/Mahabharata\" target=\"_blank\" rel=\"noopener noreferrer\">Mahabharata</a></i>.", "Attila": "<b>Attila</b> – imię męskie pochodzenia <a href=\"https://pl.wikipedia.org/wiki/Turcja\" target=\"_blank\" rel=\"noopener noreferrer\">tureckiego</a>, szczególnie popularne w Turcji i na <a href=\"https://pl.wikipedia.org/wiki/W%C4%99gry\" target=\"_blank\" rel=\"noopener noreferrer\">Węgrzech</a>, gdzie używa się także formy Etele. Żeński odpowiednik – Etelka.", "Alim": "<b>Ulem</b> – muzułmański teolog i uczony. Słowo pochodzi z wyrazu <a href=\"https://pl.wikipedia.org/wiki/J%C4%99zyk_arabski\" target=\"_blank\" rel=\"noopener noreferrer\">arabskiego</a> <i>alim</i>, oznaczającego uczonego. W skład grupy ulemów wchodzili wszyscy duchowni muzułmańscy: <a href=\"https://pl.wikipedia.org/wiki/Mufti\" target=\"_blank\" rel=\"noopener noreferrer\">muftiowie</a> oraz <a href=\"https://pl.wikipedia.org/wiki/Imam\" target=\"_blank\" rel=\"noopener noreferrer\">imamowie</a>. Ulemów określa się również mianem znawców <a href=\"https://pl.wikipedia.org/wiki/Szariat\" target=\"_blank\" rel=\"noopener noreferrer\">szariatu</a>. Ich główną siedzibą były <a href=\"https://pl.wikipedia.org/wiki/Meczet\" target=\"_blank\" rel=\"noopener noreferrer\">meczety</a>. Główną rolę posiadał meczet <a href=\"https://pl.wikipedia.org/wiki/Al-Azhar\" target=\"_blank\" rel=\"noopener noreferrer\">al-Azhar</a> w <a href=\"https://pl.wikipedia.org/wiki/Kair\" target=\"_blank\" rel=\"noopener noreferrer\">Kairze</a>.", "Aidan": "<b>Aidan</b> – <a href=\"https://pl.wikipedia.org/wiki/Imi%C4%99\" target=\"_blank\" rel=\"noopener noreferrer\">imię</a> męskie pochodzenia celtyckiego, od staroirlandzkiego <i>Áedán</i> – zdrobniałej formy imienia <i>Áed</i>, oznaczającego „płomień, ogień”. Jest to imię irlandzkiego świętego z <a href=\"https://pl.wikipedia.org/wiki/VII_wiek\" target=\"_blank\" rel=\"noopener noreferrer\">VII</a> w.", "Anis": "<b>Anisette</b> – <a href=\"https://pl.wikipedia.org/wiki/Likier\" target=\"_blank\" rel=\"noopener noreferrer\">likier</a> pochodzenia <a href=\"https://pl.wikipedia.org/wiki/Francja\" target=\"_blank\" rel=\"noopener noreferrer\">francuskiego</a> o zawartości alkoholu 25-40%. Jest produkowany z likierów korzennych na bazie <a href=\"https://pl.wikipedia.org/wiki/Biedrzeniec_any%C5%BC\" target=\"_blank\" rel=\"noopener noreferrer\">anyżu</a>, oliwki anyżowej z dodatkiem aromatu <a href=\"https://pl.wikipedia.org/wiki/Koper_ogrodowy\" target=\"_blank\" rel=\"noopener noreferrer\">kopru</a>, <a href=\"https://pl.wikipedia.org/wiki/Go%C5%BAdziki\" target=\"_blank\" rel=\"noopener noreferrer\">goździków</a>, bądź <a href=\"https://pl.wikipedia.org/wiki/Kolendra_siewna\" target=\"_blank\" rel=\"noopener noreferrer\">kolendry</a>. Alkohol jest często używany z barach jako składnik <a href=\"https://pl.wikipedia.org/wiki/Koktajl_alkoholowy\" target=\"_blank\" rel=\"noopener noreferrer\">koktajli</a>.", "Alwin": "<b>Alwin</b> – imię męskie pochodzenia <a href=\"https://pl.wikipedia.org/wiki/J%C4%99zyki_germa%C5%84skie\" target=\"_blank\" rel=\"noopener noreferrer\">germańskiego</a>. Stanowi skróconą formę imienia <a href=\"https://pl.wikipedia.org/wiki/Albwin\" target=\"_blank\" rel=\"noopener noreferrer\">Albwin</a> lub <a href=\"https://pl.wikipedia.org/wiki/Adalwin\" target=\"_blank\" rel=\"noopener noreferrer\">Adalwin</a>.", "Azad": "<b>Azad</b>, właściwie <b>Azad Azadpour</b> (ur. <a href=\"https://pl.wikipedia.org/wiki/24_listopada\" target=\"_blank\" rel=\"noopener noreferrer\">24 listopada</a> <a href=\"https://pl.wikipedia.org/wiki/1973\" target=\"_blank\" rel=\"noopener noreferrer\">1973</a> w <a href=\"https://pl.wikipedia.org/wiki/Sanandad%C5%BC\" target=\"_blank\" rel=\"noopener noreferrer\">Sanandadżu</a>, <a href=\"https://pl.wikipedia.org/wiki/Iran\" target=\"_blank\" rel=\"noopener noreferrer\">Iran</a>) – niemieckojęzyczny <a href=\"https://pl.wikipedia.org/wiki/Rap\" target=\"_blank\" rel=\"noopener noreferrer\">raper</a> irańsko-kurdyjskiego pochodzenia. Mieszka we <a href=\"https://pl.wikipedia.org/wiki/Frankfurt_nad_Menem\" target=\"_blank\" rel=\"noopener noreferrer\">Frankfurcie nad Menem</a>. Jego imię po kurdyjsku znaczy \"wolny\".", "Anzelm": "<b>Anzelm</b> – <a href=\"https://pl.wikipedia.org/wiki/Imi%C4%99\" target=\"_blank\" rel=\"noopener noreferrer\">imię</a> męskie pochodzenia <a href=\"https://pl.wikipedia.org/wiki/J%C4%99zyki_germa%C5%84skie\" target=\"_blank\" rel=\"noopener noreferrer\">germańskiego</a> (<i>ans</i> &lt;<a href=\"https://pl.wikipedia.org/wiki/Azowie\" target=\"_blank\" rel=\"noopener noreferrer\">Azowie</a>&gt; + <i>helm</i> &lt;hełm&gt;, oznacza „strzeżony przez bóstwa”). Imię <a href=\"https://pl.wikipedia.org/wiki/Imi%C4%99_teoforyczne\" target=\"_blank\" rel=\"noopener noreferrer\">teoforyczne</a>. W Polsce używane w 1228 r. oraz od XIV w.", "Arkady": "<b>Arkady</b> – oboczna forma <a href=\"https://pl.wikipedia.org/wiki/Imi%C4%99\" target=\"_blank\" rel=\"noopener noreferrer\">imienia</a> <a href=\"https://pl.wikipedia.org/wiki/Arkadiusz_(imi%C4%99)\" target=\"_blank\" rel=\"noopener noreferrer\">Arkadiusz</a>.", "Adalbert": "<b>Adalbert, Adelbert</b> – <a href=\"https://pl.wikipedia.org/wiki/Imi%C4%99\" target=\"_blank\" rel=\"noopener noreferrer\">imię</a> męskie pochodzenia <a href=\"https://pl.wikipedia.org/wiki/J%C4%99zyki_germa%C5%84skie\" target=\"_blank\" rel=\"noopener noreferrer\">germańskiego</a>. Wywodzi się od słów oznaczających <i>adal</i> (ród szlachecki) i <i>beraht</i> (jasny, błyszczący), oznaczało „pochodzącego ze szlachetnego rodu”. Występuje w wielu odmianach, np.: <a href=\"https://pl.wikipedia.org/wiki/Albert_(imi%C4%99)\" target=\"_blank\" rel=\"noopener noreferrer\">Albert</a>, Olbracht.", "Ayman": "<b>Ayman</b> (<a href=\"https://pl.wikipedia.org/wiki/J%C4%99zyk_arabski\" target=\"_blank\" rel=\"noopener noreferrer\">arab.</a> َأيْمَن) – arabskie imię męskie, oznaczające: błogosławiony, szczęśliwy. Bywa zapisywane także jako Ajman, Aiman, Aimen, Aymen.", "Antoniusz": "<b>Antoni</b> – <a href=\"https://pl.wikipedia.org/wiki/Imi%C4%99\" target=\"_blank\" rel=\"noopener noreferrer\">imię</a> męskie pochodzenia <a href=\"https://pl.wikipedia.org/wiki/%C5%81acina\" target=\"_blank\" rel=\"noopener noreferrer\">łacińskiego</a>. Pochodzi od <i>Antonii</i> (<a href=\"https://pl.wikipedia.org/wiki/Drzewo_genealogiczne_Antoniusz%C3%B3w\" target=\"_blank\" rel=\"noopener noreferrer\">Antoniuszów</a>), znaczącego rodu w starożytnym <a href=\"https://pl.wikipedia.org/wiki/Rzym\" target=\"_blank\" rel=\"noopener noreferrer\">Rzymie</a>. Wśród imion nadawanych nowo narodzonym dzieciom, Antoni w 2017, 2018, 2019, 2020, 2021 r. zajmował 1. miejsce w grupie imion męskich. W całej populacji Polaków Antoni zajmował w 2017 r. 51. miejsce (130 174 nadań).", "Arseniusz": "<b>Arseniusz</b> – <a href=\"https://pl.wikipedia.org/wiki/Imi%C4%99\" target=\"_blank\" rel=\"noopener noreferrer\">imię</a> męskie pochodzenia <a href=\"https://pl.wikipedia.org/wiki/J%C4%99zyk_grecki\" target=\"_blank\" rel=\"noopener noreferrer\">greckiego</a>. Wywodzi się od słowa ἀρσεν (<i>arsen</i>) oznaczającego „męski”.", "Amos": "<b>Amos</b> – <a href=\"https://pl.wikipedia.org/wiki/Imi%C4%99\" target=\"_blank\" rel=\"noopener noreferrer\">imię</a> męskie pochodzenia <a href=\"https://pl.wikipedia.org/wiki/Biblia\" target=\"_blank\" rel=\"noopener noreferrer\">biblijnego</a>. Wywodzi się od <a href=\"https://pl.wikipedia.org/wiki/J%C4%99zyk_hebrajski\" target=\"_blank\" rel=\"noopener noreferrer\">hebr.</a> עמוס <i>amos</i> – „mocny, dźwigający ciężary”. Patronem tego imienia jest <a href=\"https://pl.wikipedia.org/wiki/Amos_(prorok)\" target=\"_blank\" rel=\"noopener noreferrer\">Amos</a>, jeden z dwunastu <a href=\"https://pl.wikipedia.org/wiki/Prorocy_mniejsi\" target=\"_blank\" rel=\"noopener noreferrer\">proroków mniejszych</a>, którego imieniem nazwana jest jedna z ksiąg biblijnych – <a href=\"https://pl.wikipedia.org/wiki/Ksi%C4%99ga_Amosa\" target=\"_blank\" rel=\"noopener noreferrer\">Księga Amosa</a>. Obchodzi <a href=\"https://pl.wikipedia.org/wiki/Imieniny\" target=\"_blank\" rel=\"noopener noreferrer\">imieniny</a> <a href=\"https://pl.wikipedia.org/wiki/31_marca\" target=\"_blank\" rel=\"noopener noreferrer\">31 marca</a>.", "Abdallah": "<b>Abdullah</b>, <b>Abdallah</b>, <b>Abd Allah</b> (<a href=\"https://pl.wikipedia.org/wiki/J%C4%99zyk_arabski\" target=\"_blank\" rel=\"noopener noreferrer\">arab.</a>&#160;&#8207;عبد ﷲ&#8206;) to popularne wśród <a href=\"https://pl.wikipedia.org/wiki/Islam\" target=\"_blank\" rel=\"noopener noreferrer\">muzułmanów</a> <a href=\"https://pl.wikipedia.org/wiki/Imi%C4%99\" target=\"_blank\" rel=\"noopener noreferrer\">imię</a> pochodzenia <a href=\"https://pl.wikipedia.org/wiki/J%C4%99zyk_arabski\" target=\"_blank\" rel=\"noopener noreferrer\">arabskiego</a> oznaczające <i>sługa <a href=\"https://pl.wikipedia.org/wiki/Allah\" target=\"_blank\" rel=\"noopener noreferrer\">Allaha</a></i>. Jest ono często przybierane przez osoby nowo nawrócone na <a href=\"https://pl.wikipedia.org/wiki/Islam\" target=\"_blank\" rel=\"noopener noreferrer\">islam</a>.", "Arek": "<b>Arkadiusz</b> – <a href=\"https://pl.wikipedia.org/wiki/Imi%C4%99\" target=\"_blank\" rel=\"noopener noreferrer\">imię</a> męskie pochodzenia <a href=\"https://pl.wikipedia.org/wiki/J%C4%99zyk_grecki\" target=\"_blank\" rel=\"noopener noreferrer\">greckiego</a>. Wywodzi się od słowa Αρκαδικóς (Arkadikós) oznaczającego „pochodzący z <a href=\"https://pl.wikipedia.org/wiki/Arkadia_(kraina_historyczna)\" target=\"_blank\" rel=\"noopener noreferrer\">Arkadii</a>”.", "Aurelian": "<b>Aurelian</b> – <a href=\"https://pl.wikipedia.org/wiki/Imi%C4%99\" target=\"_blank\" rel=\"noopener noreferrer\">imię</a> męskie pochodzące od <a href=\"https://pl.wikipedia.org/wiki/%C5%81acina\" target=\"_blank\" rel=\"noopener noreferrer\">łac.</a>&#160;<em>Aurelianus</em>. Pierwotnie <a href=\"https://pl.wikipedia.org/wiki/Nazwisko#Przydomek_(cognomen)\" target=\"_blank\" rel=\"noopener noreferrer\">przydomek</a> (<em>cognomen</em>) od <i>gentilicium Aurelius</i>, oznaczający „należący do rodu Aurelia”, a wywodzi się pośrednio od słowa <a href=\"https://pl.wikipedia.org/wiki/%C5%81acina\" target=\"_blank\" rel=\"noopener noreferrer\">łac.</a>&#160;<em>aureolus</em> – „złocisty”. Możliwe jest też pochodzenie imienia od nazwy szczepu <a href=\"https://pl.wikipedia.org/wiki/Galia\" target=\"_blank\" rel=\"noopener noreferrer\">galijskiego</a> Aureliani ze stolicą w Cenabum (późniejsze <i>Aurelianensis</i>, dzisiejszy <a href=\"https://pl.wikipedia.org/wiki/Orlean\" target=\"_blank\" rel=\"noopener noreferrer\">Orlean</a>).", "Ashley": "<b>Ashley</b> – żeńskie, jak i męskie <a href=\"https://pl.wikipedia.org/wiki/Imi%C4%99\" target=\"_blank\" rel=\"noopener noreferrer\">imię</a> pochodzenia staroangielskiego, używane co najmniej od XVI wieku, popularne w krajach anglojęzycznych.", "Artemiusz": "<b>Artemiusz</b> – <a href=\"https://pl.wikipedia.org/wiki/Imi%C4%99\" target=\"_blank\" rel=\"noopener noreferrer\">imię</a> męskie, pochodzenia <a href=\"https://pl.wikipedia.org/wiki/J%C4%99zyk_grecki\" target=\"_blank\" rel=\"noopener noreferrer\">greckiego</a>, w wersji Αρτέμιος/Artemios wywodzące się od imienia bogini <a href=\"https://pl.wikipedia.org/wiki/Artemida\" target=\"_blank\" rel=\"noopener noreferrer\">Artemidy</a>, a w wersji Ἀρτεμής/Artemes znaczące „bezpieczny, idealnego zdrowia”. Imię to nosiło kilku świętych. Forma żeńska – <a href=\"https://pl.wikipedia.org/wiki/Artemia_(imi%C4%99)\" target=\"_blank\" rel=\"noopener noreferrer\">Artemia</a>.", "Amirani": "Według mitu <a href=\"https://pl.wikipedia.org/wiki/Swanowie\" target=\"_blank\" rel=\"noopener noreferrer\">Swanów</a>, żona myśliwego, w zemście za zdradę męża, zabiła boginię, ścinając jej włosy podczas snu. Myśliwy wydobył dziecko z łona zmarłej matki i nadał mu imię <i>Amirani</i>. Chłopiec miał na ciele znamiona świadczące o jego półboskim pochodzeniu – symbole słońca i księżyca na łopatkach oraz złoty ząb.", "Ariusz": "<b>Ariusz</b> (ur. ok. <a href=\"https://pl.wikipedia.org/wiki/256\" target=\"_blank\" rel=\"noopener noreferrer\">256</a> lub <a href=\"https://pl.wikipedia.org/wiki/260\" target=\"_blank\" rel=\"noopener noreferrer\">260</a> w <a href=\"https://pl.wikipedia.org/wiki/Cyrenajka\" target=\"_blank\" rel=\"noopener noreferrer\">Cyrenajce</a>, zm. <a href=\"https://pl.wikipedia.org/wiki/336\" target=\"_blank\" rel=\"noopener noreferrer\">336</a> w <a href=\"https://pl.wikipedia.org/wiki/Konstantynopol\" target=\"_blank\" rel=\"noopener noreferrer\">Konstantynopolu</a>) – wczesnochrześcijański <a href=\"https://pl.wikipedia.org/wiki/Prezbiter\" target=\"_blank\" rel=\"noopener noreferrer\">prezbiter</a>, <a href=\"https://pl.wikipedia.org/wiki/Teolog\" target=\"_blank\" rel=\"noopener noreferrer\">teolog</a> i <a href=\"https://pl.wikipedia.org/wiki/Poezja\" target=\"_blank\" rel=\"noopener noreferrer\">poeta</a> z <a href=\"https://pl.wikipedia.org/wiki/Aleksandria\" target=\"_blank\" rel=\"noopener noreferrer\">Aleksandrii</a>, <a href=\"https://pl.wikipedia.org/wiki/Libia\" target=\"_blank\" rel=\"noopener noreferrer\">Libijczyk</a> z pochodzenia.", "Atanazy": "<b>Atanazy</b> – <a href=\"https://pl.wikipedia.org/wiki/Imi%C4%99\" target=\"_blank\" rel=\"noopener noreferrer\">imię</a> męskie pochodzenia <a href=\"https://pl.wikipedia.org/wiki/J%C4%99zyk_grecki\" target=\"_blank\" rel=\"noopener noreferrer\">greckiego</a>. Wywodzi się od słowa oznaczającego „nieśmiertelny” (<a href=\"https://pl.wikipedia.org/wiki/J%C4%99zyk_grecki\" target=\"_blank\" rel=\"noopener noreferrer\">gr.</a>&#160;Αθανάσιος).", "Alban": "<b>Alban</b> – <a href=\"https://pl.wikipedia.org/wiki/Imi%C4%99\" target=\"_blank\" rel=\"noopener noreferrer\">imię</a> męskie pochodzenia <a href=\"https://pl.wikipedia.org/wiki/%C5%81acina\" target=\"_blank\" rel=\"noopener noreferrer\">łacińskiego</a> genetycznie <a href=\"https://pl.wikipedia.org/wiki/Nazwisko#Przydomek_(cognomen)\" target=\"_blank\" rel=\"noopener noreferrer\">cognomen</a> <i>Albanus</i> oznaczające „pochodzący z Alby”, tj. np. z miasta <i><a href=\"https://pl.wikipedia.org/wiki/Alba_Longa\" target=\"_blank\" rel=\"noopener noreferrer\">Alba Longa</a></i> albo <i>Alba Fucentia</i>; istniała też góra <i><a href=\"https://pl.wikipedia.org/wiki/Monte_Cavo\" target=\"_blank\" rel=\"noopener noreferrer\">Albanus mons</a></i>. Językoznawczyni <a href=\"https://pl.wikipedia.org/wiki/Maria_Malec_(j%C4%99zykoznawczyni)\" target=\"_blank\" rel=\"noopener noreferrer\">Maria Malec</a> wskazuje na odniesienie pochodzenia Albana do miasta <i>Alba Longa</i>.", "Askaniusz": "Wyprowadzony przez ojca z płonącej Troi, towarzyszył mu w wędrówce do Italii. Syn <a href=\"https://pl.wikipedia.org/wiki/Eneasz\" target=\"_blank\" rel=\"noopener noreferrer\">Eneasza</a> i <a href=\"https://pl.wikipedia.org/wiki/Troja\" target=\"_blank\" rel=\"noopener noreferrer\">trojanki</a> <a href=\"https://pl.wikipedia.org/wiki/Kreuza_(c%C3%B3rka_Priama)\" target=\"_blank\" rel=\"noopener noreferrer\">Kreuzy</a>, ojciec <a href=\"https://pl.wikipedia.org/wiki/Silvius\" target=\"_blank\" rel=\"noopener noreferrer\">Silviusa</a>, po śmierci ojca król <a href=\"https://pl.wikipedia.org/wiki/Latynowie\" target=\"_blank\" rel=\"noopener noreferrer\">Latynów</a> i założyciel <a href=\"https://pl.wikipedia.org/wiki/Alba_Longa\" target=\"_blank\" rel=\"noopener noreferrer\">Alby Longi</a>. Jedna z postaci występujących w księdze II <a href=\"https://pl.wikipedia.org/wiki/Eneida\" target=\"_blank\" rel=\"noopener noreferrer\">Eneidy</a>. Według legendy od Askaniusza pochodzi sławny ród Julijski, którego przedstawicielami byli patrycjusze oraz znamienici obywatele <a href=\"https://pl.wikipedia.org/wiki/Rzym\" target=\"_blank\" rel=\"noopener noreferrer\">Rzymu</a>, m.in. <a href=\"https://pl.wikipedia.org/wiki/Gajusz_Juliusz_Cezar\" target=\"_blank\" rel=\"noopener noreferrer\">Juliusz Cezar</a> i <a href=\"https://pl.wikipedia.org/wiki/Oktawian_August\" target=\"_blank\" rel=\"noopener noreferrer\">Oktawian August</a>. Następca Eneasza w panowaniu nad Latynami (wtedy przybrał imię Julus).", "Arwid": "<b>Arwid</b> – <a href=\"https://pl.wikipedia.org/wiki/Imi%C4%99\" target=\"_blank\" rel=\"noopener noreferrer\">imię</a> męskie, złożone ze <a href=\"https://pl.wikipedia.org/wiki/J%C4%99zyk_staronordyjski\" target=\"_blank\" rel=\"noopener noreferrer\">staronordyjskich</a> elementów <i>ari</i> — „orzeł” i <i>viðr</i> — „las”.", "Antonin": "<b>Antonin</b> – <a href=\"https://pl.wikipedia.org/wiki/Imi%C4%99\" target=\"_blank\" rel=\"noopener noreferrer\">imię</a> pochodzenia <a href=\"https://pl.wikipedia.org/wiki/%C5%81acina\" target=\"_blank\" rel=\"noopener noreferrer\">łacińskiego</a>, powstałe od męskiego imienia <a href=\"https://pl.wikipedia.org/wiki/Antoni_(imi%C4%99)\" target=\"_blank\" rel=\"noopener noreferrer\">Antoni</a>.", "Amon": "<b>Amon</b> – <a href=\"https://pl.wikipedia.org/wiki/Imi%C4%99\" target=\"_blank\" rel=\"noopener noreferrer\">imię</a> męskie pochodzenia <a href=\"https://pl.wikipedia.org/wiki/Egipt\" target=\"_blank\" rel=\"noopener noreferrer\">egipskiego</a>. Wywodzi się od <a href=\"https://pl.wikipedia.org/wiki/J%C4%99zyk_grecki\" target=\"_blank\" rel=\"noopener noreferrer\">greckiej</a> wersji imienia egipskiego boga <i><a href=\"https://pl.wikipedia.org/wiki/Amon_(b%C3%B3g_egipski)\" target=\"_blank\" rel=\"noopener noreferrer\">Amona</a></i>. Oznacza: „ożywiający powiew”. Znanych jest około dziesięciu świętych katolickich o tym imieniu.", "Archibald": "<b>Archibald</b> – forma oboczna imienia Erchembod – <a href=\"https://pl.wikipedia.org/wiki/Imi%C4%99\" target=\"_blank\" rel=\"noopener noreferrer\">imię</a> męskie pochodzenia <a href=\"https://pl.wikipedia.org/wiki/J%C4%99zyki_germa%C5%84skie\" target=\"_blank\" rel=\"noopener noreferrer\">germańskiego</a>, złożone z członów <i>ercan</i> („prawdziwy, autentyczny”) i <i>bald</i> („śmiały, odważny”). Inną formą oboczną jest imię <i>Erchembald</i>, a w Polsce występowało w formie <i>Archibald</i>, <i>Archambałt</i>, <i>Archambuł</i>, <i>Erkinbold</i> i <i>Erkambaldus</i>. Według stanu na 17 stycznia 2015 r. imię to miało w Polsce 5 nadań.", "Akira": "<b>Akira</b>&#32;(<a href=\"https://pl.wikipedia.org/wiki/J%C4%99zyk_japo%C5%84ski\" target=\"_blank\" rel=\"noopener noreferrer\">jap.</a>&#32;あきら, アキラ) – popularne <a href=\"https://pl.wikipedia.org/wiki/Imiona_japo%C5%84skie\" target=\"_blank\" rel=\"noopener noreferrer\">męskie imię japońskie</a>, czasem noszone także przez kobiety.", "Afgan": "Wytwarzany głównie przez plemię Ersari zamieszkujące obszary <a href=\"https://pl.wikipedia.org/wiki/Turkmenistan\" target=\"_blank\" rel=\"noopener noreferrer\">Turkmenii</a> nad rzeką <a href=\"https://pl.wikipedia.org/wiki/Amu-daria\" target=\"_blank\" rel=\"noopener noreferrer\">Amu-daria</a> od początku XVII wieku. Pochodzenie nazwy tego kobierca <a href=\"https://pl.wikipedia.org/wiki/Europa\" target=\"_blank\" rel=\"noopener noreferrer\">Europejczycy</a> zawdzięczają pośrednictwu <a href=\"https://pl.wikipedia.org/wiki/Rosjanie\" target=\"_blank\" rel=\"noopener noreferrer\">Rosjan</a>, którzy eksportowali ten towar na <a href=\"https://pl.wikipedia.org/wiki/Europa_Zachodnia\" target=\"_blank\" rel=\"noopener noreferrer\">Zachód</a>, po uprzednim zaopatrzeniu się w <a href=\"https://pl.wikipedia.org/wiki/Kabul\" target=\"_blank\" rel=\"noopener noreferrer\">Kabulu</a>.", "Adar": "Zgodnie z <a href=\"https://pl.wikipedia.org/wiki/Talmud\" target=\"_blank\" rel=\"noopener noreferrer\">Talmudem</a> (traktat Taanit 29a) \"wraz z nadejściem adar nastaje <a href=\"https://pl.wikipedia.org/wiki/Rado%C5%9B%C4%87_(emocja)\" target=\"_blank\" rel=\"noopener noreferrer\">radość</a>\". Istnieje też powiedzenie (<a href=\"https://pl.wikipedia.org/wiki/Jidysz\" target=\"_blank\" rel=\"noopener noreferrer\">jid</a>.): \"אין חודש אדר, זאָגט די גמרא, מרבין בשׂימחה – פֿרייען זיך ייִדעלעך אויף וואָס די וועלט שטייט\", co oznacza: \"w miesiącu adar, jak powiada Gemara, radują się Żydzi na czym świat stoi\".", "Ares": "<b>Ares</b> (<a href=\"https://pl.wikipedia.org/wiki/J%C4%99zyk_grecki\" target=\"_blank\" rel=\"noopener noreferrer\">gr.</a> Ἄρης Árēs, <a href=\"https://pl.wikipedia.org/wiki/%C5%81acina\" target=\"_blank\" rel=\"noopener noreferrer\">łac.</a>&#160;<em>Mars</em>) – w <a href=\"https://pl.wikipedia.org/wiki/Mitologia_grecka\" target=\"_blank\" rel=\"noopener noreferrer\">mitologii greckiej</a> bóg wojny, syn <a href=\"https://pl.wikipedia.org/wiki/Zeus\" target=\"_blank\" rel=\"noopener noreferrer\">Zeusa</a> i <a href=\"https://pl.wikipedia.org/wiki/Hera\" target=\"_blank\" rel=\"noopener noreferrer\">Hery</a>. Jego odpowiednikiem w <a href=\"https://pl.wikipedia.org/wiki/Mitologia_rzymska\" target=\"_blank\" rel=\"noopener noreferrer\">mitologii rzymskiej</a> jest <a href=\"https://pl.wikipedia.org/wiki/Mars_(mitologia)\" target=\"_blank\" rel=\"noopener noreferrer\">Mars</a>. W <a href=\"https://pl.wikipedia.org/wiki/Astrologia\" target=\"_blank\" rel=\"noopener noreferrer\">astrologii</a> identyfikowany z <a href=\"https://pl.wikipedia.org/wiki/Gwiazdozbi%C3%B3r_Barana\" target=\"_blank\" rel=\"noopener noreferrer\">Baranem</a>. Jeden z dwunastu <a href=\"https://pl.wikipedia.org/wiki/Bogowie_olimpijscy\" target=\"_blank\" rel=\"noopener noreferrer\">bogów olimpijskich</a>.", "Augustus": "Młody wódz, wówczas już właściwie jedynowładca imperium rzymskiego, dołączył go do swego imienia jako przydomek i od tamtej pory nosił imię: <i>Imperator Caesar Divi Filius Augustus</i>. Samego słowa nie da się jednoznacznie przetłumaczyć, oznacza mniej więcej \"wyniesiony dzięki boskiej mocy\", \"pełen boskiej mocy\" i wcześniej było używane na określenie obiektów inauguracji, z których przyszłości odczytywali <a href=\"https://pl.wikipedia.org/wiki/Augur\" target=\"_blank\" rel=\"noopener noreferrer\">augurowie</a>. Sam Oktawian nie uznawał ani tego tytułu, ani żadnego z imion jako oficjalnej nazwy sprawowanego przez się urzędu. W tym znaczeniu używał tytułu <a href=\"https://pl.wikipedia.org/wiki/Princeps_senatus\" target=\"_blank\" rel=\"noopener noreferrer\"><i>princeps</i> <i>senatus</i></a>, przyjętego w tym samym roku, który był jedynie honorowym tytułem nadawanym jednemu z senatorów, który znajdował się na szczycie listy senackiej i miał prawo rozpoczynać obrady. Było to świadome działanie Oktawiana, który chciał być widziany jako odnowiciel republiki zaprowadzający pokój, stąd też unikał używania militarnego tytułu <i>dux</i>, który nosił w czasie wojen domowych, a także nie przyjął władzy królewskiej wiążącej się z tytułem <i>rex</i>, a powszechnie znienawidzonej w republikańskim Rzymie.", "Aldrin": "Została nazwana imieniem twórcy metody jej wytwarzania – noblisty z 1950 <a href=\"https://pl.wikipedia.org/wiki/Kurt_Alder\" target=\"_blank\" rel=\"noopener noreferrer\">Kurta Aldera</a>.", "Aureli": "<b>Aureli</b> – oboczna forma <a href=\"https://pl.wikipedia.org/wiki/Imi%C4%99\" target=\"_blank\" rel=\"noopener noreferrer\">imienia</a> męskiego <a href=\"https://pl.wikipedia.org/wiki/Aureliusz\" target=\"_blank\" rel=\"noopener noreferrer\">Aureliusz</a>, pochodzącego od nazwy rzymskiego rodu Aureliuszy, która z kolei pochodzi od <a href=\"https://pl.wikipedia.org/wiki/%C5%81ac.\" target=\"_blank\" rel=\"noopener noreferrer\">łacińskiego</a> <i>aureolus</i> – „złocisty” (co mogło znaczyć także „wspaniały”).", "Anna": "<b>Anna</b>, <b>Hanna</b> (<a href=\"https://pl.wikipedia.org/wiki/J%C4%99zyk_hebrajski\" target=\"_blank\" rel=\"noopener noreferrer\">hebr.</a>&#160;&#8207;חַנָּה&#8206; <i>hannāh</i> – „łaska”) – <a href=\"https://pl.wikipedia.org/wiki/Imi%C4%99\" target=\"_blank\" rel=\"noopener noreferrer\">imię</a> żeńskie pochodzenia <a href=\"https://pl.wikipedia.org/wiki/J%C4%99zyk_hebrajski\" target=\"_blank\" rel=\"noopener noreferrer\">hebrajskiego</a>, które tłumaczy się jako „pełna wdzięku, łaski”.", "Anicet": "<b>Anicet</b> – <a href=\"https://pl.wikipedia.org/wiki/Imi%C4%99\" target=\"_blank\" rel=\"noopener noreferrer\">imię</a> męskie pochodzące od <i>Anicetus</i>, <a href=\"https://pl.wikipedia.org/wiki/%C5%81acina\" target=\"_blank\" rel=\"noopener noreferrer\">zlatynizowanej</a> formy greckiego imienia <i>Aniketos</i>. Wywodzi się ono od słowa oznaczającego „niezwyciężony, niepokonany”. Nosił je jeden z wczesnych <a href=\"https://pl.wikipedia.org/wiki/Papie%C5%BC\" target=\"_blank\" rel=\"noopener noreferrer\">papieży</a>, <a href=\"https://pl.wikipedia.org/wiki/Anicet_(papie%C5%BC)\" target=\"_blank\" rel=\"noopener noreferrer\">św. Anicet</a>.", "Agaton": "<b>Agaton</b> – <a href=\"https://pl.wikipedia.org/wiki/Imi%C4%99\" target=\"_blank\" rel=\"noopener noreferrer\">imię</a> męskie pochodzenia <a href=\"https://pl.wikipedia.org/wiki/J%C4%99zyk_grecki\" target=\"_blank\" rel=\"noopener noreferrer\">greckiego</a>, wywodzące się od słowa 'agathós', ' agath', oznaczający „dobry”. Wśród patronów tego imienia święci: Agaton, żołnierz (zm. w 250) i papież <a href=\"https://pl.wikipedia.org/wiki/Agaton_(papie%C5%BC)\" target=\"_blank\" rel=\"noopener noreferrer\">św. Agaton</a> (zm. w 681). Od tego imienia (<i>: Agafon</i>) powstała staroruska forma skrócona (zdrobniała, spieszczona) <i>Gafan(ko)</i>, utworzona za pomocą popularnej w imiennictwie zarówno ruskim, jak i polskim techniki ucinania nagłosu.", "Atsushi": "<b>Atsushi</b>&#32;(<a href=\"https://pl.wikipedia.org/wiki/J%C4%99zyk_japo%C5%84ski\" target=\"_blank\" rel=\"noopener noreferrer\">jap.</a>&#32;アツシ, あつし) – męskie <a href=\"https://pl.wikipedia.org/wiki/Imiona_japo%C5%84skie\" target=\"_blank\" rel=\"noopener noreferrer\">imię japońskie</a>.", "Aleksa": "<b>Aleksa</b> – forma żeńska <a href=\"https://pl.wikipedia.org/wiki/Imi%C4%99\" target=\"_blank\" rel=\"noopener noreferrer\">imienia</a> <a href=\"https://pl.wikipedia.org/wiki/Aleksy\" target=\"_blank\" rel=\"noopener noreferrer\">Aleksy</a>.", "Ami": "<b>Ami</b>&#32;(<a href=\"https://pl.wikipedia.org/wiki/J%C4%99zyk_japo%C5%84ski\" target=\"_blank\" rel=\"noopener noreferrer\">jap.</a>&#32;あみ, アミ, 亜美) – żeńskie <a href=\"https://pl.wikipedia.org/wiki/Imiona_japo%C5%84skie\" target=\"_blank\" rel=\"noopener noreferrer\">imię japońskie</a>.", "Abelard": "<b>Abelard</b> – <a href=\"https://pl.wikipedia.org/wiki/Imi%C4%99\" target=\"_blank\" rel=\"noopener noreferrer\">imię</a> męskie zapewne pochodzenia <a href=\"https://pl.wikipedia.org/wiki/J%C4%99zyk_francuski\" target=\"_blank\" rel=\"noopener noreferrer\">francuskiego</a> (<a href=\"https://pl.wikipedia.org/wiki/Dialekt_prowansalski\" target=\"_blank\" rel=\"noopener noreferrer\">prowansalskiego</a>), którego pierwotne znaczenie wywodzone jest od wyrazu prowansalskiego <i>abelha</i>, oznaczającego „<a href=\"https://pl.wikipedia.org/wiki/Pszczelarz\" target=\"_blank\" rel=\"noopener noreferrer\">pszczelarza</a>”. Jednak bywa ono także łączone z <a href=\"https://pl.wikipedia.org/wiki/J%C4%99zyk_niemiecki\" target=\"_blank\" rel=\"noopener noreferrer\">niemieckimi</a> imionami <i>Adalhard</i> (dosł. „szlachetna siła”) bądź też <i><a href=\"https://pl.wikipedia.org/wiki/Eberhard\" target=\"_blank\" rel=\"noopener noreferrer\">Eberhard</a></i> (dosł. „silny jak dzik”).", "Abd": "<b>Abd</b> albo <b>`Abd</b> – w <a href=\"https://pl.wikipedia.org/wiki/Islam\" target=\"_blank\" rel=\"noopener noreferrer\">islamskich</a> imionach <a href=\"https://pl.wikipedia.org/wiki/J%C4%99zyk_arabski\" target=\"_blank\" rel=\"noopener noreferrer\">arabskich</a> oznacza sługę. Występuje zawsze w połączeniu z jednym z <a href=\"https://pl.wikipedia.org/wiki/99_atrybut%C3%B3w_Allaha\" target=\"_blank\" rel=\"noopener noreferrer\">99 imion Boga</a>.Np.: <a href=\"https://pl.wikipedia.org/wiki/Abdallah\" target=\"_blank\" rel=\"noopener noreferrer\">Abdallah</a> – Sługa Allaha, Abd al-Aziz – Sługa Wszechmocnego, … .„Abd” używane było w imionach również w <a href=\"https://pl.wikipedia.org/wiki/D%C5%BCahilijja\" target=\"_blank\" rel=\"noopener noreferrer\">czasach przedislamskich</a> jak np. w imieniu prapradziada <a href=\"https://pl.wikipedia.org/wiki/Mahomet\" target=\"_blank\" rel=\"noopener noreferrer\">Mahometa</a> <i>Abd <a href=\"https://pl.wikipedia.org/wiki/Manaf\" target=\"_blank\" rel=\"noopener noreferrer\">Manaf</a></i>.", "Ardi": "<i><b>Ardipithecus ramidus</b></i> (syn. <i>Australopithecus ramidus</i>; <i>Ardipithecus ramidus ramidus</i>) – <a href=\"https://pl.wikipedia.org/wiki/Gatunek_(biologia)\" target=\"_blank\" rel=\"noopener noreferrer\">gatunek</a> wymarłego ssaka <a href=\"https://pl.wikipedia.org/wiki/Naczelne\" target=\"_blank\" rel=\"noopener noreferrer\">naczelnego</a> z rodziny <a href=\"https://pl.wikipedia.org/wiki/Cz%C5%82owiekowate\" target=\"_blank\" rel=\"noopener noreferrer\">człowiekowatych</a> (Hominidae) żyjącego w <a href=\"https://pl.wikipedia.org/wiki/Pliocen\" target=\"_blank\" rel=\"noopener noreferrer\">pliocenie</a> na terenach <a href=\"https://pl.wikipedia.org/wiki/Afryka\" target=\"_blank\" rel=\"noopener noreferrer\">Afryki</a>. Najbardziej kompletne <a href=\"https://pl.wikipedia.org/wiki/Skamienia%C5%82o%C5%9Bci\" target=\"_blank\" rel=\"noopener noreferrer\">skamieniałości</a> <i>A. ramidus</i> pochodzą z okolic wioski Aramis w <a href=\"https://pl.wikipedia.org/wiki/Etiopia\" target=\"_blank\" rel=\"noopener noreferrer\">Etiopii</a> i liczą około 4,4 mln lat. Znaleziony tam szkielet młodej samicy nie przypomina budową szkieletu <a href=\"https://pl.wikipedia.org/wiki/Szympans\" target=\"_blank\" rel=\"noopener noreferrer\">szympansa</a>, <a href=\"https://pl.wikipedia.org/wiki/Goryl\" target=\"_blank\" rel=\"noopener noreferrer\">goryla</a>, ani innych naczelnych blisko spokrewnionych z człowiekiem. <i>A. ramidus</i> wykazywał cechy zarówno hominidów nadrzewnych, jak i pewną formę naziemnej <a href=\"https://pl.wikipedia.org/wiki/Dwuno%C5%BCno%C5%9B%C4%87\" target=\"_blank\" rel=\"noopener noreferrer\">dwunożności</a>, bardziej prymitywną niż występująca u <i><a href=\"https://pl.wikipedia.org/wiki/Australopiteki\" target=\"_blank\" rel=\"noopener noreferrer\">Australopithecus</a></i>. Żył prawdopodobnie głównie w <a href=\"https://pl.wikipedia.org/wiki/Las\" target=\"_blank\" rel=\"noopener noreferrer\">lasach</a>. Był stworzeniem dwunożnym, miał chwytne stopy, stosunkowo niewielką czaszkę – objętość puszki mózgowej wynosiła 300–350 cm³. Wiele cech budowy czaszki występowało także u <i><a href=\"https://pl.wikipedia.org/wiki/Sahelantrop\" target=\"_blank\" rel=\"noopener noreferrer\">Sahelanthropus</a></i>, dowodząc, że czaszki środkowoplioceńskich hominidów znacząco różniły się od tych u australopiteków oraz współczesnych małp. Odnaleziono ponad 145 zębów <i>Ardipithecus ramidus</i> – ich budowa sugeruje, że hominid ten był prawdopodobnie wszystkożercą lub owocożercą. Samica miała około 120 cm wzrostu i ważyła 50 kg.", "Anu": "Jego imię pisano za pomocą znaku klinowego w kształcie gwiazdy, który oznacza zarówno niebo (sum. <b>AN</b>), jak i boga (sum. <b>DINGIR</b>, akad. <i>ilu</i>). Pan wszystkich bogów rozsądza ich kłótnie, a jego wyroki są nieodwołalne; niewiele obchodzą go jednak sprawy ludzkie. Majestatyczny, szanowany, ale zajmujący najwyższą sferę nieba pozostaje zawsze kimś dalekim i w gruncie rzeczy dosyć niewyraźnym.", "Abir": "<b>Abir</b> – <a href=\"https://pl.wikipedia.org/wiki/Imi%C4%99\" target=\"_blank\" rel=\"noopener noreferrer\">imię</a> żeńskie pochodzenia arabskiego o znaczeniu \"zapach\". Obecnie rzadko nadawane.", "Alif": "أ, إ – jako nośnik <a href=\"https://pl.wikipedia.org/wiki/Hamza\" target=\"_blank\" rel=\"noopener noreferrer\">hamzy (ء)</a> – wtedy może na początku wyrazów oznaczać krótkie <b>a</b>, <b>i</b> lub <b>u</b>; występowanie: np. w słowie alif (ألف).", "Abdon": "<b>Abdon</b> – <a href=\"https://pl.wikipedia.org/wiki/Imi%C4%99\" target=\"_blank\" rel=\"noopener noreferrer\">imię</a> męskie pochodzenia <a href=\"https://pl.wikipedia.org/wiki/Biblia\" target=\"_blank\" rel=\"noopener noreferrer\">biblijnego</a>. Wywodzi się z <a href=\"https://pl.wikipedia.org/wiki/J%C4%99zyk_hebrajski\" target=\"_blank\" rel=\"noopener noreferrer\">hebrajskiego</a> słowa oznaczającego „sługa”. Nosił je <a href=\"https://pl.wikipedia.org/wiki/Abdon_i_Senen\" target=\"_blank\" rel=\"noopener noreferrer\">święty Abdon</a> żyjący w II lub III wieku. Abdon <a href=\"https://pl.wikipedia.org/wiki/Imieniny\" target=\"_blank\" rel=\"noopener noreferrer\">imieniny</a> obchodzi 30 lipca.", "Aldis": "Aldis ma istotne znaczenie w porozumiewaniu się w czasie <a href=\"https://pl.wikipedia.org/wiki/Cisza_radiowa\" target=\"_blank\" rel=\"noopener noreferrer\">ciszy radiowej</a>.", "Ananiasz": "<b>Ananiasz</b> – <a href=\"https://pl.wikipedia.org/wiki/Imi%C4%99\" target=\"_blank\" rel=\"noopener noreferrer\">imię</a> męskie pochodzenia <a href=\"https://pl.wikipedia.org/wiki/Biblia\" target=\"_blank\" rel=\"noopener noreferrer\">biblijnego</a>. Grecka forma <a href=\"https://pl.wikipedia.org/wiki/J%C4%99zyk_hebrajski\" target=\"_blank\" rel=\"noopener noreferrer\">hebrajskiego</a> <i>Hananiah</i> – „<a href=\"https://pl.wikipedia.org/wiki/Jahwe\" target=\"_blank\" rel=\"noopener noreferrer\">Jahwe</a> jest łaskawy”. Jednym z patronów tego imienia jest <a href=\"https://pl.wikipedia.org/wiki/Ananiasz_z_Damaszku\" target=\"_blank\" rel=\"noopener noreferrer\">św. Ananiasz z Damaszku</a>.", "Amand": "<b>Amand</b> – <a href=\"https://pl.wikipedia.org/wiki/Imi%C4%99\" target=\"_blank\" rel=\"noopener noreferrer\">imię</a> męskie pochodzące od <a href=\"https://pl.wikipedia.org/wiki/%C5%81acina\" target=\"_blank\" rel=\"noopener noreferrer\">łacińskiego</a> <i><a href=\"https://pl.wikipedia.org/wiki/Amandus\" target=\"_blank\" rel=\"noopener noreferrer\">Amandus</a></i> wywodzące się od słowa <i>amara</i>, 'kochać'. Amand to ten, „który powinien być kochany”. Istnieje trzech świętych patronów tego imienia.", "Adelbert": "<b>Adalbert, Adelbert</b> – <a href=\"https://pl.wikipedia.org/wiki/Imi%C4%99\" target=\"_blank\" rel=\"noopener noreferrer\">imię</a> męskie pochodzenia <a href=\"https://pl.wikipedia.org/wiki/J%C4%99zyki_germa%C5%84skie\" target=\"_blank\" rel=\"noopener noreferrer\">germańskiego</a>. Wywodzi się od słów oznaczających <i>adal</i> (ród szlachecki) i <i>beraht</i> (jasny, błyszczący), oznaczało „pochodzącego ze szlachetnego rodu”. Występuje w wielu odmianach, np.: <a href=\"https://pl.wikipedia.org/wiki/Albert_(imi%C4%99)\" target=\"_blank\" rel=\"noopener noreferrer\">Albert</a>, Olbracht.", "Alla": "<b>Alla</b>, <i>Ałła</i> – <a href=\"https://pl.wikipedia.org/wiki/Imi%C4%99\" target=\"_blank\" rel=\"noopener noreferrer\">imię</a> żeńskie prawdopodobnie pochodzenia <a href=\"https://pl.wikipedia.org/wiki/J%C4%99zyk_grecki\" target=\"_blank\" rel=\"noopener noreferrer\">greckiego</a> i wywodzące się od <a href=\"https://pl.wikipedia.org/wiki/J%C4%99zyk_grecki\" target=\"_blank\" rel=\"noopener noreferrer\">gr.</a>&#160;άλλη – „inna”. Używane przede wszystkim w Rosji, na <a href=\"https://pl.wikipedia.org/wiki/Bia%C5%82oru%C5%9B\" target=\"_blank\" rel=\"noopener noreferrer\">Białorusi</a> i <a href=\"https://pl.wikipedia.org/wiki/Ukraina\" target=\"_blank\" rel=\"noopener noreferrer\">Ukrainie</a>.", "Akio": "<b>Akio</b>&#32;(<a href=\"https://pl.wikipedia.org/wiki/J%C4%99zyk_japo%C5%84ski\" target=\"_blank\" rel=\"noopener noreferrer\">jap.</a>&#32;あきお, アキオ) – męskie <a href=\"https://pl.wikipedia.org/wiki/Imiona_japo%C5%84skie\" target=\"_blank\" rel=\"noopener noreferrer\">imię japońskie</a>.", "Asa": "<b>Asa</b> – imię męskie o niepewnym znaczeniu. Według jednej z hipotez jest skróceniem hebrajskiego słowa <i>asael</i>, znaczącego „stworzył Bóg”.", "Amilcar": "Znane było z wytwarzania aut wyścigowych oraz eleganckich modeli wyższej <a href=\"https://pl.wikipedia.org/wiki/Autosegment_D\" target=\"_blank\" rel=\"noopener noreferrer\">klasy średniej</a>. Sukcesem okazał się udział w wyścigu <a href=\"https://pl.wikipedia.org/wiki/24h_Le_Mans\" target=\"_blank\" rel=\"noopener noreferrer\">Le Mans</a> w 1924 i 1932 roku. W 1937 zostało przejęte przez koncern <a href=\"https://pl.wikipedia.org/wiki/Hotchkiss\" target=\"_blank\" rel=\"noopener noreferrer\">Hotchkiss et Cie</a>. Produkcji aut tej marki zaprzestano w czasie <a href=\"https://pl.wikipedia.org/wiki/II_wojna_%C5%9Bwiatowa\" target=\"_blank\" rel=\"noopener noreferrer\">II wojny światowej</a> i już nie wznowiono. Nazwa „Amilcar” pochodzi ze złożenia nazwisk założycieli firmy (Joseph Lamy i Émile Akar). Do 1937 występowało pod nazwą „Sté Nouvelle pour l’Automobile Amilcar”, a potem „Sté Financière pour l’Automobile”.", "Antos": "Nazwisko <b>Antos</b> (Antosz) wywodzi się od imienia <a href=\"https://pl.wikipedia.org/wiki/Antoni_(imi%C4%99)\" target=\"_blank\" rel=\"noopener noreferrer\">Antoni</a>, notowanego w Polsce od XIII wieku; pochodzącego od łacińskiego Antonius (<a href=\"https://pl.wikipedia.org/wiki/Dynastia_Antonin%C3%B3w\" target=\"_blank\" rel=\"noopener noreferrer\">Antoninowie</a>) – znanego rodu rzymskiego i dynastii w cesarstwie rzymskim panującej w latach 96–192. Jest notowane w Polsce od XIII wieku.", "Aldi": "<b>Aldi</b> (nazwa stylizowana: <b>ALDI</b>) – <a href=\"https://pl.wikipedia.org/wiki/Niemcy\" target=\"_blank\" rel=\"noopener noreferrer\">niemiecka</a> sieć dyskontów spożywczo-przemysłowych obecna na pięciu kontynentach. Siódma pod względem sprzedaży sieć marketów na świecie. Nazwa przedsiębiorstwa pochodzi od skrótu nazwiska <b>Al</b>brecht i słowa <b>di</b>skont. Przedsiębiorstwo powstało i do dziś jest <a href=\"https://pl.wikipedia.org/wiki/Przedsi%C4%99biorstwo_rodzinne\" target=\"_blank\" rel=\"noopener noreferrer\">firmą rodzinną</a> Albrechtów z <a href=\"https://pl.wikipedia.org/wiki/Essen\" target=\"_blank\" rel=\"noopener noreferrer\">Essen</a>.", "Aki": "<b>Aki</b>&#32;(<a href=\"https://pl.wikipedia.org/wiki/J%C4%99zyk_japo%C5%84ski\" target=\"_blank\" rel=\"noopener noreferrer\">jap.</a>&#32;あき, アキ) – popularne <a href=\"https://pl.wikipedia.org/wiki/Imiona_japo%C5%84skie\" target=\"_blank\" rel=\"noopener noreferrer\">imię japońskie</a>, fińskie i nigeryjskie. W Japonii występuje także jako nazwisko.", "Agenor": "<b>Agenor</b> – <a href=\"https://pl.wikipedia.org/wiki/Imi%C4%99\" target=\"_blank\" rel=\"noopener noreferrer\">imię</a> męskie pochodzenia <a href=\"https://pl.wikipedia.org/wiki/J%C4%99zyk_grecki\" target=\"_blank\" rel=\"noopener noreferrer\">greckiego</a>. Wywodzi się od słowa oznaczającego „mężny”, „bohaterski”.", "Amaro": "Amaro powstaje na bazie produktów pochodzących z Włoch – ziół, przypraw, kwiatów i/lub skórki <a href=\"https://pl.wikipedia.org/wiki/Cytrus\" target=\"_blank\" rel=\"noopener noreferrer\">owoców cytrusowych</a>. Skład mieszanki różni się w zależności od marki, a informacje takie jak proporcje użytych produktów, czy szczegóły procesu powstawania amaro utrzymywane są w tajemnicy. Po wybraniu składników bazowych dla danego likieru poddaje się je procesom mającym na celu uzyskanie z nich smaku i aromatu – część z nich zostaje namoczona w alkoholu, część w wodzie. Każdy z użytych produktów ma pewien określony czas, w którym oddaje rozpuszczalnikowi swoją esencję. Dlatego też składające się na końcowy efekt, czyli smak likieru, elementy często nie mogą być macerowane razem. W chwili uzyskania oczekiwanego rezultatu prowadzonych do tej pory działań, poszczególne ciecze łączy się ze sobą w ściśle określonych proporcjach, a następnie przelewa do beczek (niektóre rodzaje amari np. Fernet-Branca dojrzewają) lub butelek.", "Azariasz": "<b>Azariasz</b> – hebrajskie i biblijne imię męskie oznaczające „<a href=\"https://pl.wikipedia.org/wiki/Jahwe\" target=\"_blank\" rel=\"noopener noreferrer\">Jahwe</a> dopomógł”, „<a href=\"https://pl.wikipedia.org/wiki/Jahwe\" target=\"_blank\" rel=\"noopener noreferrer\">Jahwe</a> wspomaga” (hebr. Azarjahu, Azaria).", "Ajin": "Oznacza <a href=\"https://pl.wikipedia.org/wiki/Sp%C3%B3%C5%82g%C5%82oska_szczelinowa_gard%C5%82owa_d%C5%BAwi%C4%99czna\" target=\"_blank\" rel=\"noopener noreferrer\">szczelinową dźwięczną spółgłoskę gardłową</a> lub <a href=\"https://pl.wikipedia.org/wiki/Sp%C3%B3%C5%82g%C5%82oska_szczelinowa_nag%C5%82o%C5%9Bniowa_d%C5%BAwi%C4%99czna\" target=\"_blank\" rel=\"noopener noreferrer\">nagłośniową</a>.", "Allah": "<a href=\"https://pl.wikipedia.org/wiki/Mitologia_arabska\" target=\"_blank\" rel=\"noopener noreferrer\">Początkowo</a> słowo Allah było wykorzystywane zarówno przez <a href=\"https://pl.wikipedia.org/wiki/Arabowie\" target=\"_blank\" rel=\"noopener noreferrer\">Arabów</a> do określania <a href=\"https://pl.wikipedia.org/wiki/B%C3%B3g\" target=\"_blank\" rel=\"noopener noreferrer\">boga</a> <a href=\"https://pl.wikipedia.org/wiki/Ksi%C4%99%C5%BCyc\" target=\"_blank\" rel=\"noopener noreferrer\">Księżyca</a> – <a href=\"https://pl.wikipedia.org/wiki/Nanna_(b%C3%B3g)\" target=\"_blank\" rel=\"noopener noreferrer\">Sina</a>, wywodzącego się od sumeryjskiego boga księżyca <a href=\"https://pl.wikipedia.org/wiki/Nanna_(b%C3%B3g)\" target=\"_blank\" rel=\"noopener noreferrer\">Nanny</a>, jak i przez chrześcijańskich Arabów do określania Boga. Pomimo że jest tradycyjnie kojarzone z islamem, słowo Allah nie jest specyficzne dla tej religii. Także wśród przedislamskich i chrześcijańskich Arabów słowami Allah/Alihah oznaczającymi to samo co u żydów Eloh/<a href=\"https://pl.wikipedia.org/wiki/Elohim\" target=\"_blank\" rel=\"noopener noreferrer\">Elohim</a> określano Boga w rozumieniu monoteistycznym. Słowo Allah występuje między innymi na inskrypcji z Umm al-Dżimal. Od czasów <a href=\"https://pl.wikipedia.org/wiki/Mahomet\" target=\"_blank\" rel=\"noopener noreferrer\">Mahometa</a> zaczęło ono oznaczać dla muzułmanów w języku arabskim wyłącznie abrahamicznego Boga i dlatego chociaż ma ono lingwistycznie formy liczby mnogiej oraz rodzaju żeńskiego, to te formy gramatyczne nie są obecnie stosowane, przynajmniej wśród muzułmanów.", "Akihiro": "<b>Akihiro</b>&#32;(<a href=\"https://pl.wikipedia.org/wiki/J%C4%99zyk_japo%C5%84ski\" target=\"_blank\" rel=\"noopener noreferrer\">jap.</a>&#32;あきひろ, アキヒロ) – <a href=\"https://pl.wikipedia.org/wiki/Imiona_japo%C5%84skie\" target=\"_blank\" rel=\"noopener noreferrer\">męskie imię japońskie</a>.", "Alian": "Populacja dzielnicy Alian w 2016 roku liczyła 29&#160;093 mieszkańców – 14&#160;407 kobiet i 14&#160;686 mężczyzn. Liczba gospodarstw domowych wynosiła 9407, co oznacza, że w jednym gospodarstwie zamieszkiwało średnio 3,09 osób.", "Akan": "<b>Akan</b> (<a href=\"https://pl.wikipedia.org/wiki/J%C4%99zyk_hebrajski\" target=\"_blank\" rel=\"noopener noreferrer\">hebr.</a> עָכָן) – postać biblijna <a href=\"https://pl.wikipedia.org/wiki/Stary_Testament\" target=\"_blank\" rel=\"noopener noreferrer\">Starego Testamentu</a>. Występuje w <a href=\"https://pl.wikipedia.org/wiki/Ksi%C4%99ga_Jozuego\" target=\"_blank\" rel=\"noopener noreferrer\">Księdze Jozuego</a> w rozdziale 7. Wymieniany jest także w <a href=\"https://biblia.deon.pl/otworz.php?skrot=1%20Krn%202,7\" target=\"_blank\" rel=\"noopener noreferrer\">1 Krn 2,7</a> i nosi tam imię Akor.", "Audrey": "<b>Edeltruda</b>, <b>Edeltrauda</b> – <a href=\"https://pl.wikipedia.org/wiki/Imi%C4%99\" target=\"_blank\" rel=\"noopener noreferrer\">imię</a> żeńskie pochodzenia <a href=\"https://pl.wikipedia.org/wiki/J%C4%99zyk_staro-wysoko-niemiecki\" target=\"_blank\" rel=\"noopener noreferrer\">staro-wysoko-niemieckiego</a>, nienotowane w Polsce w średniowieczu; obecnie występuje w zauważalnym stopniu w Polsce na obszarach zamieszkiwanych przez mniejszość niemiecką. Imię to powstało z połączenia członów <i>adal</i> – 'szlachetny ród' oraz <i>trud</i> – 'siła, potęga' i stanowi późniejszą wersję niemieckiego imienia <i>Adeltraud</i>.", "Amelia": "<b>Amelia</b>, <b><a href=\"https://pl.wikipedia.org/wiki/Amalia\" target=\"_blank\" rel=\"noopener noreferrer\">Amalia</a></b> – <a href=\"https://pl.wikipedia.org/wiki/Imi%C4%99\" target=\"_blank\" rel=\"noopener noreferrer\">imię</a> żeńskie pochodzenia <a href=\"https://pl.wikipedia.org/wiki/Imiona_germa%C5%84skie\" target=\"_blank\" rel=\"noopener noreferrer\">germańskiego</a>, powstałe jako skrócenie imion dwuczłonowych z pierwszym członem <i>Amal-</i>, takich jak między innymi <a href=\"https://pl.wikipedia.org/wiki/Amalgunda\" target=\"_blank\" rel=\"noopener noreferrer\">Amalgunda</a> lub <a href=\"https://pl.wikipedia.org/wiki/Amalberga\" target=\"_blank\" rel=\"noopener noreferrer\">Amalberga</a>.", "Alit": "<b>Alit</b> – <a href=\"https://pl.wikipedia.org/wiki/Mineralogia\" target=\"_blank\" rel=\"noopener noreferrer\">mineralogiczna</a> nazwa krzemianu triwapnia (zasadowego krzemianu wapnia). Jest to <a href=\"https://pl.wikipedia.org/wiki/Zwi%C4%85zki_nieorganiczne\" target=\"_blank\" rel=\"noopener noreferrer\">nieorganiczny związek chemiczny</a>, <a href=\"https://pl.wikipedia.org/wiki/Sole\" target=\"_blank\" rel=\"noopener noreferrer\">sól</a> <a href=\"https://pl.wikipedia.org/wiki/Kwasy_krzemowe\" target=\"_blank\" rel=\"noopener noreferrer\">kwasu krzemowego</a> i <a href=\"https://pl.wikipedia.org/wiki/Wap%C5%84\" target=\"_blank\" rel=\"noopener noreferrer\">wapnia</a> o wzorze zapisywanym jako Ca3SiO5 lub 3CaO&#183;SiO2, a w notacji chemii cementu&#65279;<a href=\"https://www.wikidata.org/wiki/Q3344437#sitelinks-wikipedia\" target=\"_blank\" rel=\"noopener noreferrer\">(inne języki)</a> oznaczanego symbolem C3S. Jest składnikiem <a href=\"https://pl.wikipedia.org/wiki/Klinkier_cementowy\" target=\"_blank\" rel=\"noopener noreferrer\">klinkieru</a> (półproduktu <a href=\"https://pl.wikipedia.org/wiki/Cement_portlandzki\" target=\"_blank\" rel=\"noopener noreferrer\">cementu portlandzkiego</a>) odpowiedzialnym za wczesne wiązanie cementu.", "Amilkar": "<b>Hamilkar</b> lub <b>Amilkar</b> – imię męskie, wywodzi się od <a href=\"https://pl.wikipedia.org/wiki/J%C4%99zyk_fenicki\" target=\"_blank\" rel=\"noopener noreferrer\">fenickiego</a> imienia <i>Abd-Melkart</i>, oznaczającego „sługa <a href=\"https://pl.wikipedia.org/wiki/Melkart\" target=\"_blank\" rel=\"noopener noreferrer\">Melkarta</a>” (boga <a href=\"https://pl.wikipedia.org/wiki/Tyr_(miasto)\" target=\"_blank\" rel=\"noopener noreferrer\">Tyru</a>). Imię pospolite w punickiej kulturze, panujące rodziny starożytnej Kartaginy często nadawały członkom swego rodu to właśnie imię.", "Achacy": "<b>Achacy</b> – <a href=\"https://pl.wikipedia.org/wiki/Imi%C4%99\" target=\"_blank\" rel=\"noopener noreferrer\">imię</a> męskie najprawdopodobniej pochodzenia <a href=\"https://pl.wikipedia.org/wiki/J%C4%99zyk_grecki\" target=\"_blank\" rel=\"noopener noreferrer\">greckiego</a>. W takim przypadku pochodzi ono od wyrazu <i>achátēs</i> – „<a href=\"https://pl.wikipedia.org/wiki/Agat\" target=\"_blank\" rel=\"noopener noreferrer\">agat</a>”. Może również pochodzić od greckiego imienia Ἀκακίος <i>Akakios</i> (od ἀκακός <i>akakos</i> – „niewinny”, „nieznający zła”), albo od greckiego wyrazu ἀγαθός <i>agathos</i> – „dobry”. Jego żeńskim odpowiednikiem są <a href=\"https://pl.wikipedia.org/wiki/Achacja\" target=\"_blank\" rel=\"noopener noreferrer\">Achacja</a> i Akacja.", "Abdiasz": "<b>Abdiasz</b> (<a href=\"https://pl.wikipedia.org/wiki/J%C4%99zyk_hebrajski\" target=\"_blank\" rel=\"noopener noreferrer\">hebr.</a> <i>Abhadjah, Obhadjahu, Obadiah)</i> — <a href=\"https://pl.wikipedia.org/wiki/Imi%C4%99\" target=\"_blank\" rel=\"noopener noreferrer\">imię</a> męskie pochodzenia <a href=\"https://pl.wikipedia.org/wiki/J%C4%99zyk_hebrajski\" target=\"_blank\" rel=\"noopener noreferrer\">hebrajskiego</a>, oznaczające „sługa <a href=\"https://pl.wikipedia.org/wiki/Jahwe\" target=\"_blank\" rel=\"noopener noreferrer\">Jahwe</a>”. Nosił je jeden z dwunastu <a href=\"https://pl.wikipedia.org/wiki/Prorocy_mniejsi\" target=\"_blank\" rel=\"noopener noreferrer\">proroków mniejszych</a> — <a href=\"https://pl.wikipedia.org/wiki/Abdiasz_(prorok)\" target=\"_blank\" rel=\"noopener noreferrer\">prorok Abdiasz</a>. Według stanu na 31 stycznia 2023 r. imię to miało w Polsce 7 nadań.", "Andronik": "<b>Andronik</b> – <a href=\"https://pl.wikipedia.org/wiki/Imi%C4%99\" target=\"_blank\" rel=\"noopener noreferrer\">imię</a> męskie pochodzenia <a href=\"https://pl.wikipedia.org/wiki/J%C4%99zyk_grecki\" target=\"_blank\" rel=\"noopener noreferrer\">greckiego</a>. Pochodzi od starogreckiego imienia <i>Andronikos</i> (gr. <i>Ανδρόνικος</i>) wywodzącego się od słów <i>andros</i> (człowiek) i <i>nike</i> (zwycięstwo), które w złożeniu znaczą „zwycięzca”.", "Amen": "Na <a href=\"https://pl.wikipedia.org/wiki/Bliski_Wsch%C3%B3d\" target=\"_blank\" rel=\"noopener noreferrer\">Bliskim Wschodzie</a> termin ten pierwotnie oznaczał potwierdzenie przysięgi żołnierskiej (<a href=\"https://pl.wikipedia.org/wiki/Asyria\" target=\"_blank\" rel=\"noopener noreferrer\">Asyria</a>) – odpowiednik dzisiejszego „tak jest”, „rozkaz” lub „wykonam”. Jego wypowiedzenie po wysłuchaniu modlitw i błogosławieństw zastępowało ich odmówienie – w starożytności niewiele osób znało modlitwy na pamięć.", "Addison": "<b>Adam</b> – <a href=\"https://pl.wikipedia.org/wiki/Imi%C4%99\" target=\"_blank\" rel=\"noopener noreferrer\">imię</a> męskie pochodzenia <a href=\"https://pl.wikipedia.org/wiki/Ludy_semickie\" target=\"_blank\" rel=\"noopener noreferrer\">semickiego</a>. W języku <a href=\"https://pl.wikipedia.org/wiki/J%C4%99zyk_hebrajski\" target=\"_blank\" rel=\"noopener noreferrer\">hebrajskim</a> אדום <i>adom</i> oznacza „czerwony”, od koloru ziemi, z której <a href=\"https://pl.wikipedia.org/wiki/Adam_i_Ewa\" target=\"_blank\" rel=\"noopener noreferrer\">Adam</a> był ulepiony. Bardziej jednak prawdopodobne, że <i>Adam</i> wywodzi się od hebrajskiego słowa <i>adamah</i>, które oznacza „ziemię, rolę”, wtedy znaczyłoby „rolnik”, albo „że człowiek, z ziemi powstały, do ziemi wróci”. W takim ujęciu, używane jest zazwyczaj w <a href=\"https://pl.wikipedia.org/wiki/Stary_Testament\" target=\"_blank\" rel=\"noopener noreferrer\">Starym Testamencie</a>, chociaż w początkowych rozdziałach Starego Testamentu przyjęło się traktować je jako imię własne. Także w <a href=\"https://pl.wikipedia.org/wiki/J%C4%99zyki_a%C5%82tajskie\" target=\"_blank\" rel=\"noopener noreferrer\">językach ałtajskich</a> słowo <i>adam</i> oznacza „człowiek”. Współcześnie dopatruje się pochodzenia imienia w <a href=\"https://pl.wikipedia.org/wiki/J%C4%99zyk_sumeryjski\" target=\"_blank\" rel=\"noopener noreferrer\">języku sumeryjskim</a>, w którym miał oznaczać „mój ojciec” (od <i>ada.mu</i>), <a href=\"https://pl.wikipedia.org/wiki/J%C4%99zyk_akadyjski\" target=\"_blank\" rel=\"noopener noreferrer\">akadyjskim</a> „zbudowany”, lub „zrodzony”', a także w <a href=\"https://pl.wikipedia.org/wiki/J%C4%99zyk_arabski\" target=\"_blank\" rel=\"noopener noreferrer\">arabskim</a> „łączyć się” (od <i>adama</i>).", "Asteriusz": "<b>Asteriusz</b> – <a href=\"https://pl.wikipedia.org/wiki/Imi%C4%99\" target=\"_blank\" rel=\"noopener noreferrer\">imię</a> męskie pochodzenia <a href=\"https://pl.wikipedia.org/wiki/J%C4%99zyk_grecki\" target=\"_blank\" rel=\"noopener noreferrer\">greckiego</a> od <a href=\"https://pl.wikipedia.org/wiki/J%C4%99zyk_grecki\" target=\"_blank\" rel=\"noopener noreferrer\">gr.</a>&#160;Αστέριος: <a href=\"https://pl.wikipedia.org/wiki/J%C4%99zyk_grecki_klasyczny\" target=\"_blank\" rel=\"noopener noreferrer\">stgr.</a>&#160;ἀστήρ – „gwiazda”. Stąd ἀστέριος to „gwiaździsty, jasny, lśniący, niebieski”. <a href=\"https://pl.wikipedia.org/wiki/Hagiografia\" target=\"_blank\" rel=\"noopener noreferrer\">Hagiografia</a> zna ośmiu świętych o tym imieniu: m.in. nosił je Asteriusz z <a href=\"https://pl.wikipedia.org/wiki/Cezarea_Nadmorska\" target=\"_blank\" rel=\"noopener noreferrer\">Cezarei Palestyńskiej</a>, żyjący w pierwszej połowie <a href=\"https://pl.wikipedia.org/wiki/III_wiek\" target=\"_blank\" rel=\"noopener noreferrer\">III</a> wieku.", "Alibi": "<b>Alibi</b> (<a href=\"https://pl.wikipedia.org/wiki/%C5%81acina\" target=\"_blank\" rel=\"noopener noreferrer\">łac.</a> <i>gdzie indziej</i>) – <a href=\"https://pl.wikipedia.org/wiki/Dow%C3%B3d_(prawo)\" target=\"_blank\" rel=\"noopener noreferrer\">dowód</a> w <a href=\"https://pl.wikipedia.org/wiki/Post%C4%99powanie_karne\" target=\"_blank\" rel=\"noopener noreferrer\">postępowaniu karnym</a> na okoliczność, że <a href=\"https://pl.wikipedia.org/wiki/Podejrzany\" target=\"_blank\" rel=\"noopener noreferrer\">podejrzany</a> albo oskarżony znajdował się w miejscu innym niż miejsce popełnienia zarzucanego mu <a href=\"https://pl.wikipedia.org/wiki/Przest%C4%99pstwo\" target=\"_blank\" rel=\"noopener noreferrer\">przestępstwa</a>. W szerszym znaczeniu mianem alibi określany jest każdy dowód przesądzający, że podejrzany lub oskarżony nie mógł popełnić zarzuconego mu przestępstwa.", "Atom": "Słowo <i>atom</i> pochodzi z <a href=\"https://pl.wikipedia.org/wiki/J%C4%99zyk_grecki\" target=\"_blank\" rel=\"noopener noreferrer\">greckiego</a> ἄτομος – <i>átomos</i> (od α-, „nie-” + τέμνω – <i>temno</i>, „ciąć”), oznaczającego coś, czego nie da się przeciąć ani podzielić. Idea istnienia niepodzielnych składników materii pojawiła się już w pismach starożytnych <a href=\"https://pl.wikipedia.org/wiki/Filozofia_indyjska\" target=\"_blank\" rel=\"noopener noreferrer\">filozofów indyjskich</a> i <a href=\"https://pl.wikipedia.org/wiki/Filozofia_staro%C5%BCytna\" target=\"_blank\" rel=\"noopener noreferrer\">greckich</a>. W XVII i XVIII wieku chemicy potwierdzili te przypuszczenia, identyfikując pierwiastki chemiczne i pokazując, że reagują one ze sobą w ściśle określonych proporcjach. W XIX wieku odkryto <a href=\"https://pl.wikipedia.org/wiki/Ruchy_Browna\" target=\"_blank\" rel=\"noopener noreferrer\">ruchy Browna</a>, będące pośrednim dowodem ziarnistości materii. Na początku XX wieku fizycy zbadali wewnętrzną strukturę atomów, pokazując tym samym, że są one podzielne. Teorie <a href=\"https://pl.wikipedia.org/wiki/Mechanika_kwantowa\" target=\"_blank\" rel=\"noopener noreferrer\">mechaniki kwantowej</a> pozwoliły stworzyć matematyczne modele wnętrza atomu.", "Ada": "<b>Ada</b> – <a href=\"https://pl.wikipedia.org/wiki/Imi%C4%99\" target=\"_blank\" rel=\"noopener noreferrer\">imię</a> <a href=\"https://pl.wikipedia.org/wiki/Kobieta\" target=\"_blank\" rel=\"noopener noreferrer\">żeńskie</a> pochodzenia <a href=\"https://pl.wikipedia.org/wiki/Ludy_semickie\" target=\"_blank\" rel=\"noopener noreferrer\">semickiego</a>. W <a href=\"https://pl.wikipedia.org/wiki/J%C4%99zyk_hebrajski\" target=\"_blank\" rel=\"noopener noreferrer\">języku hebrajskim</a> znaczy: upiększać się, stroić się. Imię Ada jest wymieniane w <a href=\"https://pl.wikipedia.org/wiki/Biblia\" target=\"_blank\" rel=\"noopener noreferrer\">Biblii</a> w pierwszej księdze <a href=\"https://pl.wikipedia.org/wiki/Stary_Testament\" target=\"_blank\" rel=\"noopener noreferrer\">Starego Testamentu</a>, gdzie jest jedną z żon Lemecha i matką Jubala. W Biblii jest także mowa o Adzie, matce flecistów i grających na harfie (<a href=\"https://pl.wikipedia.org/wiki/Ksi%C4%99ga_Rodzaju\" target=\"_blank\" rel=\"noopener noreferrer\">Rdz.</a> 4, 21).", "Ang": "W Wielkiej Brytanii i Australii angielski jest <i>de facto</i> <a href=\"https://pl.wikipedia.org/wiki/J%C4%99zyk_urz%C4%99dowy\" target=\"_blank\" rel=\"noopener noreferrer\">językiem urzędowym</a>, choć formalnie państwa te nie objęły takim statusem żadnego języka. Angielszczyzna należy do oficjalnych języków <a href=\"https://pl.wikipedia.org/wiki/Organizacja_Narod%C3%B3w_Zjednoczonych\" target=\"_blank\" rel=\"noopener noreferrer\">ONZ</a>, a od XX wieku jest najczęściej używanym językiem w kontaktach międzynarodowych. Bywa określana jako pierwszy uniwersalny nowożytny język ludzkości. Stanowi główny język nauki, handlu i polityki, a w niektórych krajach także kształcenia wyższego.", "Agnar": "A także jedyny syn Geirröda noszący imię zaginionego na morzu <a href=\"https://pl.wikipedia.org/wiki/Stryj_(relacja_rodzinna)\" target=\"_blank\" rel=\"noopener noreferrer\">stryja</a> (może jego drugie wcielenie). Jako dziesięcioletni chłopiec był świadkiem tortur, na które ojciec skazał swego gościa Grimnira (\"Zakapturzonego\", tj. <a href=\"https://pl.wikipedia.org/wiki/Odyn\" target=\"_blank\" rel=\"noopener noreferrer\">Odyna</a>, który jak zwykle ukrywał się pod przybraną postacią). Dziecko tknięte współczuciem pokrzepiło nieszczęśnika rogiem pełnym jakiegoś napoju (prawd. miodu). Wówczas <a href=\"https://pl.wikipedia.org/wiki/Odyn\" target=\"_blank\" rel=\"noopener noreferrer\">Odyn</a> wyśpiewał chłopcu błogosławieństwo i przepowiedział mu panowanie, następnie opisał świat bogów i wyliczył swoje imiona, a w końcu rzucił na Geirröda klątwę śmierci, która natychmiast się spełniła. Agnar przejął po ojcu władzę i rządził wiele lat, choć o jego rządach nic nie wiadomo.", "Agnes": "<b>Agnieszka</b> – imię żeńskie, jedno z najpopularniejszych w Polsce, gdzie pojawiło się wraz z chrześcijaństwem. Pochodzi od <a href=\"https://pl.wikipedia.org/wiki/J%C4%99zyk_grecki\" target=\"_blank\" rel=\"noopener noreferrer\">gr.</a>&#160;Αγνή – „czysta”, „dziewicza”, „nieskalana”. Może również pochodzić od <a href=\"https://pl.wikipedia.org/wiki/%C5%81acina\" target=\"_blank\" rel=\"noopener noreferrer\">łac.</a>&#160;<em>agnus</em> – „baranek” (to jednocześnie rodzaj męski greckiej „h-agne”). Do Czech imię to dotarło w formie <a href=\"https://pl.wikipedia.org/wiki/%C5%81acina\" target=\"_blank\" rel=\"noopener noreferrer\">łac.</a>&#160;<em>Agnes</em>, następnie zostało zaadaptowane do języka polskiego w obecnej formie. Imię to funkcjonuje również w języku polskim w formie Inka, początkowo było ono polskim zdrobnieniem imienia Inez — francusko-iberyjskiej formy imienia Agnieszka (Inês, Inés, Inès) — z czasem jednak zaczęło funkcjonować w Polsce jako samodzielne imię.", "Addar": "<b>Addar</b> – <a href=\"https://pl.wikipedia.org/wiki/Imi%C4%99\" target=\"_blank\" rel=\"noopener noreferrer\">imię</a> męskie pochodzenia <a href=\"https://pl.wikipedia.org/wiki/Biblia\" target=\"_blank\" rel=\"noopener noreferrer\">biblijnego</a>. Wywodzi się od słowa oznaczającego „wspaniały”.", "Abigail": "<b>Abigail</b>, <b>Abigajl</b> – <a href=\"https://pl.wikipedia.org/wiki/Imi%C4%99\" target=\"_blank\" rel=\"noopener noreferrer\">imię</a> żeńskie pochodzenia <a href=\"https://pl.wikipedia.org/wiki/Biblia\" target=\"_blank\" rel=\"noopener noreferrer\">biblijnego</a>. Wywodzi się od hebrajskiego imienia אביגיל <i>Awigajil</i> znaczącego „radość ojca”, „mój ojciec się uradował”.", "Alicja": "Może pochodzić od włoskiej, żeńskiej formy imienia <a href=\"https://pl.wikipedia.org/wiki/Aleksy\" target=\"_blank\" rel=\"noopener noreferrer\">Aleksy</a> – Alessis, imię to przyjmowało w językach: <a href=\"https://pl.wikipedia.org/wiki/J%C4%99zyk_niemiecki\" target=\"_blank\" rel=\"noopener noreferrer\">niemieckim</a> i <a href=\"https://pl.wikipedia.org/wiki/J%C4%99zyk_angielski\" target=\"_blank\" rel=\"noopener noreferrer\">angielskim</a> formę Alexia.", "Ameliusz": "<b>Ameliusz</b> - (właściwe imię Gentilianus) urodzony w <a href=\"https://pl.wikipedia.org/wiki/Etruria\" target=\"_blank\" rel=\"noopener noreferrer\">Etrurii</a>, żyjący w III w. n.e. filozof <a href=\"https://pl.wikipedia.org/wiki/Neoplatonizm\" target=\"_blank\" rel=\"noopener noreferrer\">neoplatoński</a> ze szkoły rzymskiej, uznawany za najbardziej oddanego ucznia <a href=\"https://pl.wikipedia.org/wiki/Plotyn\" target=\"_blank\" rel=\"noopener noreferrer\">Plotyna</a>.", "Arnulf": "<b>Arnulf</b>, <b>Arnolf</b> – <a href=\"https://pl.wikipedia.org/wiki/Imi%C4%99\" target=\"_blank\" rel=\"noopener noreferrer\">imię</a> męskie pochodzenia <a href=\"https://pl.wikipedia.org/wiki/J%C4%99zyki_germa%C5%84skie\" target=\"_blank\" rel=\"noopener noreferrer\">germańskiego</a>. Pierwszy człon imienia stanowi <i>arn</i> – <a href=\"https://pl.wikipedia.org/wiki/J%C4%99zyk_staro-wysoko-niemiecki\" target=\"_blank\" rel=\"noopener noreferrer\">staro-wysoko-niemiecki (stwniem.)</a>-frankoński, średnio-dolno-niemiecki (śrdniem.) <i>arn</i> („<a href=\"https://pl.wikipedia.org/wiki/Or%C5%82y\" target=\"_blank\" rel=\"noopener noreferrer\">orzeł</a>”); drugim członem jest <i>wolf</i> – <a href=\"https://pl.wikipedia.org/wiki/J%C4%99zyki_germa%C5%84skie\" target=\"_blank\" rel=\"noopener noreferrer\">germ.</a> <i>wulfa &gt; wolfa</i> („<a href=\"https://pl.wikipedia.org/wiki/Wilk_w_kulturze\" target=\"_blank\" rel=\"noopener noreferrer\">wilk</a>”); stwniem. <i>wolf</i>. Formy z <i>-ulf</i> są odbiciem zromanizowanego germ. <i>-wulf</i>. Wariantami drugiego członu są: <i>-wulf</i>, który stanowi kontynuację najstarszej, germańskiej formy, zachowanej w śrdniem. i <a href=\"https://pl.wikipedia.org/wiki/J%C4%99zyk_dolnoniemiecki\" target=\"_blank\" rel=\"noopener noreferrer\">dolnoniemiecki (dniem.)</a>, oraz <i>-wolf</i>, kontynuacja młodszej formy germańskiej, przejętej przez stwniem., <a href=\"https://pl.wikipedia.org/wiki/J%C4%99zyk_%C5%9Brednio-wysoko-niemiecki\" target=\"_blank\" rel=\"noopener noreferrer\">średnio-wysoko-niemiecki (śrwniem.)</a> i nowoniemiecki. Imię to notowane było w Polsce już w średniowieczu, w formie (Arnolf) (<a href=\"https://pl.wikipedia.org/wiki/1219\" target=\"_blank\" rel=\"noopener noreferrer\">1219</a>), Arnolfus (Arnulf) (<a href=\"https://pl.wikipedia.org/wiki/1435\" target=\"_blank\" rel=\"noopener noreferrer\">1435</a>). Niektóre możliwe staropolskie zdrobnienia: Arnek, Arnko.", "Agis": "<b>Agis</b> – <a href=\"https://pl.wikipedia.org/wiki/Imi%C4%99\" target=\"_blank\" rel=\"noopener noreferrer\">imię</a> męskie pochodzenia <a href=\"https://pl.wikipedia.org/wiki/Greka\" target=\"_blank\" rel=\"noopener noreferrer\">greckiego</a> (gr. <i>Άγις</i>), które zostało utworzone od czasownika <i>Άγω</i> („prowadzić, przodować, wskazywać drogę”). Imię to oznacza „ten, kto prowadzi”; „ten, kto wskazuje drogę”.", "Afanazy": "<b>Atanazy</b> – <a href=\"https://pl.wikipedia.org/wiki/Imi%C4%99\" target=\"_blank\" rel=\"noopener noreferrer\">imię</a> męskie pochodzenia <a href=\"https://pl.wikipedia.org/wiki/J%C4%99zyk_grecki\" target=\"_blank\" rel=\"noopener noreferrer\">greckiego</a>. Wywodzi się od słowa oznaczającego „nieśmiertelny” (<a href=\"https://pl.wikipedia.org/wiki/J%C4%99zyk_grecki\" target=\"_blank\" rel=\"noopener noreferrer\">gr.</a>&#160;Αθανάσιος).", "Awit": "<b>Awit</b> – <a href=\"https://pl.wikipedia.org/wiki/Imi%C4%99\" target=\"_blank\" rel=\"noopener noreferrer\">imię</a> męskie pochodzenia <a href=\"https://pl.wikipedia.org/wiki/%C5%81acina\" target=\"_blank\" rel=\"noopener noreferrer\">łacińskiego</a>, pochodzące od łacińskiego przymiotnika pospolitego <i>avitus</i>, który oznaczał „pochodzący od przodków, wrodzony, dziedziczny”. Istniało 8 świętych o tym imieniu. W Polsce <b>Awit</b> nadawany jest co najmniej od <a href=\"https://pl.wikipedia.org/wiki/1777\" target=\"_blank\" rel=\"noopener noreferrer\">1777</a> roku.", "Akihito": "<b>Akihito</b>&#32;(<a href=\"https://pl.wikipedia.org/wiki/J%C4%99zyk_japo%C5%84ski\" target=\"_blank\" rel=\"noopener noreferrer\">jap.</a>&#32;あきひと, アキヒト) – <a href=\"https://pl.wikipedia.org/wiki/Imiona_japo%C5%84skie\" target=\"_blank\" rel=\"noopener noreferrer\">japońskie imię</a> męskie.", "Amparo": "<b>Amparo</b> – <a href=\"https://pl.wikipedia.org/wiki/Imi%C4%99\" target=\"_blank\" rel=\"noopener noreferrer\">imię</a> <a href=\"https://pl.wikipedia.org/wiki/Kobieta\" target=\"_blank\" rel=\"noopener noreferrer\">żeńskie</a> pochodzące z <a href=\"https://pl.wikipedia.org/wiki/%C5%81acina\" target=\"_blank\" rel=\"noopener noreferrer\">łaciny</a> w jej hiszpańskim <a href=\"https://pl.wikipedia.org/wiki/Idiom\" target=\"_blank\" rel=\"noopener noreferrer\">wariancie</a>. Popularne w <a href=\"https://pl.wikipedia.org/wiki/Hiszpania\" target=\"_blank\" rel=\"noopener noreferrer\">Hiszpanii</a> i <a href=\"https://pl.wikipedia.org/wiki/Portugalia\" target=\"_blank\" rel=\"noopener noreferrer\">Portugalii</a> i w kręgu oddziaływania kultury hiszpańskiej i portugalskiej. Dosłownie oznacza <i>\"ochronę, protekcję\"</i>. Brak odpowiednika tego imienia w języku polskim.", "Amram": "<b>Amram</b> (<a href=\"https://pl.wikipedia.org/wiki/J%C4%99zyk_hebrajski\" target=\"_blank\" rel=\"noopener noreferrer\">hebr.</a> עַמְרָם) – postać biblijna ze <a href=\"https://pl.wikipedia.org/wiki/Stary_Testament\" target=\"_blank\" rel=\"noopener noreferrer\">Starego Testamentu</a>, syn <a href=\"https://pl.wikipedia.org/wiki/Kehat\" target=\"_blank\" rel=\"noopener noreferrer\">Kehata</a>, ojciec <a href=\"https://pl.wikipedia.org/wiki/Moj%C5%BCesz\" target=\"_blank\" rel=\"noopener noreferrer\">Mojżesza</a>, <a href=\"https://pl.wikipedia.org/wiki/Aaron_(posta%C4%87_biblijna)\" target=\"_blank\" rel=\"noopener noreferrer\">Aarona</a> i <a href=\"https://pl.wikipedia.org/wiki/Miriam_(posta%C4%87_biblijna)\" target=\"_blank\" rel=\"noopener noreferrer\">Miriam</a>. Jego żoną była <a href=\"https://pl.wikipedia.org/wiki/Jokebed\" target=\"_blank\" rel=\"noopener noreferrer\">Jokebed</a>. Żył 137 lat. Od Amrama pochodzi ród Amramitów.", "Amber": "<b>Amber</b> – imię kobiece, pochodzi od nazwy bursztynu (skamieniałej żywicy drzewa, który jest często używany do produkcji biżuterii). Słowo to pochodzi od arabskiego عنبر lub Anbar. Słowo to może również odnosić się do koloru żółto-pomarańczowego.", "Antonina": "<b>Antonina</b> – <a href=\"https://pl.wikipedia.org/wiki/Imi%C4%99\" target=\"_blank\" rel=\"noopener noreferrer\">imię</a> żeńskie; żeński odpowiednik imienia <a href=\"https://pl.wikipedia.org/wiki/Antonin_(imi%C4%99)\" target=\"_blank\" rel=\"noopener noreferrer\">Antonin</a>; uformowany przy użyciu <a href=\"https://pl.wikipedia.org/wiki/Przyrostek\" target=\"_blank\" rel=\"noopener noreferrer\">przyrostka</a> <i>-inus</i>, <i>-ina</i>, oznaczającego przynależność lub pochodzenie, <a href=\"https://pl.wikipedia.org/wiki/Nazwisko#Przydomek_(cognomen)\" target=\"_blank\" rel=\"noopener noreferrer\">przydomek</a> od <a href=\"https://pl.wikipedia.org/wiki/Nazwisko#Nazwisko\" target=\"_blank\" rel=\"noopener noreferrer\">nazwy rodowej</a> <a href=\"https://pl.wikipedia.org/wiki/Drzewo_genealogiczne_Antoniusz%C3%B3w\" target=\"_blank\" rel=\"noopener noreferrer\">rodu Antoniuszów</a>. W Polsce Antonina pojawiła się później niż obecna od średniowiecza <a href=\"https://pl.wikipedia.org/wiki/Antonia_(imi%C4%99)\" target=\"_blank\" rel=\"noopener noreferrer\">Antonia</a>; notowana jest co najmniej od <a href=\"https://pl.wikipedia.org/wiki/1637\" target=\"_blank\" rel=\"noopener noreferrer\">1637</a> roku. Wśród imion nadawanych nowo narodzonym dzieciom, Antonina w 2017 r. zajmowała 15. miejsce w grupie imion żeńskich. W całej populacji Polek Antonina zajmowała w 2017 r. 90. miejsce (43 462 nadań).", "Aleksandra": "<b>Aleksandra</b> (<a href=\"https://pl.wikipedia.org/wiki/Mi%C4%99dzynarodowy_alfabet_fonetyczny\" target=\"_blank\" rel=\"noopener noreferrer\">IPA</a>: [<a href=\"https://pl.wikipedia.org/wiki/Akcent_wyrazowy\" target=\"_blank\" rel=\"noopener noreferrer\">ˌ</a><a href=\"https://pl.wikipedia.org/wiki/Samog%C5%82oska_otwarta_przednia_niezaokr%C4%85glona\" target=\"_blank\" rel=\"noopener noreferrer\">a</a><a href=\"https://pl.wikipedia.org/wiki/Sp%C3%B3%C5%82g%C5%82oska_boczna_dzi%C4%85s%C5%82owa_d%C5%BAwi%C4%99czna\" target=\"_blank\" rel=\"noopener noreferrer\">l</a><a href=\"https://pl.wikipedia.org/wiki/Samog%C5%82oska_p%C3%B3%C5%82otwarta_przednia_niezaokr%C4%85glona\" target=\"_blank\" rel=\"noopener noreferrer\">ɛ</a><a href=\"https://pl.wikipedia.org/wiki/Akcent_wyrazowy\" target=\"_blank\" rel=\"noopener noreferrer\">ˈ</a><a href=\"https://pl.wikipedia.org/wiki/Sp%C3%B3%C5%82g%C5%82oska_zwarta_mi%C4%99kkopodniebienna_bezd%C5%BAwi%C4%99czna\" target=\"_blank\" rel=\"noopener noreferrer\">k</a><a href=\"https://pl.wikipedia.org/wiki/Sp%C3%B3%C5%82g%C5%82oska_szczelinowa_dzi%C4%85s%C5%82owa_bezd%C5%BAwi%C4%99czna\" target=\"_blank\" rel=\"noopener noreferrer\">s</a><a href=\"https://pl.wikipedia.org/wiki/Mi%C4%99dzynarodowy_alfabet_fonetyczny\" target=\"_blank\" rel=\"noopener noreferrer\">ã</a><a href=\"https://pl.wikipedia.org/wiki/Sp%C3%B3%C5%82g%C5%82oska_nosowa_dzi%C4%85s%C5%82owa_d%C5%BAwi%C4%99czna\" target=\"_blank\" rel=\"noopener noreferrer\">n</a><a href=\"https://pl.wikipedia.org/wiki/Sp%C3%B3%C5%82g%C5%82oska_zwarta_dzi%C4%85s%C5%82owa_d%C5%BAwi%C4%99czna\" target=\"_blank\" rel=\"noopener noreferrer\">d</a><a href=\"https://pl.wikipedia.org/wiki/Sp%C3%B3%C5%82g%C5%82oska_dr%C5%BC%C4%85ca_dzi%C4%85s%C5%82owa_d%C5%BAwi%C4%99czna\" target=\"_blank\" rel=\"noopener noreferrer\">r</a><a href=\"https://pl.wikipedia.org/wiki/Samog%C5%82oska_otwarta_przednia_niezaokr%C4%85glona\" target=\"_blank\" rel=\"noopener noreferrer\">a</a>], <a href=\"https://pl.wikipedia.org/wiki/J%C4%99zyk_grecki\" target=\"_blank\" rel=\"noopener noreferrer\">gr.</a>&#160;Ἀλεξάνδρα) – żeński odpowiednik <a href=\"https://pl.wikipedia.org/wiki/J%C4%99zyk_grecki\" target=\"_blank\" rel=\"noopener noreferrer\">greckiego</a> imienia <a href=\"https://pl.wikipedia.org/wiki/Aleksander\" target=\"_blank\" rel=\"noopener noreferrer\">Aleksander</a> (Ἀλέξανδρος – obrońca ludzi). Imię Aleksandra w Polsce weszło w użycie w XIV wieku, a spopularyzował je m.in. <a href=\"https://pl.wikipedia.org/wiki/Henryk_Sienkiewicz\" target=\"_blank\" rel=\"noopener noreferrer\">Henryk Sienkiewicz</a>, nadając to imię <a href=\"https://pl.wikipedia.org/wiki/Aleksandra_Billewicz%C3%B3wna\" target=\"_blank\" rel=\"noopener noreferrer\">bohaterce</a> <i><a href=\"https://pl.wikipedia.org/wiki/Potop_(powie%C5%9B%C4%87)\" target=\"_blank\" rel=\"noopener noreferrer\">Potopu</a></i>.", "Achacjusz": "<b>Achacy</b> – <a href=\"https://pl.wikipedia.org/wiki/Imi%C4%99\" target=\"_blank\" rel=\"noopener noreferrer\">imię</a> męskie najprawdopodobniej pochodzenia <a href=\"https://pl.wikipedia.org/wiki/J%C4%99zyk_grecki\" target=\"_blank\" rel=\"noopener noreferrer\">greckiego</a>. W takim przypadku pochodzi ono od wyrazu <i>achátēs</i> – „<a href=\"https://pl.wikipedia.org/wiki/Agat\" target=\"_blank\" rel=\"noopener noreferrer\">agat</a>”. Może również pochodzić od greckiego imienia Ἀκακίος <i>Akakios</i> (od ἀκακός <i>akakos</i> – „niewinny”, „nieznający zła”), albo od greckiego wyrazu ἀγαθός <i>agathos</i> – „dobry”. Jego żeńskim odpowiednikiem są <a href=\"https://pl.wikipedia.org/wiki/Achacja\" target=\"_blank\" rel=\"noopener noreferrer\">Achacja</a> i Akacja.", "Adonai": "W 2008 roku <a href=\"https://pl.wikipedia.org/wiki/Kongregacja_ds._Kultu_Bo%C5%BCego_i_Dyscypliny_Sakrament%C3%B3w\" target=\"_blank\" rel=\"noopener noreferrer\">Kongregacja ds. Kultu Bożego i Dyscypliny Sakramentów</a> <a href=\"https://pl.wikipedia.org/wiki/Ko%C5%9Bci%C3%B3%C5%82_katolicki\" target=\"_blank\" rel=\"noopener noreferrer\">Kościoła katolickiego</a> wydała dyrektywę, która zawierała zalecenie, by w obrzędach liturgicznych unikać stosowanego dotąd biblijnego imienia <i>Jahwe</i>, zastępując je odpowiednikiem <i>Adonai</i>, w znaczeniu „Pan”. Zalecenie to wydano, by zgodnie z hebrajską tradycją imię Boga pozostawało niewypowiedziane.", "Ambrogio": "<b>Ambroży</b> (<a href=\"https://pl.wikipedia.org/wiki/J%C4%99zyk_grecki\" target=\"_blank\" rel=\"noopener noreferrer\">gr.</a> <i>ambrósios</i> – boski, nieśmiertelny, święty od <i>(am)brotós</i> – (nie)śmiertelny) – <a href=\"https://pl.wikipedia.org/wiki/Imi%C4%99\" target=\"_blank\" rel=\"noopener noreferrer\">imię</a> męskie pochodzenia <a href=\"https://pl.wikipedia.org/wiki/J%C4%99zyk_grecki\" target=\"_blank\" rel=\"noopener noreferrer\">greckiego</a>.", "Aster": "Nazwa rodzajowa <i>Aster</i> pochodzi od starogreckiego słowa ἀστέρı (astéri), co znaczy „gwiazda”. Nawiązuje ona do gwiaździstego kształtu <a href=\"https://pl.wikipedia.org/wiki/Koszyczek\" target=\"_blank\" rel=\"noopener noreferrer\">koszyczka</a> kwiatowego.", "Arca": "<i><b>Arca</b></i> – <a href=\"https://pl.wikipedia.org/wiki/Rodzaj_(biologia)\" target=\"_blank\" rel=\"noopener noreferrer\">rodzaj</a> <a href=\"https://pl.wikipedia.org/wiki/Ma%C5%82%C5%BCe\" target=\"_blank\" rel=\"noopener noreferrer\">małży</a> <a href=\"https://pl.wikipedia.org/wiki/Nitkoskrzelne\" target=\"_blank\" rel=\"noopener noreferrer\">nitkoskrzelnych</a> z rodziny <a href=\"https://pl.wikipedia.org/wiki/Arkowate\" target=\"_blank\" rel=\"noopener noreferrer\">arkowatych</a> (Arcidae) opisany naukowo przez <a href=\"https://pl.wikipedia.org/wiki/Karol_Linneusz\" target=\"_blank\" rel=\"noopener noreferrer\">Linneusza</a> w 1758 roku. <a href=\"https://pl.wikipedia.org/wiki/Gatunek_typowy\" target=\"_blank\" rel=\"noopener noreferrer\">Gatunkiem typowym</a> jest <i><a href=\"https://pl.wikipedia.org/wiki/Arca_noae\" target=\"_blank\" rel=\"noopener noreferrer\">Arca noae</a></i> (arka Noego). <a href=\"https://pl.wikipedia.org/wiki/Grupa_siostrzana\" target=\"_blank\" rel=\"noopener noreferrer\">Taksonem siostrzanym</a> jest <i>Acar</i>. W zapisie kopalnym najstarsi przedstawiciele tego rodzaju są znani ze skamielin pochodzących z <a href=\"https://pl.wikipedia.org/wiki/Kreda_(okres)\" target=\"_blank\" rel=\"noopener noreferrer\">kredy</a>. Współcześnie żyjące gatunki występują w wodach strefy tropikalnej i subtropikalnej. Większe gatunki zaliczane są do <a href=\"https://pl.wikipedia.org/wiki/Owoce_morza\" target=\"_blank\" rel=\"noopener noreferrer\">owoców morza</a> i poławiane komercyjnie. Do gatunków najczęściej poławianych i wykorzystywanych kulinarnie należy <a href=\"https://pl.wikipedia.org/wiki/Arka_Noego_(zwierz%C4%99ta)\" target=\"_blank\" rel=\"noopener noreferrer\">arka Noego</a>.", "Anita": "<b>Anita</b> – <a href=\"https://pl.wikipedia.org/wiki/Imi%C4%99\" target=\"_blank\" rel=\"noopener noreferrer\">imię</a> żeńskie, które powstało z hiszpańskiej zdrobniałej formy imienia <a href=\"https://pl.wikipedia.org/wiki/Anna\" target=\"_blank\" rel=\"noopener noreferrer\">Anna</a> (<a href=\"https://pl.wikipedia.org/wiki/J%C4%99zyk_hiszpa%C5%84ski\" target=\"_blank\" rel=\"noopener noreferrer\">hiszp.</a> Ana). Istnieje też teza, że <b>Anita</b> jest skróconą formą <i>Juanity</i> – hiszpańskiego odpowiednika <a href=\"https://pl.wikipedia.org/wiki/Joanna\" target=\"_blank\" rel=\"noopener noreferrer\">Joanny</a>.", "Alwar": "<b>Alwar</b> – <a href=\"https://pl.wikipedia.org/wiki/Imi%C4%99\" target=\"_blank\" rel=\"noopener noreferrer\">imię</a> męskie pochodzenia <a href=\"https://pl.wikipedia.org/wiki/J%C4%99zyki_germa%C5%84skie\" target=\"_blank\" rel=\"noopener noreferrer\">germańskiego</a>, oznaczające „strażnik wszystkiego/wszystkich”.", "Abiel": "<b>Abiel</b> – <a href=\"https://pl.wikipedia.org/wiki/Imi%C4%99\" target=\"_blank\" rel=\"noopener noreferrer\">imię</a> dwóch postaci biblijnych oznaczające w <a href=\"https://pl.wikipedia.org/wiki/J%C4%99zyk_hebrajski\" target=\"_blank\" rel=\"noopener noreferrer\">języku hebrajskim</a> „Bóg jest moim ojcem”. 1. Imię to nosił ojciec <a href=\"https://pl.wikipedia.org/wiki/Kisz_(posta%C4%87_biblijna)\" target=\"_blank\" rel=\"noopener noreferrer\">Kisza</a>, dziadek <a href=\"https://pl.wikipedia.org/wiki/Saul_(kr%C3%B3l_Izraela)\" target=\"_blank\" rel=\"noopener noreferrer\">Saula</a> (1 Sm 9,1) i <a href=\"https://pl.wikipedia.org/wiki/Abner\" target=\"_blank\" rel=\"noopener noreferrer\">Abnera</a> (1Sm 14,51). 2. Imię to nosił również jeden z bohaterskich wojowników <a href=\"https://pl.wikipedia.org/wiki/Dawid_(kr%C3%B3l_Izraela)\" target=\"_blank\" rel=\"noopener noreferrer\">Dawida</a> (1 Krn 11,32).", "Ardalion": "<b>Ardalion</b> – <a href=\"https://pl.wikipedia.org/wiki/Imi%C4%99\" target=\"_blank\" rel=\"noopener noreferrer\">imię</a> męskie, prawdopodobnie pochodzące od <a href=\"https://pl.wikipedia.org/wiki/%C5%81acina\" target=\"_blank\" rel=\"noopener noreferrer\">łac.</a> <i>ardalio</i> — \"skrzętny, krzątający się\". Jego patronem jest św. Ardalion, komediant.", "Akinori": "<b>Akinori</b>&#32;(<a href=\"https://pl.wikipedia.org/wiki/J%C4%99zyk_japo%C5%84ski\" target=\"_blank\" rel=\"noopener noreferrer\">jap.</a>&#32;あきのり, アキノリ) – męskie <a href=\"https://pl.wikipedia.org/wiki/Imiona_japo%C5%84skie\" target=\"_blank\" rel=\"noopener noreferrer\">imię japońskie</a>.", "Archip": "<b>Archip</b> – <a href=\"https://pl.wikipedia.org/wiki/Imi%C4%99\" target=\"_blank\" rel=\"noopener noreferrer\">imię</a> męskie <a href=\"https://pl.wikipedia.org/wiki/Etymologia\" target=\"_blank\" rel=\"noopener noreferrer\">pochodzenia</a> <a href=\"https://pl.wikipedia.org/wiki/J%C4%99zyk_grecki\" target=\"_blank\" rel=\"noopener noreferrer\">greckiego</a>, złożone z członów: <i>αρχος (archos)</i>, oznaczającego \"mistrz\" oraz <i>‘ιππος (híppos)</i> – „koń”.", "Adair": "<b>Adair</b> – zarówno żeńskie, jak i męskie <a href=\"https://pl.wikipedia.org/wiki/Imi%C4%99\" target=\"_blank\" rel=\"noopener noreferrer\">imię</a> pochodzenia germańskiego oznaczające „bogatą włócznię”. Występuje też w wariantach Adaire, Adare i Adayre. Obecnie imię to nie jest popularne.", "Arystarch": "<b>Arystarch</b> – <a href=\"https://pl.wikipedia.org/wiki/Imi%C4%99\" target=\"_blank\" rel=\"noopener noreferrer\">imię</a> męskie pochodzenia <a href=\"https://pl.wikipedia.org/wiki/J%C4%99zyk_grecki\" target=\"_blank\" rel=\"noopener noreferrer\">greckiego</a> oznaczające tyle co <i>najlepszy władca</i>.", "Arata": "<b>Arata</b>&#32;(<a href=\"https://pl.wikipedia.org/wiki/J%C4%99zyk_japo%C5%84ski\" target=\"_blank\" rel=\"noopener noreferrer\">jap.</a>&#32;あらた, アラタ) – męskie <a href=\"https://pl.wikipedia.org/wiki/Imiona_japo%C5%84skie\" target=\"_blank\" rel=\"noopener noreferrer\">imię japońskie</a>, jest używane także jako nazwisko.", "Azael": "<b>Azazel</b> (<a href=\"https://pl.wikipedia.org/wiki/J%C4%99zyk_hebrajski\" target=\"_blank\" rel=\"noopener noreferrer\">hebr.</a> עזאזל, <a href=\"https://pl.wikipedia.org/wiki/J%C4%99zyk_arabski\" target=\"_blank\" rel=\"noopener noreferrer\">arab.</a> عزازل <i>Azazil</i>) – <a href=\"https://pl.wikipedia.org/wiki/Upad%C5%82y_anio%C5%82\" target=\"_blank\" rel=\"noopener noreferrer\">upadły anioł</a> występujący w mitologii hebrajskiej i muzułmańskiej, znany również pod imionami <b>Azael</b>, <b>Hazazel</b> i <b>Assasello</b>. Jego imię oznacza „Bóg umacnia”, a z hebrajskiego „ten, który się oddalił”.", "Alina": "<b>Alina</b> – <a href=\"https://pl.wikipedia.org/wiki/Imi%C4%99\" target=\"_blank\" rel=\"noopener noreferrer\">imię</a> żeńskie pochodzenia <a href=\"https://pl.wikipedia.org/wiki/J%C4%99zyki_germa%C5%84skie\" target=\"_blank\" rel=\"noopener noreferrer\">germańskiego</a>, powstałe jako forma pochodna od <a href=\"https://pl.wikipedia.org/wiki/Adelajda_(imi%C4%99)\" target=\"_blank\" rel=\"noopener noreferrer\">Adelajda</a>, <a href=\"https://pl.wikipedia.org/wiki/Adelina_(imi%C4%99)\" target=\"_blank\" rel=\"noopener noreferrer\">Adelina</a>. W staropolszczyźnie pisane m.in. <b>Alena</b>, <b>Helina</b>.Imię to może mieć też związek z mianem <a href=\"https://pl.wikipedia.org/wiki/Halina\" target=\"_blank\" rel=\"noopener noreferrer\">Halina</a> – „ładna”, „dostojna”, „spokojna”. Alina to także pierwotna, pruska nazwa rzeki <a href=\"https://pl.wikipedia.org/wiki/%C5%81yna\" target=\"_blank\" rel=\"noopener noreferrer\">Łyny</a>, która w młodszych formach brzmiała Alna (1251 <a href=\"https://pl.wikipedia.org/wiki/Naszej_ery\" target=\"_blank\" rel=\"noopener noreferrer\">n.e.</a>) i Alne (1308). Alina w języku pruskim oznaczała samicę <a href=\"https://pl.wikipedia.org/wiki/Jele%C5%84\" target=\"_blank\" rel=\"noopener noreferrer\">jelenia</a> – łanię. Po <a href=\"https://pl.wikipedia.org/wiki/J%C4%99zyk_litewski\" target=\"_blank\" rel=\"noopener noreferrer\">litewsku</a> słowo <i>elnias</i> oznacza jelenia.", "Aminu": "<b>Aminu</b>, <b>Aminum</b> (<i>Aminu</i>, zapisywane <i>A-mi-nu</i>) – według <i><a href=\"https://pl.wikipedia.org/wiki/Asyryjska_lista_kr%C3%B3l%C3%B3w\" target=\"_blank\" rel=\"noopener noreferrer\">Asyryjskiej listy królów</a></i> 26 król <a href=\"https://pl.wikipedia.org/wiki/Asyria\" target=\"_blank\" rel=\"noopener noreferrer\">Asyrii</a>, syn i następca <a href=\"https://pl.wikipedia.org/wiki/Ilu-kabkabi\" target=\"_blank\" rel=\"noopener noreferrer\">Ilu-kabkabi</a>, a tym samym starszy brat <a href=\"https://pl.wikipedia.org/wiki/Szamszi-Adad_I\" target=\"_blank\" rel=\"noopener noreferrer\">Szamszi-Adada I</a> (1808-1776 p.n.e.). Jego imię jest ostatnim w sekcji „10 królów, których ojcowie są [<i>znani</i>]”. Obecnie wiadomo, iż władcy ci nigdy nie panowali w Asyrii, a umieszczeni zostali w <i>Asyryjskiej liście królów</i> tylko dlatego, iż byli przodkami Szamszi-Adada I, <a href=\"https://pl.wikipedia.org/wiki/Amoryci\" target=\"_blank\" rel=\"noopener noreferrer\">amoryckiego</a> uzurpatora, który przejął kontrolę nad miastem-państwem <a href=\"https://pl.wikipedia.org/wiki/Aszur_(miasto)\" target=\"_blank\" rel=\"noopener noreferrer\">Aszur</a>. Skryba układający <i>Asyryjską listę królów</i> dodatkowo „uczynił” Aminu ojcem <a href=\"https://pl.wikipedia.org/wiki/Sulili\" target=\"_blank\" rel=\"noopener noreferrer\">Sulili</a>, jednego z wczesnych, rodzimych władców Aszur, choć ten panował ok. 200 lat przed Szamszi-Adadem I. Zabiegiem tym skryba ten chciał najprawdopodobniej włączyć amoryckich przodków Szamszi-Adada I do listy władców, którzy poprzedzali go na tronie Aszur.", "Asser": "W 893 Asser napisał biografię Alfreda, zwaną <i>Life of King Alfred</i> (Żywot króla Alfreda). Rękopis przetrwał do czasów nowożytnych w tylko jednej kopii, która była częścią księgozbioru Cottona. Kopia ta uległa zniszczeniu w pożarze w 1731, ale tłumaczenia, które sporządzono wcześniej w połączeniu z fragmentami dzieła Assera, które zostały przytoczone przez innych wczesnych autorów, umożliwiły rekonstrukcję tego dzieła. Biografia ta jest obecnie głównym źródłem informacji o życiu Alfreda i dostarcza o nim o wiele więcej wiadomości niż o jakimkolwiek innym wczesnym władcy angielskim. Asser pomagał także Alfredowi w tłumaczeniu <i>Regula pastoralis</i> (traktatu dotyczącego obowiązków duchowieństwa) <a href=\"https://pl.wikipedia.org/wiki/Papie%C5%BC_Grzegorz_I\" target=\"_blank\" rel=\"noopener noreferrer\">Grzegorza Wielkiego</a> i prawdopodobnie innych dzieł.", "Akihiko": "<b>Akihiko</b>&#32;(<a href=\"https://pl.wikipedia.org/wiki/J%C4%99zyk_japo%C5%84ski\" target=\"_blank\" rel=\"noopener noreferrer\">jap.</a>&#32;あきひこ, アキヒコ) – <a href=\"https://pl.wikipedia.org/wiki/Imiona_japo%C5%84skie\" target=\"_blank\" rel=\"noopener noreferrer\">męskie imię japońskie</a>.", "Agapit": "<b>Agapit</b> – <a href=\"https://pl.wikipedia.org/wiki/Imi%C4%99\" target=\"_blank\" rel=\"noopener noreferrer\">imię</a> męskie pochodzenia <a href=\"https://pl.wikipedia.org/wiki/J%C4%99zyk_grecki\" target=\"_blank\" rel=\"noopener noreferrer\">greckiego</a>. Powstało z <a href=\"https://pl.wikipedia.org/wiki/J%C4%99zyk_grecki\" target=\"_blank\" rel=\"noopener noreferrer\">gr.</a>&#160;Αγαπητός, oznaczającego „drogi, kochany”.", "Ayumu": "<b>Ayumu</b>&#32;(<a href=\"https://pl.wikipedia.org/wiki/J%C4%99zyk_japo%C5%84ski\" target=\"_blank\" rel=\"noopener noreferrer\">jap.</a>&#32;あゆむ, アユム) – męskie <a href=\"https://pl.wikipedia.org/wiki/Imiona_japo%C5%84skie\" target=\"_blank\" rel=\"noopener noreferrer\">imię japońskie</a>.", "Aldwin": "<b>Audoen</b>, <i>Aldowin</i> – <a href=\"https://pl.wikipedia.org/wiki/Imi%C4%99\" target=\"_blank\" rel=\"noopener noreferrer\">imię</a> męskie pochodzenia <a href=\"https://pl.wikipedia.org/wiki/J%C4%99zyki_germa%C5%84skie\" target=\"_blank\" rel=\"noopener noreferrer\">germańskiego</a>, złożone z członów <i>alt</i> – „stary” i <i>wini</i> – „przyjaciel”, a oznacza – stary przyjaciel. Patronem tego imienia jest św. Audoen (Aldowin, Aldwin), biskup <a href=\"https://pl.wikipedia.org/wiki/Rouen\" target=\"_blank\" rel=\"noopener noreferrer\">Rouen</a>.", "Asuka": "<b>Asuka</b>&#32;(<a href=\"https://pl.wikipedia.org/wiki/J%C4%99zyk_japo%C5%84ski\" target=\"_blank\" rel=\"noopener noreferrer\">jap.</a>&#32;あすか, アスカ) – głównie żeńskie <a href=\"https://pl.wikipedia.org/wiki/Imiona_japo%C5%84skie\" target=\"_blank\" rel=\"noopener noreferrer\">imię japońskie</a>, rzadko noszone przez mężczyzn, może być używane także jako nazwisko.", "Ademar": "<b>Ademar</b>, Adalmer, Adalmar – męskie <a href=\"https://pl.wikipedia.org/wiki/Imi%C4%99\" target=\"_blank\" rel=\"noopener noreferrer\">imię</a> <a href=\"https://pl.wikipedia.org/wiki/J%C4%99zyki_germa%C5%84skie\" target=\"_blank\" rel=\"noopener noreferrer\">germańskie</a>, notowane w <a href=\"https://pl.wikipedia.org/wiki/Polska\" target=\"_blank\" rel=\"noopener noreferrer\">Polsce</a> od <a href=\"https://pl.wikipedia.org/wiki/%C5%9Aredniowiecze\" target=\"_blank\" rel=\"noopener noreferrer\">średniowiecza</a> w formie <i>Ademarus</i> (<a href=\"https://pl.wikipedia.org/wiki/1318\" target=\"_blank\" rel=\"noopener noreferrer\">1318</a>). Pierwszy człon imienia, <i>Adal–</i> w różnych odmiankach oznacza „szlachetny ród”, „ród szlachecki, stan szlachecki”, natomiast <i>-mar</i>, pochodzi od <a href=\"https://pl.wikipedia.org/wiki/J%C4%99zyk_staro-wysoko-niemiecki\" target=\"_blank\" rel=\"noopener noreferrer\">stwniem.</a> <i>māri //-meraz</i> — „sławny”. Staropolskie zdrobnienia od imion z pierwszym członem <i>Adal-</i> to: Alesz, Alis, Alsz, Alszyk, Halsz, Oberek, Oberko, Apecko, Opac(z), Opac(z)ek, Opac(z)ko, Opecko, Owruta.", "Anti": "Jego kult jest bardzo stary, pochodzi co najmniej z okresu <a href=\"https://pl.wikipedia.org/wiki/II_dynastia\" target=\"_blank\" rel=\"noopener noreferrer\">drugiej dynastii</a>, kiedy to miał już swoich kapłanów. Anti najprawdopodobniej był patronem dawnej okolicy Badari, które było centrum kultu <a href=\"https://pl.wikipedia.org/wiki/Horus\" target=\"_blank\" rel=\"noopener noreferrer\">Horusa</a>. Przedstawiany jest jako sokół stojący na łodzi.", "Antoś": "Sama nazwa Antoś pochodzi od imion dwóch skoczków narciarskich ze Szczyrku – <a href=\"https://pl.wikipedia.org/wiki/Antoni_%C5%81aciak\" target=\"_blank\" rel=\"noopener noreferrer\">Antoniego Łaciaka</a> i <a href=\"https://pl.wikipedia.org/wiki/Antoni_Wieczorek\" target=\"_blank\" rel=\"noopener noreferrer\">Antoniego Wieczorka</a>. Skocznia nazywana była też <a href=\"https://pl.wikipedia.org/wiki/Beskidek_(860_m)\" target=\"_blank\" rel=\"noopener noreferrer\">Beskidkiem</a> – od nazwy stoku na którym była położona.", "Artemon": "<b>Artemon</b> – <a href=\"https://pl.wikipedia.org/wiki/Imi%C4%99\" target=\"_blank\" rel=\"noopener noreferrer\">imię</a> męskie wywodzące się od imienia wczesnochrześcijańskiego biskupa św. Artemona.", "Alfa": "<b>Alfa</b> (<b>ἄλφα</b>, pisana <b>Αα</b>) − pierwsza <a href=\"https://pl.wikipedia.org/wiki/Litera\" target=\"_blank\" rel=\"noopener noreferrer\">litera</a> <a href=\"https://pl.wikipedia.org/wiki/Alfabet_grecki\" target=\"_blank\" rel=\"noopener noreferrer\">alfabetu greckiego</a>. W greckim systemie liczbowym oznacza liczbę <a href=\"https://pl.wikipedia.org/wiki/1_(liczba)\" target=\"_blank\" rel=\"noopener noreferrer\">1</a>. Alfa pochodzi od litery <a href=\"https://pl.wikipedia.org/wiki/Alfabet_fenicki\" target=\"_blank\" rel=\"noopener noreferrer\">alfabetu fenickiego</a> <a href=\"https://pl.wikipedia.org/wiki/Alef\" target=\"_blank\" rel=\"noopener noreferrer\">alef</a> <a href=\"https://pl.wikipedia.org/wiki/Plik:Phoenician_aleph.svg\" target=\"_blank\" rel=\"noopener noreferrer\"></a>. Od alfy pochodzą <a href=\"https://pl.wikipedia.org/wiki/Alfabet_%C5%82aci%C5%84ski\" target=\"_blank\" rel=\"noopener noreferrer\">łacińskie</a> <a href=\"https://pl.wikipedia.org/wiki/A\" target=\"_blank\" rel=\"noopener noreferrer\">A</a> i <a href=\"https://pl.wikipedia.org/wiki/Cyrylica\" target=\"_blank\" rel=\"noopener noreferrer\">cyrylickie</a> <a href=\"https://pl.wikipedia.org/wiki/%D0%90_(cyrylica)\" target=\"_blank\" rel=\"noopener noreferrer\">А</a>.", "Alberico": "Starofrancusko-normańska forma <b>Aubrey</b> jest używana w krajach anglojęzycznych jako imię a także nazwisko. Od <a href=\"https://pl.wikipedia.org/wiki/Lata_70._XX_wieku\" target=\"_blank\" rel=\"noopener noreferrer\">lat 70. XX wieku</a> częściej nadawana jest kobietom, być może pod wpływem podobieństwa z żeńskim imieniem <a href=\"https://pl.wikipedia.org/wiki/Edeltruda\" target=\"_blank\" rel=\"noopener noreferrer\">Audrey</a>. Możliwe, że żeńska forma jest w istocie odmiennym imieniem i wywodzi się również poprzez starofrancuski z germańskiego żeńskiego imienia <i>Albrad</i>, od <i>alb</i> – elf oraz drugiego członu o nieustalonej etymologii.", "Alba": "<b>Alba</b> – <a href=\"https://pl.wikipedia.org/wiki/Imi%C4%99\" target=\"_blank\" rel=\"noopener noreferrer\">imię</a> żeńskie pochodzenia <a href=\"https://pl.wikipedia.org/wiki/%C5%81acina\" target=\"_blank\" rel=\"noopener noreferrer\">łacińskiego</a>, pochodzące od łac. <i>Albus/a</i>, od <i>albus</i> \"jasny, biały, świetlisty\". W Polsce spotykane bardzo rzadko, choć notowane już w średniowieczu.", "Ageusz": "<b>Aggeusz</b> – <a href=\"https://pl.wikipedia.org/wiki/Imi%C4%99\" target=\"_blank\" rel=\"noopener noreferrer\">imię</a> męskie, biblijne, z <a href=\"https://pl.wikipedia.org/wiki/J%C4%99zyk_hebrajski\" target=\"_blank\" rel=\"noopener noreferrer\">hebrajskiego</a> <i>Haggai</i>, 'urodzony w święto', zatem odpowiadałoby to <a href=\"https://pl.wikipedia.org/wiki/%C5%81acina\" target=\"_blank\" rel=\"noopener noreferrer\">łacińskiemu</a> <i>Dominicus</i> czy <a href=\"https://pl.wikipedia.org/wiki/J%C4%99zyk_grecki\" target=\"_blank\" rel=\"noopener noreferrer\">greckiemu</a> <i>Kyriakós</i> (<i>świąteczny</i> lub <i>urodzony w święto</i>). Imię to nosił <a href=\"https://pl.wikipedia.org/wiki/Aggeusz\" target=\"_blank\" rel=\"noopener noreferrer\">jeden z proroków mniejszych</a> w <a href=\"https://pl.wikipedia.org/wiki/Biblia\" target=\"_blank\" rel=\"noopener noreferrer\">Biblii</a>.", "Aoi": "<b>Aoi</b>&#32;(<a href=\"https://pl.wikipedia.org/wiki/J%C4%99zyk_japo%C5%84ski\" target=\"_blank\" rel=\"noopener noreferrer\">jap.</a>&#32;あおい, アオイ) – <a href=\"https://pl.wikipedia.org/wiki/Imiona_japo%C5%84skie\" target=\"_blank\" rel=\"noopener noreferrer\">imię japońskie</a>, używane jest także jako nazwisko. Oznacza „malwa” lub „niebieski”. Imieniny obchodzi 27 marca.", "Agamemnon": "<b>Agamemnon</b> (<a href=\"https://pl.wikipedia.org/wiki/J%C4%99zyk_grecki\" target=\"_blank\" rel=\"noopener noreferrer\">gr.</a> Ἀγαμέμνων <i>Agamémnōn</i>, <a href=\"https://pl.wikipedia.org/wiki/%C5%81acina\" target=\"_blank\" rel=\"noopener noreferrer\">łac.</a> <i>Agamemnon</i>) – w <a href=\"https://pl.wikipedia.org/wiki/Mitologia_grecka\" target=\"_blank\" rel=\"noopener noreferrer\">mitologii greckiej</a> syn <a href=\"https://pl.wikipedia.org/wiki/Atreus\" target=\"_blank\" rel=\"noopener noreferrer\">Atreusza</a> i <a href=\"https://pl.wikipedia.org/wiki/Aerope_(c%C3%B3rka_Katreusa)\" target=\"_blank\" rel=\"noopener noreferrer\">Aerope</a>, (w niektórych mitach ojcostwo przypisywane jest <a href=\"https://pl.wikipedia.org/wiki/Plejstenes\" target=\"_blank\" rel=\"noopener noreferrer\">Plejstenesowi</a>), starszy brat <a href=\"https://pl.wikipedia.org/wiki/Menelaos\" target=\"_blank\" rel=\"noopener noreferrer\">Menelaosa</a>, pochodził z rodu <a href=\"https://pl.wikipedia.org/wiki/Atrydzi\" target=\"_blank\" rel=\"noopener noreferrer\">Atrydów</a>. Król <a href=\"https://pl.wikipedia.org/wiki/Argolida\" target=\"_blank\" rel=\"noopener noreferrer\">Argolidy</a>, krainy, w której najważniejszymi miastami były <a href=\"https://pl.wikipedia.org/wiki/Argos_(Grecja)\" target=\"_blank\" rel=\"noopener noreferrer\">Argos</a>, <a href=\"https://pl.wikipedia.org/wiki/Mykeny\" target=\"_blank\" rel=\"noopener noreferrer\">Mykeny</a>, <a href=\"https://pl.wikipedia.org/wiki/Tyryns\" target=\"_blank\" rel=\"noopener noreferrer\">Tiryns</a>, Midea. Według najpóźniejszego przekazu był królem Lakedajmonu ze stolicą Amyklaj. Od jego przodków nazywano go czasem Atrydą, Pelopidą lub Tantalidą.", "Ashoka": "Pierwszym jego zarządzeniem był rozkaz zgładzenia wszystkich przyrodnich braci – ewentualnych pretendentów do królewskiego tronu. Przy życiu pozostawił tylko młodszego brata – pochodzącego od tej samej matki Tisidżę. Król miał syna, Mahendrę (Mahindę), urodzonego w 284 roku p.n.e. oraz córkę, Sanghamitrę, urodzoną w 268 roku p.n.e.", "Absalon": "<b>Absalon</b>, <b>Absalom</b> – <a href=\"https://pl.wikipedia.org/wiki/Imi%C4%99\" target=\"_blank\" rel=\"noopener noreferrer\">imię</a> męskie pochodzenia <a href=\"https://pl.wikipedia.org/wiki/Biblia\" target=\"_blank\" rel=\"noopener noreferrer\">biblijnego</a>. Wywodzi się z hebrajskiego <i>Abishalom</i> oznaczającego „Ojciec [Bóg] jest pokojem”. Formą przyjętą w Polsce jest <b>Absalon</b>. Skandynawską formą tego imienia jest <b>Axel</b>.", "Admin": "<b>Administrator systemów komputerowych</b> (<a href=\"https://pl.wikipedia.org/wiki/%C5%81acina\" target=\"_blank\" rel=\"noopener noreferrer\">łac.</a>&#160;<em>administrator</em> „zarządca”), żargonowo <b>sysadmin</b> (<a href=\"https://pl.wikipedia.org/wiki/J%C4%99zyk_angielski\" target=\"_blank\" rel=\"noopener noreferrer\">ang.</a>&#160;<em>system administrator</em>) – <a href=\"https://pl.wikipedia.org/wiki/Informatyka\" target=\"_blank\" rel=\"noopener noreferrer\">informatyk</a> zajmujący się zarządzaniem <a href=\"https://pl.wikipedia.org/wiki/System_informatyczny\" target=\"_blank\" rel=\"noopener noreferrer\">systemem informatycznym</a> i odpowiadający za jego sprawne działanie.", "Amat": "<b>Amat</b> – <a href=\"https://pl.wikipedia.org/wiki/Imi%C4%99\" target=\"_blank\" rel=\"noopener noreferrer\">imię</a> męskie pochodzenia <a href=\"https://pl.wikipedia.org/wiki/%C5%81acina\" target=\"_blank\" rel=\"noopener noreferrer\">łacińskiego</a>. Wywodzi się od łacińskiej nazwy rodowej (<i>Amatus</i>), która z kolei dosłownie oznacza \"ukochany, drogi, kochany\".", "Afro": "<b>Afro</b> – <a href=\"https://pl.wikipedia.org/wiki/Fryzura\" target=\"_blank\" rel=\"noopener noreferrer\">sposób ułożenia włosów</a>. Są to włosy kręcone, ułożone stercząco – te z brzegu na boki, pośrodku ku górze tak, aby fryzura tworzyła kształt kuli. Nazwa pochodzi od amerykańskiego wyrażenia „Afro-Americans”, odnoszącego się do czarnoskórych Amerykanów.", "Arame": "O procesie powstawania Urartu zachowało się mało informacji. Pozostaje niejasnym, kto był następcą Arama: jego rywal <a href=\"https://pl.wikipedia.org/wiki/Lutipri\" target=\"_blank\" rel=\"noopener noreferrer\">Lutipri</a> czy syn Lutipriego – <a href=\"https://pl.wikipedia.org/wiki/Sarduri_I\" target=\"_blank\" rel=\"noopener noreferrer\">Sarduri I</a>. W połowie IX wieku p.n.e. na terenie niegdysiejszego Urartu trwał proces zjednoczenia plemion <a href=\"https://pl.wikipedia.org/wiki/Nairi\" target=\"_blank\" rel=\"noopener noreferrer\">Nairi</a> w jedno scentralizowane państwo. Prawdopodobnie Aramu i Lutipri stali na czele dwóch różnych plemion. Walkę o przejęcie władzy zwierzchniej wygrał ostatecznie Lutipri. Za czasów Arama stolicą Urartu było miasto Arzaszkun. Po jego zburzeniu przez <a href=\"https://pl.wikipedia.org/wiki/Asyria\" target=\"_blank\" rel=\"noopener noreferrer\">Asyryjczyków</a>, już za panowania Sarduriego I, stolica została przeniesiona do <a href=\"https://pl.wikipedia.org/wiki/Tuszpa\" target=\"_blank\" rel=\"noopener noreferrer\">Tuszpy</a>.", "Ajaks": "<b>Ajaks</b> – <a href=\"https://pl.wikipedia.org/wiki/Imi%C4%99\" target=\"_blank\" rel=\"noopener noreferrer\">imię</a> męskie pochodzenia <a href=\"https://pl.wikipedia.org/wiki/J%C4%99zyk_grecki\" target=\"_blank\" rel=\"noopener noreferrer\">greckiego</a>, które może wywodzić się od słowa oznaczającego „ruch, poruszenie, życie” albo „kraj, kraina”, a być może stanowi skrócenie z imienia <i>Filajas</i>. Imię to nosiły dwie postaci <a href=\"https://pl.wikipedia.org/wiki/Mitologia_grecka\" target=\"_blank\" rel=\"noopener noreferrer\">greckiej mitologii</a>. W <a href=\"https://pl.wikipedia.org/wiki/Polska\" target=\"_blank\" rel=\"noopener noreferrer\">Polsce</a> jest nadawane od średniowiecza.", "Almeida": "Nazwa miejscowości wywodzi się z <a href=\"https://pl.wikipedia.org/wiki/J%C4%99zyk_arabski\" target=\"_blank\" rel=\"noopener noreferrer\">arabskiego</a> <i>al-Ma’ida</i>, co oznacza „stół”. Odnosi się to do płaskiego ukształtowania terenu otaczającego miejscowość.", "Arsłan": "<b>Arsłan</b> – <a href=\"https://pl.wikipedia.org/wiki/Polska\" target=\"_blank\" rel=\"noopener noreferrer\">polski</a> <a href=\"https://pl.wikipedia.org/wiki/Herb_szlachecki\" target=\"_blank\" rel=\"noopener noreferrer\">herb szlachecki</a> używany przez rodzinę <a href=\"https://pl.wikipedia.org/wiki/Ksi%C4%85%C5%BC%C4%99\" target=\"_blank\" rel=\"noopener noreferrer\">książęcą</a> pochodzenia <a href=\"https://pl.wikipedia.org/wiki/Tatarzy\" target=\"_blank\" rel=\"noopener noreferrer\">tatarskiego</a>.", "Anastasia": "<b>Anastazja</b> – żeński odpowiednik <a href=\"https://pl.wikipedia.org/wiki/Imi%C4%99\" target=\"_blank\" rel=\"noopener noreferrer\">imienia</a> <a href=\"https://pl.wikipedia.org/wiki/Anastazy\" target=\"_blank\" rel=\"noopener noreferrer\">Anastazy</a>. Oznacza „zmartwychwstała, wskrzeszona”.", "Adad": "<b>Adad</b> – bóg burzy, wiatru, deszczu i piorunów oraz siły niszczycielskiej, jedno z ważniejszych bóstw w <a href=\"https://pl.wikipedia.org/wiki/Mitologia_babilo%C5%84ska\" target=\"_blank\" rel=\"noopener noreferrer\">mitologii babilońskiej</a>. Geneza Adada sięga okresu <a href=\"https://pl.wikipedia.org/wiki/Sumer\" target=\"_blank\" rel=\"noopener noreferrer\">sumeryjskiego</a>. Był on utożsamiany z pomniejszym bóstwem w <a href=\"https://pl.wikipedia.org/wiki/Mitologia_sumeryjska\" target=\"_blank\" rel=\"noopener noreferrer\">panteonie sumeryjskim</a> – <a href=\"https://pl.wikipedia.org/wiki/Iszkur\" target=\"_blank\" rel=\"noopener noreferrer\">Iszkurem</a>, którego cechy rozwinęły się w okresie <a href=\"https://pl.wikipedia.org/wiki/Babilonia\" target=\"_blank\" rel=\"noopener noreferrer\">babilońskim</a>, a następnie <a href=\"https://pl.wikipedia.org/wiki/Asyria\" target=\"_blank\" rel=\"noopener noreferrer\">asyryjskim</a>, gdy Adadowi przypisano atrybuty i cechy wojskowe. O randze Adada świadczy włączanie jego imienia do imion królów.", "Arystydes": "<b>Arystydes</b> – <a href=\"https://pl.wikipedia.org/wiki/Imi%C4%99\" target=\"_blank\" rel=\"noopener noreferrer\">imię</a> męskie pochodzenia <a href=\"https://pl.wikipedia.org/wiki/Gr.\" target=\"_blank\" rel=\"noopener noreferrer\">greckiego</a> Αριστειδης, co oznacza „najlepszy rodzaj”, stanowiąc złożenie członów αριστος (aristos) „najlepszy” i ειδος (eidos) - „rodzaj, gatunek”. <b>Arystydes</b> <a href=\"https://pl.wikipedia.org/wiki/Imieniny\" target=\"_blank\" rel=\"noopener noreferrer\">imieniny</a> obchodzi <a href=\"https://pl.wikipedia.org/wiki/31_sierpnia\" target=\"_blank\" rel=\"noopener noreferrer\">31 sierpnia</a>.", "Aneirin": "<b>Aneirin</b> lub <b>Neirin</b> – wczesnośredniowieczny poeta pochodzenia brytońskiego (<a href=\"https://pl.wikipedia.org/wiki/Walia\" target=\"_blank\" rel=\"noopener noreferrer\">walijskiego</a>). Uważany za <a href=\"https://pl.wikipedia.org/wiki/Bard\" target=\"_blank\" rel=\"noopener noreferrer\">barda</a> lub poetę nadwornego w jednym z kumbryjskich królestw <i>Starej Północy</i> (Hen Ogledd), prawdopodobnie Gododin w <a href=\"https://pl.wikipedia.org/wiki/Edynburg\" target=\"_blank\" rel=\"noopener noreferrer\">Edynburgu</a>. Od XVII wieku jego imię często zapisywano błędnie jako <b>Aneurin</b>.", "Angelina": "<b>Angelina</b> – forma pochodna <a href=\"https://pl.wikipedia.org/wiki/Imi%C4%99\" target=\"_blank\" rel=\"noopener noreferrer\">imion</a> <a href=\"https://pl.wikipedia.org/wiki/Aniela\" target=\"_blank\" rel=\"noopener noreferrer\">Aniela</a>, <a href=\"https://pl.wikipedia.org/wiki/Angela\" target=\"_blank\" rel=\"noopener noreferrer\">Angela</a>.", "Akseli": "<b>Absalon</b>, <b>Absalom</b> – <a href=\"https://pl.wikipedia.org/wiki/Imi%C4%99\" target=\"_blank\" rel=\"noopener noreferrer\">imię</a> męskie pochodzenia <a href=\"https://pl.wikipedia.org/wiki/Biblia\" target=\"_blank\" rel=\"noopener noreferrer\">biblijnego</a>. Wywodzi się z hebrajskiego <i>Abishalom</i> oznaczającego „Ojciec [Bóg] jest pokojem”. Formą przyjętą w Polsce jest <b>Absalon</b>. Skandynawską formą tego imienia jest <b>Axel</b>.", "Albina": "<b>Albina</b> – <a href=\"https://pl.wikipedia.org/wiki/Imi%C4%99\" target=\"_blank\" rel=\"noopener noreferrer\">imię</a> żeńskie pochodzenia <a href=\"https://pl.wikipedia.org/wiki/%C5%81acina\" target=\"_blank\" rel=\"noopener noreferrer\">łacińskiego</a>, żeński odpowiednik imienia <a href=\"https://pl.wikipedia.org/wiki/Albin\" target=\"_blank\" rel=\"noopener noreferrer\">Albin</a>. Prawdopodobnie wywodzi się od słowa \"albus\", czyli czysty, biały. Inna hipoteza głosi, że to połączenie germańskich słów „alb” i „wini”, co ma oznaczać „przyjaciółkę elfów”.", "Ammon": "<b>Ammon</b> (<a href=\"https://pl.wikipedia.org/wiki/Alfabet_deseret\" target=\"_blank\" rel=\"noopener noreferrer\">deseret</a> 𐐈𐐣𐐊𐐤) – imię męskie występujące w wyznaniach należących do <a href=\"https://pl.wikipedia.org/wiki/Ruch_%C5%9Bwi%C4%99tych_w_dniach_ostatnich\" target=\"_blank\" rel=\"noopener noreferrer\">ruchu świętych w dniach ostatnich</a> (mormonów). Pochodzi z Księgi Mormona, w której nosiły je dwie postacie. Pojawiło się w źródłach już w początkach mormonizmu. Popularne w zdominowanym przez świętych w dniach ostatnich stanie Utah. Występuje wśród wyznających mormonizm Maorysów oraz w Meksyku. Znalazło odzwierciedlenie w szerszej mormońskiej kulturze. Jako imię wywiedzione z pism świętych uznawane jest za powód do dumy. Ma także wywierać pozytywny wpływ na życie duchowe noszącego je człowieka.", "Ansgary": "<b>Oskar</b> – <a href=\"https://pl.wikipedia.org/wiki/Imi%C4%99\" target=\"_blank\" rel=\"noopener noreferrer\">imię</a> męskie pochodzenia <a href=\"https://pl.wikipedia.org/wiki/J%C4%99zyki_germa%C5%84skie\" target=\"_blank\" rel=\"noopener noreferrer\">germańskiego</a> oznaczające „bożą włócznię” lub „włócznię boga” (<i>os</i> lub <i>ans</i> „bóg” i <i>gār</i> „włócznia”) lub <a href=\"https://pl.wikipedia.org/wiki/J%C4%99zyki_celtyckie\" target=\"_blank\" rel=\"noopener noreferrer\">iryjskiego</a>, gdzie oznaczało „przyjaciela jeleni” (<i>os</i> „jeleń”, <i>cara</i> „przyjaciel”). W tekstach po polsku pojawiło się w XV wieku. Imię to nosili m.in. królowie <a href=\"https://pl.wikipedia.org/wiki/Szwecja\" target=\"_blank\" rel=\"noopener noreferrer\">Szwecji</a>. Jego wariantem przyjętym w Polsce jest <b>Ansgar</b>.", "Albus": "<b>Alba Sylwiusz</b> (<a href=\"https://pl.wikipedia.org/wiki/%C5%81acina\" target=\"_blank\" rel=\"noopener noreferrer\">łac</a>. <i>Alba Silvius</i>) – legendarny król miasta <a href=\"https://pl.wikipedia.org/wiki/Alba_Longa\" target=\"_blank\" rel=\"noopener noreferrer\">Alba Longa</a>, syn <a href=\"https://pl.wikipedia.org/wiki/Latinus_Silvius\" target=\"_blank\" rel=\"noopener noreferrer\">Latynusa Sylwiusza</a>, wnuk <a href=\"https://pl.wikipedia.org/wiki/Aeneas_Silvius\" target=\"_blank\" rel=\"noopener noreferrer\">Eneasza Sylwiusza</a>, przodek: <a href=\"https://pl.wikipedia.org/wiki/Silvius\" target=\"_blank\" rel=\"noopener noreferrer\">Sylwiusza</a>, <a href=\"https://pl.wikipedia.org/wiki/Askaniusz\" target=\"_blank\" rel=\"noopener noreferrer\">Askaniusza</a> i <a href=\"https://pl.wikipedia.org/wiki/Eneasz\" target=\"_blank\" rel=\"noopener noreferrer\">Eneasza</a>, ojciec <a href=\"https://pl.wikipedia.org/wiki/Capetus\" target=\"_blank\" rel=\"noopener noreferrer\">Kapeta</a> (imię według narracji <a href=\"https://pl.wikipedia.org/wiki/Dionizjusz_z_Halikarnasu\" target=\"_blank\" rel=\"noopener noreferrer\">Dionizjusza z Halikarnasu</a>, przez Liwiusza zwany <i>Atysem</i>). Rządził 39 lat.", "Amira": "<b>Amira</b> (<a href=\"https://pl.wikipedia.org/wiki/J%C4%99zyk_arabski\" target=\"_blank\" rel=\"noopener noreferrer\">arab.</a> أميرة) – imię arabskie, oznaczające „<a href=\"https://pl.wikipedia.org/wiki/Ksi%C4%99%C5%BCniczka\" target=\"_blank\" rel=\"noopener noreferrer\">księżniczka</a>”. Słowo to także funkcjonuje w <a href=\"https://pl.wikipedia.org/wiki/J%C4%99zyk_arabski\" target=\"_blank\" rel=\"noopener noreferrer\">języku arabskim</a> potocznie.", "Adlai": "<b>Adlai</b> – męskie <a href=\"https://pl.wikipedia.org/wiki/Imi%C4%99\" target=\"_blank\" rel=\"noopener noreferrer\">imię</a> pochodzenia hebrajskiego. Jego znaczenie to „Bóg jest sprawiedliwy” lub „Bóg jest ozdobą”.", "Arkadia": "<b>Arkadia</b> – <a href=\"https://pl.wikipedia.org/wiki/Imi%C4%99\" target=\"_blank\" rel=\"noopener noreferrer\">imię</a> żeńskie pochodzenia <a href=\"https://pl.wikipedia.org/wiki/Greka\" target=\"_blank\" rel=\"noopener noreferrer\">greckiego</a>. Wywodzi od słowa (<i>arkadios</i>) oznaczającego „pochodząca z <a href=\"https://pl.wikipedia.org/wiki/Arkadia_(kraina_historyczna)\" target=\"_blank\" rel=\"noopener noreferrer\">Arkadii</a>, krainy szczęśliwości”.", "Arashi": "<b>Arashi</b>&#32;(<a href=\"https://pl.wikipedia.org/wiki/J%C4%99zyk_japo%C5%84ski\" target=\"_blank\" rel=\"noopener noreferrer\">jap.</a>&#32;嵐&#59; dosł. <i>burza</i>) - <a href=\"https://pl.wikipedia.org/wiki/Imiona_japo%C5%84skie\" target=\"_blank\" rel=\"noopener noreferrer\">imię japońskie</a> noszone przez mężczyzn oraz kobiety.", "Amerigo": "<b>Emeryk</b>, Amalaryk, Amalryk – <a href=\"https://pl.wikipedia.org/wiki/Imi%C4%99\" target=\"_blank\" rel=\"noopener noreferrer\">imię</a> męskie pochodzenia <a href=\"https://pl.wikipedia.org/wiki/J%C4%99zyki_germa%C5%84skie\" target=\"_blank\" rel=\"noopener noreferrer\">germańskiego</a>. Wywodzi się ze starogermańskiego imienia <a href=\"https://pl.wikipedia.org/wiki/Amalaryk\" target=\"_blank\" rel=\"noopener noreferrer\">Amalaryk</a>, oznaczającego „władca <a href=\"https://pl.wikipedia.org/wiki/Amalowie\" target=\"_blank\" rel=\"noopener noreferrer\">Amalów</a>” (Amalowie według gockiej legendy to ród królewski pochodzenia boskiego). Człon <i>amal</i> może także oznaczać „gorliwy” lub „dzielny, aktywny”. Emeryk może wywodzić się również z saksońskiego <i>Emmerich</i>, oznaczającego „zawsze bogaty”.", "Aser": "Miał sześciu synów oraz jedną córkę (Serach). Od niego wywodzi się jedno z <a href=\"https://pl.wikipedia.org/wiki/Dwana%C5%9Bcie_Plemion_Izraela\" target=\"_blank\" rel=\"noopener noreferrer\">dwunastu pokoleń Izraela</a>. Według tradycji dożył 123 lat.", "Awadh": "<b>Awadh</b> lub <b>Oudh</b> – region w <a href=\"https://pl.wikipedia.org/wiki/Indie\" target=\"_blank\" rel=\"noopener noreferrer\">indyjskim</a> stanie <a href=\"https://pl.wikipedia.org/wiki/Uttar_Pradesh\" target=\"_blank\" rel=\"noopener noreferrer\">Uttar Pradesh</a> graniczący od południowego zachodu z <a href=\"https://pl.wikipedia.org/wiki/Doab\" target=\"_blank\" rel=\"noopener noreferrer\">doabem</a> <a href=\"https://pl.wikipedia.org/wiki/Ganges\" target=\"_blank\" rel=\"noopener noreferrer\">Gangesu</a> i <a href=\"https://pl.wikipedia.org/wiki/Jamuna\" target=\"_blank\" rel=\"noopener noreferrer\">Jamuny</a>, od północnego zachodu z regionem Rohilkhand, od wschodu z Purvanchal a od północy z <a href=\"https://pl.wikipedia.org/wiki/Nepal\" target=\"_blank\" rel=\"noopener noreferrer\">Nepalem</a>. Mieszkańcy regiony posługują się językiem <a href=\"https://pl.wikipedia.org/wiki/Awadhi\" target=\"_blank\" rel=\"noopener noreferrer\">Awadhi</a>. Nazwa regionu pochodzi od miasta <a href=\"https://pl.wikipedia.org/wiki/Ayodhya\" target=\"_blank\" rel=\"noopener noreferrer\">Ayodhya</a>, stolicy starożytnego królestwa Kosala, którego obszar pokrywał się z dzisiejszym obszarem regionu Awadh&#8201;.", "Arnolf": "<b>Arnulf</b>, <b>Arnolf</b> – <a href=\"https://pl.wikipedia.org/wiki/Imi%C4%99\" target=\"_blank\" rel=\"noopener noreferrer\">imię</a> męskie pochodzenia <a href=\"https://pl.wikipedia.org/wiki/J%C4%99zyki_germa%C5%84skie\" target=\"_blank\" rel=\"noopener noreferrer\">germańskiego</a>. Pierwszy człon imienia stanowi <i>arn</i> – <a href=\"https://pl.wikipedia.org/wiki/J%C4%99zyk_staro-wysoko-niemiecki\" target=\"_blank\" rel=\"noopener noreferrer\">staro-wysoko-niemiecki (stwniem.)</a>-frankoński, średnio-dolno-niemiecki (śrdniem.) <i>arn</i> („<a href=\"https://pl.wikipedia.org/wiki/Or%C5%82y\" target=\"_blank\" rel=\"noopener noreferrer\">orzeł</a>”); drugim członem jest <i>wolf</i> – <a href=\"https://pl.wikipedia.org/wiki/J%C4%99zyki_germa%C5%84skie\" target=\"_blank\" rel=\"noopener noreferrer\">germ.</a> <i>wulfa &gt; wolfa</i> („<a href=\"https://pl.wikipedia.org/wiki/Wilk_w_kulturze\" target=\"_blank\" rel=\"noopener noreferrer\">wilk</a>”); stwniem. <i>wolf</i>. Formy z <i>-ulf</i> są odbiciem zromanizowanego germ. <i>-wulf</i>. Wariantami drugiego członu są: <i>-wulf</i>, który stanowi kontynuację najstarszej, germańskiej formy, zachowanej w śrdniem. i <a href=\"https://pl.wikipedia.org/wiki/J%C4%99zyk_dolnoniemiecki\" target=\"_blank\" rel=\"noopener noreferrer\">dolnoniemiecki (dniem.)</a>, oraz <i>-wolf</i>, kontynuacja młodszej formy germańskiej, przejętej przez stwniem., <a href=\"https://pl.wikipedia.org/wiki/J%C4%99zyk_%C5%9Brednio-wysoko-niemiecki\" target=\"_blank\" rel=\"noopener noreferrer\">średnio-wysoko-niemiecki (śrwniem.)</a> i nowoniemiecki. Imię to notowane było w Polsce już w średniowieczu, w formie (Arnolf) (<a href=\"https://pl.wikipedia.org/wiki/1219\" target=\"_blank\" rel=\"noopener noreferrer\">1219</a>), Arnolfus (Arnulf) (<a href=\"https://pl.wikipedia.org/wiki/1435\" target=\"_blank\" rel=\"noopener noreferrer\">1435</a>). Niektóre możliwe staropolskie zdrobnienia: Arnek, Arnko.", "Atabeg": "<b>Atabeg</b> – tytuł seldżucki nadawany wychowawcy synów <a href=\"https://pl.wikipedia.org/wiki/Su%C5%82tan\" target=\"_blank\" rel=\"noopener noreferrer\">sułtana</a> lub namiestnikowi prowincji. Atabeg podlegał <a href=\"https://pl.wikipedia.org/wiki/Su%C5%82tan\" target=\"_blank\" rel=\"noopener noreferrer\">sułtanowi</a>, ale stał w hierarchii wyżej niż <a href=\"https://pl.wikipedia.org/wiki/Chan_(w%C5%82adca)\" target=\"_blank\" rel=\"noopener noreferrer\">chan</a>. Słowo <i>atabeg</i> można przetłumaczyć jako \"ojciec księcia\". Tytuł ten był powszechny wśród <a href=\"https://pl.wikipedia.org/wiki/Seld%C5%BCukidzi\" target=\"_blank\" rel=\"noopener noreferrer\">Seldżuków</a> od <a href=\"https://pl.wikipedia.org/wiki/XI_wiek\" target=\"_blank\" rel=\"noopener noreferrer\">XI</a> do <a href=\"https://pl.wikipedia.org/wiki/XIII_wiek\" target=\"_blank\" rel=\"noopener noreferrer\">XIII wieku</a>. Z czasem miano atabega oznaczało tytuł dygnitarza. W <a href=\"https://pl.wikipedia.org/wiki/Egipt_mameluk%C3%B3w_(%C5%9Bredniowieczny)\" target=\"_blank\" rel=\"noopener noreferrer\">Egipcie mameluków</a> natomiast atabeg był wysokim rangą oficerem. Po upadku Seldżukidów i sułtanatu mameluków tytuł ten był używany sporadycznie.", "Antonia": "<b>Antonia</b> – <a href=\"https://pl.wikipedia.org/wiki/Imi%C4%99\" target=\"_blank\" rel=\"noopener noreferrer\">imię</a> żeńskie pochodzenia <a href=\"https://pl.wikipedia.org/wiki/%C5%81acina\" target=\"_blank\" rel=\"noopener noreferrer\">łacińskiego</a>, żeński odpowiednik imienia <a href=\"https://pl.wikipedia.org/wiki/Antoni_(imi%C4%99)\" target=\"_blank\" rel=\"noopener noreferrer\">Antoni</a>. W Polsce pojawiło się wcześniej niż imię <a href=\"https://pl.wikipedia.org/wiki/Antonina\" target=\"_blank\" rel=\"noopener noreferrer\">Antonina</a>, ale następnie zostało przez nie wyparte. W Kościele katolickim istnieją dwie patronki tego imienia.", "Aishwarya": "Pochodziła z arystokratycznego rodu Rana (w latach 1846–1950 <i>de facto</i> dziedzicznie sprawującego funkcję premiera Nepalu). Jej rodzicami byli generał Kendra Shumsher Jang Bahadur Rana i jego żona Rani Rajya Lakshmi Rana.", "Alodiusz": "<b>Alodiusz</b> – <a href=\"https://pl.wikipedia.org/wiki/Imi%C4%99\" target=\"_blank\" rel=\"noopener noreferrer\">imię</a> męskie urobione od <a href=\"https://pl.wikipedia.org/wiki/Frankowie\" target=\"_blank\" rel=\"noopener noreferrer\">frankońskiego</a> <i>al-ôd</i>, co oznacza „dziedzictwo, pełne posiadanie”. Imię to łączy się także ze średniowiecznym <a href=\"https://pl.wikipedia.org/wiki/%C5%81acina\" target=\"_blank\" rel=\"noopener noreferrer\">łacińskim</a> wyrazu <i><a href=\"https://pl.wikipedia.org/wiki/Alodium\" target=\"_blank\" rel=\"noopener noreferrer\">allodium</a></i>, który oznaczał „majątek ziemski wolny od ciężarów i powinności lennych”, a pochodzi również od tego samego wyrazu frankońskiego. W Kościele katolickim istnieje kilku świętych patronów tego imienia, m.in. św. Alodiusz, biskup <a href=\"https://pl.wikipedia.org/wiki/Auxerre\" target=\"_blank\" rel=\"noopener noreferrer\">Auxerre</a>, następca <a href=\"https://pl.wikipedia.org/wiki/German_z_Auxerre\" target=\"_blank\" rel=\"noopener noreferrer\">św. Germana</a>.", "Ahmadiyya": "<b>Ahmadijja</b> (<a href=\"https://pl.wikipedia.org/wiki/J%C4%99zyk_arabski\" target=\"_blank\" rel=\"noopener noreferrer\">arab.</a>&#160;&#8207;أحمدية&#8206;, <a href=\"https://pl.wikipedia.org/wiki/Transkrypcja_(j%C4%99zykoznawstwo)\" target=\"_blank\" rel=\"noopener noreferrer\">trans.</a> <b>ʾaḥmadiyya</b>, także: <b>ahmadija</b>) – ruch reformatorski w <a href=\"https://pl.wikipedia.org/wiki/Islam\" target=\"_blank\" rel=\"noopener noreferrer\">islamie</a> założony przez <a href=\"https://pl.wikipedia.org/wiki/Muzu%C5%82manin\" target=\"_blank\" rel=\"noopener noreferrer\">muzułmanina</a> <a href=\"https://pl.wikipedia.org/wiki/Mirza_Gulam_Ahmad\" target=\"_blank\" rel=\"noopener noreferrer\">Mirzę Ghulama Ahmada</a> z <a href=\"https://pl.wikipedia.org/wiki/Qadian\" target=\"_blank\" rel=\"noopener noreferrer\">Qadian</a> (1839–1908) (<a href=\"https://pl.wikipedia.org/wiki/Pend%C5%BCab\" target=\"_blank\" rel=\"noopener noreferrer\">Pendżab</a>), który ogłosił się (zgodnie z objawieniami otrzymywanymi od 1865 roku) <a href=\"https://pl.wikipedia.org/wiki/Mahdi\" target=\"_blank\" rel=\"noopener noreferrer\">mahdim</a> i powtórnie przybyłym <a href=\"https://pl.wikipedia.org/wiki/Jezus_Chrystus\" target=\"_blank\" rel=\"noopener noreferrer\">Jezusem</a>, później zaś także <a href=\"https://pl.wikipedia.org/wiki/Inkarnacja\" target=\"_blank\" rel=\"noopener noreferrer\">inkarnacją</a> <a href=\"https://pl.wikipedia.org/wiki/Kryszna\" target=\"_blank\" rel=\"noopener noreferrer\">Kryszny</a>. Ruch w 1900 roku został oficjalnie uznany przez władze brytyjsko-indyjskie.", "Agnieszka": "<b>Agnieszka</b> – imię żeńskie, jedno z najpopularniejszych w Polsce, gdzie pojawiło się wraz z chrześcijaństwem. Pochodzi od <a href=\"https://pl.wikipedia.org/wiki/J%C4%99zyk_grecki\" target=\"_blank\" rel=\"noopener noreferrer\">gr.</a>&#160;Αγνή – „czysta”, „dziewicza”, „nieskalana”. Może również pochodzić od <a href=\"https://pl.wikipedia.org/wiki/%C5%81acina\" target=\"_blank\" rel=\"noopener noreferrer\">łac.</a>&#160;<em>agnus</em> – „baranek” (to jednocześnie rodzaj męski greckiej „h-agne”). Do Czech imię to dotarło w formie <a href=\"https://pl.wikipedia.org/wiki/%C5%81acina\" target=\"_blank\" rel=\"noopener noreferrer\">łac.</a>&#160;<em>Agnes</em>, następnie zostało zaadaptowane do języka polskiego w obecnej formie. Imię to funkcjonuje również w języku polskim w formie Inka, początkowo było ono polskim zdrobnieniem imienia Inez — francusko-iberyjskiej formy imienia Agnieszka (Inês, Inés, Inès) — z czasem jednak zaczęło funkcjonować w Polsce jako samodzielne imię.", "Agata": "<b>Agata</b> – imię żeńskie, pochodzące od przymiotnika <a href=\"https://pl.wikipedia.org/wiki/J%C4%99zyk_grecki_klasyczny\" target=\"_blank\" rel=\"noopener noreferrer\">stgr.</a>&#160;ἀγαθός („dobry”), w Polsce znane od XIII wieku.", "Aneta": "<b>Aneta</b>, <b>Anetta</b> – forma pochodna imienia <a href=\"https://pl.wikipedia.org/wiki/Anna\" target=\"_blank\" rel=\"noopener noreferrer\">Anna</a>, powstała jako przeniesienie francuskiego zdrobnienia tego imienia, <i>Anette</i>, do języka polskiego. Pochodzi z <a href=\"https://pl.wikipedia.org/wiki/J%C4%99zyk_hebrajski\" target=\"_blank\" rel=\"noopener noreferrer\">języka hebrajskiego</a>. Imię dotarło do Polski w <a href=\"https://pl.wikipedia.org/wiki/XIX_wiek\" target=\"_blank\" rel=\"noopener noreferrer\">XIX w.</a>, wcześniej używano tylko imienia Anna.", "Angelika": "<b>Angelika</b> – <a href=\"https://pl.wikipedia.org/wiki/Imi%C4%99\" target=\"_blank\" rel=\"noopener noreferrer\">imię</a> żeńskie pochodzenia <a href=\"https://pl.wikipedia.org/wiki/%C5%81acina\" target=\"_blank\" rel=\"noopener noreferrer\">łacińskiego</a>, w języku łacińskim oznacza „anielica”, „posłanka”.", "Aniela": "<b>Aniela</b> – <a href=\"https://pl.wikipedia.org/wiki/Imi%C4%99\" target=\"_blank\" rel=\"noopener noreferrer\">imię</a> żeńskie, które jest spolszczoną formą <a href=\"https://pl.wikipedia.org/wiki/%C5%81acina\" target=\"_blank\" rel=\"noopener noreferrer\">łacińskiego</a> imienia <a href=\"https://pl.wikipedia.org/wiki/Angela\" target=\"_blank\" rel=\"noopener noreferrer\">Angela</a>, pochodzącego od <a href=\"https://pl.wikipedia.org/wiki/J%C4%99zyk_grecki\" target=\"_blank\" rel=\"noopener noreferrer\">greckiego</a> słowa <i>ángelos</i> „posłaniec”. Imię trafiło do Polski z Włoch prawdopodobnie w XVIII wieku. W świecie <a href=\"https://pl.wikipedia.org/wiki/Chrze%C5%9Bcija%C5%84stwo\" target=\"_blank\" rel=\"noopener noreferrer\">chrześcijańskim</a> upowszechniło się jako nawiązanie do <a href=\"https://pl.wikipedia.org/wiki/Anio%C5%82\" target=\"_blank\" rel=\"noopener noreferrer\">aniołów</a> i <a href=\"https://pl.wikipedia.org/wiki/Anio%C5%82_Str%C3%B3%C5%BC_(religioznawstwo)\" target=\"_blank\" rel=\"noopener noreferrer\">Anioła Stróża</a>. Jest żeńskim odpowiednikiem imienia <a href=\"https://pl.wikipedia.org/wiki/Anio%C5%82_(imi%C4%99)\" target=\"_blank\" rel=\"noopener noreferrer\">Anioł (Angel)</a>.", "Adrianna": "<b>Adrianna</b>, <b>Adriana</b> – <a href=\"https://pl.wikipedia.org/wiki/Imi%C4%99\" target=\"_blank\" rel=\"noopener noreferrer\">imię</a> żeńskie; żeński odpowiednik <a href=\"https://pl.wikipedia.org/wiki/Imi%C4%99\" target=\"_blank\" rel=\"noopener noreferrer\">imienia</a> <a href=\"https://pl.wikipedia.org/wiki/Adrian_(imi%C4%99)\" target=\"_blank\" rel=\"noopener noreferrer\">Adrian</a>, które pojawiło się w średniowieczu. Pochodzi od męskiego imienia <a href=\"https://pl.wikipedia.org/wiki/Hadrian\" target=\"_blank\" rel=\"noopener noreferrer\">Hadrian</a> lub Adrian, to znaczy <i>należący do miasta Hadrii</i> w Picenum (Włochy). Częściej – w formie Adrian – nadawano je chłopcom. Jako imię żeńskie w zapiskach po raz pierwszy znalazło się około 1350 roku.", "Anastazja": "<b>Anastazja</b> – żeński odpowiednik <a href=\"https://pl.wikipedia.org/wiki/Imi%C4%99\" target=\"_blank\" rel=\"noopener noreferrer\">imienia</a> <a href=\"https://pl.wikipedia.org/wiki/Anastazy\" target=\"_blank\" rel=\"noopener noreferrer\">Anastazy</a>. Oznacza „zmartwychwstała, wskrzeszona”.", "Aldona": "<b>Aldona</b> – <a href=\"https://pl.wikipedia.org/wiki/Imi%C4%99\" target=\"_blank\" rel=\"noopener noreferrer\">imię</a> żeńskie, pochodzi ono od staropruskiego miana <i>Aldegut</i> lub białoruskiego <i>Ałdonia</i>, będącego przekształceniem greckiego imienia <a href=\"https://pl.wikipedia.org/wiki/Eudoksja_(imi%C4%99)\" target=\"_blank\" rel=\"noopener noreferrer\">Eudokia</a> (Eudocja). Nosiło je wiele księżniczek litewskich wydawanych za polskich książąt (głównie mazowieckich).", "Aurelia": "<b>Aurelia</b> – imię żeńskie pochodzące od nazwy rzymskiego rodu Aurelia, która z kolei pochodzi od <a href=\"https://pl.wikipedia.org/wiki/%C5%81acina\" target=\"_blank\" rel=\"noopener noreferrer\">łac.</a>&#160;<em>aureolus</em> – „złocisty, złoty”, co mogło znaczyć także „wspaniały”.", "Andżelika": "<b>Angelika</b> – <a href=\"https://pl.wikipedia.org/wiki/Imi%C4%99\" target=\"_blank\" rel=\"noopener noreferrer\">imię</a> żeńskie pochodzenia <a href=\"https://pl.wikipedia.org/wiki/%C5%81acina\" target=\"_blank\" rel=\"noopener noreferrer\">łacińskiego</a>, w języku łacińskim oznacza „anielica”, „posłanka”.", "Apolonia": "<b>Apolonia</b> – imię żeńskie pochodzenia <a href=\"https://pl.wikipedia.org/wiki/J%C4%99zyk_grecki\" target=\"_blank\" rel=\"noopener noreferrer\">greckiego</a>, oznaczające osobę należącą do boga <a href=\"https://pl.wikipedia.org/wiki/Apollo\" target=\"_blank\" rel=\"noopener noreferrer\">Apolla</a>. W <a href=\"https://pl.wikipedia.org/wiki/Staro%C5%BCytno%C5%9B%C4%87\" target=\"_blank\" rel=\"noopener noreferrer\">starożytności</a> mogło także pochodzić od nazwy miasta (dotyczy wyzwoleńców).", "Adela": "<b>Adela</b> – imię żeńskie pochodzenia germańskiego. Jest ono skróconą formą dwuczłonowych imion takich jak Adalberga, <a href=\"https://pl.wikipedia.org/wiki/Adalgunda\" target=\"_blank\" rel=\"noopener noreferrer\">Adalgunda</a>, <a href=\"https://pl.wikipedia.org/wiki/Adelajda_(imi%C4%99)\" target=\"_blank\" rel=\"noopener noreferrer\">Adelajda</a>, <a href=\"https://pl.wikipedia.org/wiki/Adelinda\" target=\"_blank\" rel=\"noopener noreferrer\">Adelinda</a>, tj. imion z pierwszym członem <i>adal</i> oznaczającym „szlachetny ród”, „szlachetny stan”. Skrócenie to powstało na gruncie <a href=\"https://pl.wikipedia.org/wiki/J%C4%99zyk_francuski\" target=\"_blank\" rel=\"noopener noreferrer\">języka francuskiego</a>.", "Arleta": "<b>Arleta</b>, <b>Arletta</b> – imię żeńskie zapożyczone z francuskiego; powstało prawdopodobnie jako zdrobnienie germańskiego imienia <i>Carletta</i> (<i>Karletta</i>), żeńskiej formy imienia Karl (<a href=\"https://pl.wikipedia.org/wiki/Karol\" target=\"_blank\" rel=\"noopener noreferrer\">Karol</a>).", "Alfreda": "<b>Alfreda</b> – żeński odpowiednik <a href=\"https://pl.wikipedia.org/wiki/Imi%C4%99\" target=\"_blank\" rel=\"noopener noreferrer\">imienia</a> <a href=\"https://pl.wikipedia.org/wiki/Alfred\" target=\"_blank\" rel=\"noopener noreferrer\">Alfred</a>.", "Amanda": "<b>Amanda</b> – <a href=\"https://pl.wikipedia.org/wiki/Imi%C4%99\" target=\"_blank\" rel=\"noopener noreferrer\">imię</a> żeńskie pochodzenia <a href=\"https://pl.wikipedia.org/wiki/%C5%81acina\" target=\"_blank\" rel=\"noopener noreferrer\">łacińskiego</a>, stanowiące żeński odpowiednik imienia <a href=\"https://pl.wikipedia.org/wiki/Amand_(imi%C4%99)\" target=\"_blank\" rel=\"noopener noreferrer\">Amand</a>, wywodzące się od czasownika <i>amare</i> – „kochać” i oznaczające „ta, która powinna być kochana” lub „godna miłości”. Znane w <a href=\"https://pl.wikipedia.org/wiki/Staro%C5%BCytny_Rzym\" target=\"_blank\" rel=\"noopener noreferrer\">starożytnym Rzymie</a>. W Niemczech rozpowszechnione w początkach XIX wieku. W <a href=\"https://pl.wikipedia.org/wiki/Stany_Zjednoczone\" target=\"_blank\" rel=\"noopener noreferrer\">Stanach Zjednoczonych</a> nadawane często. W Polsce notowane co najmniej od II połowy <a href=\"https://pl.wikipedia.org/wiki/XVIII_wiek\" target=\"_blank\" rel=\"noopener noreferrer\">XVIII wieku</a>, a w średniowieczu znana była tylko męska forma Amandus(z). Imię nadal rzadkie w Polsce. W styczniu 2025 r. w rejestrze <a href=\"https://pl.wikipedia.org/wiki/PESEL\" target=\"_blank\" rel=\"noopener noreferrer\">PESEL</a>, wśród publicznie dostępnych danych dotyczących osób żyjących, wykazano 5766 kobiet o imieniu Amanda nadanym jako imię pierwsze.", "Adelajda": "<b>Adelajda</b> – <a href=\"https://pl.wikipedia.org/wiki/Imi%C4%99\" target=\"_blank\" rel=\"noopener noreferrer\">imię</a> żeńskie pochodzenia <a href=\"https://pl.wikipedia.org/wiki/J%C4%99zyki_germa%C5%84skie\" target=\"_blank\" rel=\"noopener noreferrer\">germańskiego</a>. Składa się z elementów <i>adal</i> \"ród, ród szlachetny\" i <i>heit</i> \"osoba, stan, rodzaj\" i oznaczać mogło osobę wywodzącą się ze szlachetnego rodu.", "Angela": "<b>Angela</b> – imię pochodzi od <a href=\"https://pl.wikipedia.org/wiki/%C5%81acina\" target=\"_blank\" rel=\"noopener noreferrer\">łacińskiego</a> imienia <i>Angel</i>, które powstało od <a href=\"https://pl.wikipedia.org/wiki/J%C4%99zyk_grecki\" target=\"_blank\" rel=\"noopener noreferrer\">greckiego</a> słowa ángelos \"posłaniec\". Imię to też zostało przyswojone w postaci <a href=\"https://pl.wikipedia.org/wiki/Aniela\" target=\"_blank\" rel=\"noopener noreferrer\">Aniela</a>, od niego powstały też imiona <a href=\"https://pl.wikipedia.org/wiki/Angelika\" target=\"_blank\" rel=\"noopener noreferrer\">Angelika</a> i <a href=\"https://pl.wikipedia.org/wiki/Angelina\" target=\"_blank\" rel=\"noopener noreferrer\">Angelina</a>. Jest żeńskim odpowiednikiem imienia <a href=\"https://pl.wikipedia.org/wiki/Anio%C5%82_(imi%C4%99)\" target=\"_blank\" rel=\"noopener noreferrer\">Anioł (Angel)</a>. W ostatnich czasach zapis imienia Angela bywa spolszczany i występuje w formie Andżela lub nawet <i>Andrzela</i> (część osób błędnie wywodzi jej <a href=\"https://pl.wikipedia.org/wiki/Etymologia\" target=\"_blank\" rel=\"noopener noreferrer\">źródłosłów</a> od imienia męskiego <a href=\"https://pl.wikipedia.org/wiki/Andrzej\" target=\"_blank\" rel=\"noopener noreferrer\">Andrzej</a>). Ta druga wersja jest niepoprawna.", "Adelina": "<b>Adelina</b> – <a href=\"https://pl.wikipedia.org/wiki/Imi%C4%99\" target=\"_blank\" rel=\"noopener noreferrer\">imię</a> żeńskie pochodzenia <a href=\"https://pl.wikipedia.org/wiki/Germanie\" target=\"_blank\" rel=\"noopener noreferrer\">germańskiego</a>, utworzone za pomocą zdrabniającego przyrostka <i>-ina</i> od imienia <a href=\"https://pl.wikipedia.org/wiki/Adela\" target=\"_blank\" rel=\"noopener noreferrer\">Adela</a>.", "Arletta": "<b>Arleta</b>, <b>Arletta</b> – imię żeńskie zapożyczone z francuskiego; powstało prawdopodobnie jako zdrobnienie germańskiego imienia <i>Carletta</i> (<i>Karletta</i>), żeńskiej formy imienia Karl (<a href=\"https://pl.wikipedia.org/wiki/Karol\" target=\"_blank\" rel=\"noopener noreferrer\">Karol</a>).", "Aurora": "<b>Aurora</b> – <a href=\"https://pl.wikipedia.org/wiki/Imi%C4%99\" target=\"_blank\" rel=\"noopener noreferrer\">imię</a> żeńskie pochodzenia <a href=\"https://pl.wikipedia.org/wiki/%C5%81acina\" target=\"_blank\" rel=\"noopener noreferrer\">łacińskiego</a> oznaczające „zorzę poranną, jutrzenkę”. Imię pochodzi od bogini <a href=\"https://pl.wikipedia.org/wiki/Aurora_(mitologia)\" target=\"_blank\" rel=\"noopener noreferrer\">Aurory</a>, identyfikowanej później z grecką <a href=\"https://pl.wikipedia.org/wiki/Eos_(mitologia)\" target=\"_blank\" rel=\"noopener noreferrer\">Eos</a>.", "Ariana": "<b>Ariana</b> – żeński odpowiednik imienia <a href=\"https://pl.wikipedia.org/wiki/Arian\" target=\"_blank\" rel=\"noopener noreferrer\">Arian</a> pochodzenia <a href=\"https://pl.wikipedia.org/wiki/%C5%81acina\" target=\"_blank\" rel=\"noopener noreferrer\">łacińskiego</a>. Arianna, Ariana, Ariane w jęz. angielskim, francuskim i włoskim to odpowiedniki imienia <a href=\"https://pl.wikipedia.org/wiki/Ariadna_(imi%C4%99)\" target=\"_blank\" rel=\"noopener noreferrer\">Ariadna</a>.", "Alicia": "<b>Alicia</b> – <a href=\"https://pl.wikipedia.org/wiki/Imi%C4%99\" target=\"_blank\" rel=\"noopener noreferrer\">imię</a> żeńskie pochodzenia <a href=\"https://pl.wikipedia.org/wiki/Hiszpania\" target=\"_blank\" rel=\"noopener noreferrer\">hiszpańskiego</a>.", "Amalia": "Odpowiedniki w innych językach:", "Anika": "<b>Anika</b> – <a href=\"https://pl.wikipedia.org/wiki/Imi%C4%99\" target=\"_blank\" rel=\"noopener noreferrer\">imię</a> żeńskie, jedna ze zdrobniałych form imienia <a href=\"https://pl.wikipedia.org/wiki/Anna\" target=\"_blank\" rel=\"noopener noreferrer\">Anna</a> m.in. w jęz. duńskim i holenderskim.", "Augustyna": "<b>Augustyna</b> – żeński odpowiednik <a href=\"https://pl.wikipedia.org/wiki/Imi%C4%99\" target=\"_blank\" rel=\"noopener noreferrer\">imienia</a> <a href=\"https://pl.wikipedia.org/wiki/Augustyn\" target=\"_blank\" rel=\"noopener noreferrer\">Augustyn</a>.", "Aida": "<b>Aida</b> – <a href=\"https://pl.wikipedia.org/wiki/Imi%C4%99\" target=\"_blank\" rel=\"noopener noreferrer\">imię</a> żeńskie o niejasnym pochodzeniu, być może arabskim albo greckim lub twór literacki.", "Arianna": "<b>Ariadna</b> – <a href=\"https://pl.wikipedia.org/wiki/Imi%C4%99\" target=\"_blank\" rel=\"noopener noreferrer\">imię</a> żeńskie pochodzenia <a href=\"https://pl.wikipedia.org/wiki/J%C4%99zyk_grecki\" target=\"_blank\" rel=\"noopener noreferrer\">greckiego</a> (<i>Ἀριάδνη</i> gr. <i>ari</i> – „naj”, <i>adne</i> – „czysta, święta, szlachetna”). Patronką tego imienia jest św. <a href=\"https://pl.wikipedia.org/wiki/Ariadna_(m%C4%99czennica)\" target=\"_blank\" rel=\"noopener noreferrer\">Ariadna</a> z <a href=\"https://pl.wikipedia.org/wiki/Frygia\" target=\"_blank\" rel=\"noopener noreferrer\">Frygii</a> (zm. w roku 130).", "Astrid": "<b>Astryda</b> – <a href=\"https://pl.wikipedia.org/wiki/Imi%C4%99\" target=\"_blank\" rel=\"noopener noreferrer\">imię</a> żeńskie pochodzenia <a href=\"https://pl.wikipedia.org/wiki/J%C4%99zyki_germa%C5%84skie\" target=\"_blank\" rel=\"noopener noreferrer\">germańskiego</a>, złożone ze <a href=\"https://pl.wikipedia.org/wiki/J%C4%99zyk_staronordyjski\" target=\"_blank\" rel=\"noopener noreferrer\">staronorweskich</a> wyrazów <i>áss</i> – „bóg” i <i>fríðr</i> – „piękna” (mogło zatem oznaczać „piękna jak bóg”). Patronką tego imienia jest bł. Astryda.", "Andżelina": "<b>Angelina</b> – forma pochodna <a href=\"https://pl.wikipedia.org/wiki/Imi%C4%99\" target=\"_blank\" rel=\"noopener noreferrer\">imion</a> <a href=\"https://pl.wikipedia.org/wiki/Aniela\" target=\"_blank\" rel=\"noopener noreferrer\">Aniela</a>, <a href=\"https://pl.wikipedia.org/wiki/Angela\" target=\"_blank\" rel=\"noopener noreferrer\">Angela</a>.", "Adamina": "<b>Adamina</b> – żeński odpowiednik <a href=\"https://pl.wikipedia.org/wiki/Imi%C4%99\" target=\"_blank\" rel=\"noopener noreferrer\">imienia</a>/<a href=\"https://pl.wikipedia.org/wiki/Nazwisko\" target=\"_blank\" rel=\"noopener noreferrer\">nazwiska</a> <a href=\"https://pl.wikipedia.org/wiki/Adam\" target=\"_blank\" rel=\"noopener noreferrer\">Adam</a>. <a href=\"https://pl.wikipedia.org/wiki/Imieniny\" target=\"_blank\" rel=\"noopener noreferrer\">Imieniny</a> 6 kwietnia, <a href=\"https://pl.wikipedia.org/wiki/16_maja\" target=\"_blank\" rel=\"noopener noreferrer\">16 maja</a> i <a href=\"https://pl.wikipedia.org/wiki/24_grudnia\" target=\"_blank\" rel=\"noopener noreferrer\">24 grudnia</a>. Imię pochodzi z języka <a href=\"https://pl.wikipedia.org/wiki/J%C4%99zyk_hebrajski\" target=\"_blank\" rel=\"noopener noreferrer\">hebrajskiego</a> i oznacza ono \"człowiek\", a w znaczeniu biblijnym \"pierwszy człowiek od <a href=\"https://pl.wikipedia.org/wiki/B%C3%B3g_Ojciec\" target=\"_blank\" rel=\"noopener noreferrer\">Boga</a>\".", "Augusta": "<b>Augusta</b> – imię łacińskiego pochodzenia, żeński odpowiednik <a href=\"https://pl.wikipedia.org/wiki/Imi%C4%99\" target=\"_blank\" rel=\"noopener noreferrer\">imienia</a> <a href=\"https://pl.wikipedia.org/wiki/August_(imi%C4%99)\" target=\"_blank\" rel=\"noopener noreferrer\">August</a>. W Polsce rzadko używane.", "Aniceta": "<b>Aniceta</b> – żeński odpowiednik <a href=\"https://pl.wikipedia.org/wiki/Imi%C4%99\" target=\"_blank\" rel=\"noopener noreferrer\">imienia</a> <a href=\"https://pl.wikipedia.org/wiki/Anicet\" target=\"_blank\" rel=\"noopener noreferrer\">Anicet</a>, które z kolei jest zlatynizowaną formą greckiego imienia Aniketos (Ἀνίκητος) oznaczającego „niepokonany”. Jego patronem jest m.in. jeden z wczesnych <a href=\"https://pl.wikipedia.org/wiki/Papie%C5%BC\" target=\"_blank\" rel=\"noopener noreferrer\">papieży</a>, <a href=\"https://pl.wikipedia.org/wiki/Anicet_(papie%C5%BC)\" target=\"_blank\" rel=\"noopener noreferrer\">św. Anicet</a>.", "Anja": "<b>Anna</b>, <b>Hanna</b> (<a href=\"https://pl.wikipedia.org/wiki/J%C4%99zyk_hebrajski\" target=\"_blank\" rel=\"noopener noreferrer\">hebr.</a>&#160;&#8207;חַנָּה&#8206; <i>hannāh</i> – „łaska”) – <a href=\"https://pl.wikipedia.org/wiki/Imi%C4%99\" target=\"_blank\" rel=\"noopener noreferrer\">imię</a> żeńskie pochodzenia <a href=\"https://pl.wikipedia.org/wiki/J%C4%99zyk_hebrajski\" target=\"_blank\" rel=\"noopener noreferrer\">hebrajskiego</a>, które tłumaczy się jako „pełna wdzięku, łaski”.", "Aya": "<b>Aya</b>&#32;(<a href=\"https://pl.wikipedia.org/wiki/J%C4%99zyk_japo%C5%84ski\" target=\"_blank\" rel=\"noopener noreferrer\">jap.</a>&#32;あや, アカネ) – żeńskie <a href=\"https://pl.wikipedia.org/wiki/Imiona_japo%C5%84skie\" target=\"_blank\" rel=\"noopener noreferrer\">imię japońskie</a>.", "Arlena": "<b>Arlena</b> – <a href=\"https://pl.wikipedia.org/wiki/Imi%C4%99\" target=\"_blank\" rel=\"noopener noreferrer\">imię</a> żeńskie, którego pochodzenie jest niepewne. Być może wywodzi się od <i>Arlene</i>, co oznacza w <a href=\"https://pl.wikipedia.org/wiki/J%C4%99zyk_irlandzki\" target=\"_blank\" rel=\"noopener noreferrer\">języku irlandzkim</a> „gwarancję, zobowiązanie”. Imię to może być też skróconą formą imion żeńskich kończących się na -arlena, np. <a href=\"https://pl.wikipedia.org/wiki/Marlena\" target=\"_blank\" rel=\"noopener noreferrer\">Marlena</a>. Istnieje też hipoteza, jakoby imię to miało być wariantem <i>Arline</i>, imienia prawdopodobnie wymyślonego przez mało znanego kompozytora irlandzkiego <a href=\"https://pl.wikipedia.org/wiki/Michael_William_Balfe\" target=\"_blank\" rel=\"noopener noreferrer\">Michaela Williama Balfego</a> dla głównej bohaterki najbardziej znanej jego opery „Czeszka” (<i>The Bohemian girl</i>).", "Ałła": "<b>Alla</b>, <i>Ałła</i> – <a href=\"https://pl.wikipedia.org/wiki/Imi%C4%99\" target=\"_blank\" rel=\"noopener noreferrer\">imię</a> żeńskie prawdopodobnie pochodzenia <a href=\"https://pl.wikipedia.org/wiki/J%C4%99zyk_grecki\" target=\"_blank\" rel=\"noopener noreferrer\">greckiego</a> i wywodzące się od <a href=\"https://pl.wikipedia.org/wiki/J%C4%99zyk_grecki\" target=\"_blank\" rel=\"noopener noreferrer\">gr.</a>&#160;άλλη – „inna”. Używane przede wszystkim w Rosji, na <a href=\"https://pl.wikipedia.org/wiki/Bia%C5%82oru%C5%9B\" target=\"_blank\" rel=\"noopener noreferrer\">Białorusi</a> i <a href=\"https://pl.wikipedia.org/wiki/Ukraina\" target=\"_blank\" rel=\"noopener noreferrer\">Ukrainie</a>.", "Alojza": "<b>Alojza</b>, <b>Alojzja</b> – imię żeńskie pochodzenia germańskiego.", "Albertyna": "<b>Albertyna</b> – żeński odpowiednik <a href=\"https://pl.wikipedia.org/wiki/Imi%C4%99\" target=\"_blank\" rel=\"noopener noreferrer\">imienia</a> <a href=\"https://pl.wikipedia.org/wiki/Albert_(imi%C4%99)\" target=\"_blank\" rel=\"noopener noreferrer\">Albert</a>, pierwotnie zdrobnienie od żeńskiego imienia <a href=\"https://pl.wikipedia.org/wiki/Alberta_(imi%C4%99)\" target=\"_blank\" rel=\"noopener noreferrer\">Alberta</a>. Patronką tego imienia jest bł. <a href=\"https://pl.wikipedia.org/wiki/Albertyna_Berkenbrock\" target=\"_blank\" rel=\"noopener noreferrer\">Albertyna Berkenbrock</a>.", "Atena": "<b>Atena</b> (<a href=\"https://pl.wikipedia.org/wiki/J%C4%99zyk_grecki\" target=\"_blank\" rel=\"noopener noreferrer\">gr.</a> Ἀθηνή Athene, Ἀθηναίη Athenaie, <a href=\"https://pl.wikipedia.org/wiki/%C5%81acina\" target=\"_blank\" rel=\"noopener noreferrer\">łac.</a> Minerva) – w <a href=\"https://pl.wikipedia.org/wiki/Mitologia_grecka\" target=\"_blank\" rel=\"noopener noreferrer\">mitologii greckiej</a> bogini <a href=\"https://pl.wikipedia.org/wiki/M%C4%85dro%C5%9B%C4%87\" target=\"_blank\" rel=\"noopener noreferrer\">mądrości</a>, <a href=\"https://pl.wikipedia.org/wiki/Sztuka\" target=\"_blank\" rel=\"noopener noreferrer\">sztuki</a>, sprawiedliwej wojny oraz opiekunka miast, m.in. <a href=\"https://pl.wikipedia.org/wiki/Ateny\" target=\"_blank\" rel=\"noopener noreferrer\">Aten</a> i <a href=\"https://pl.wikipedia.org/wiki/Sparta\" target=\"_blank\" rel=\"noopener noreferrer\">Sparty</a>. Jest jedną z dwunastu głównych bogów olimpijskich. Jej atrybutami są: włócznia, tarcza i łuk. Jej świętym zwierzęciem jest <a href=\"https://pl.wikipedia.org/wiki/Sowa_Ateny\" target=\"_blank\" rel=\"noopener noreferrer\">sowa</a>, a rośliną – oliwka. Jej rzymskim odpowiednikiem jest <a href=\"https://pl.wikipedia.org/wiki/Minerwa\" target=\"_blank\" rel=\"noopener noreferrer\">Minerwa</a>.", "Adolfina": "<b>Adolfina</b> – żeński odpowiednik (obok <a href=\"https://pl.wikipedia.org/wiki/Adolfa\" target=\"_blank\" rel=\"noopener noreferrer\">Adolfy</a>) <a href=\"https://pl.wikipedia.org/wiki/Imi%C4%99\" target=\"_blank\" rel=\"noopener noreferrer\">imienia</a> <a href=\"https://pl.wikipedia.org/wiki/Adolf\" target=\"_blank\" rel=\"noopener noreferrer\">Adolf</a>.", "Anatola": "<b>Anatolia</b>, <b>Anatola</b> – <a href=\"https://pl.wikipedia.org/wiki/Imi%C4%99\" target=\"_blank\" rel=\"noopener noreferrer\">imię</a> żeńskie pochodzenia <a href=\"https://pl.wikipedia.org/wiki/J%C4%99zyk_grecki\" target=\"_blank\" rel=\"noopener noreferrer\">greckiego</a>, oznaczające \"pochodząca ze wschodu, wschodnia\".", "Alana": "<b>Alana</b> – <a href=\"https://pl.wikipedia.org/wiki/Imi%C4%99\" target=\"_blank\" rel=\"noopener noreferrer\">imię</a> żeńskie pochodzenia <a href=\"https://pl.wikipedia.org/wiki/Celtowie\" target=\"_blank\" rel=\"noopener noreferrer\">celtyckiego</a>, odpowiednik męski: <a href=\"https://pl.wikipedia.org/wiki/Alan\" target=\"_blank\" rel=\"noopener noreferrer\">Alan</a>.", "Andżela": "<b>Angela</b> – imię pochodzi od <a href=\"https://pl.wikipedia.org/wiki/%C5%81acina\" target=\"_blank\" rel=\"noopener noreferrer\">łacińskiego</a> imienia <i>Angel</i>, które powstało od <a href=\"https://pl.wikipedia.org/wiki/J%C4%99zyk_grecki\" target=\"_blank\" rel=\"noopener noreferrer\">greckiego</a> słowa ángelos \"posłaniec\". Imię to też zostało przyswojone w postaci <a href=\"https://pl.wikipedia.org/wiki/Aniela\" target=\"_blank\" rel=\"noopener noreferrer\">Aniela</a>, od niego powstały też imiona <a href=\"https://pl.wikipedia.org/wiki/Angelika\" target=\"_blank\" rel=\"noopener noreferrer\">Angelika</a> i <a href=\"https://pl.wikipedia.org/wiki/Angelina\" target=\"_blank\" rel=\"noopener noreferrer\">Angelina</a>. Jest żeńskim odpowiednikiem imienia <a href=\"https://pl.wikipedia.org/wiki/Anio%C5%82_(imi%C4%99)\" target=\"_blank\" rel=\"noopener noreferrer\">Anioł (Angel)</a>. W ostatnich czasach zapis imienia Angela bywa spolszczany i występuje w formie Andżela lub nawet <i>Andrzela</i> (część osób błędnie wywodzi jej <a href=\"https://pl.wikipedia.org/wiki/Etymologia\" target=\"_blank\" rel=\"noopener noreferrer\">źródłosłów</a> od imienia męskiego <a href=\"https://pl.wikipedia.org/wiki/Andrzej\" target=\"_blank\" rel=\"noopener noreferrer\">Andrzej</a>). Ta druga wersja jest niepoprawna.", "Anfisa": "<b>Antuza</b> – <a href=\"https://pl.wikipedia.org/wiki/Imi%C4%99\" target=\"_blank\" rel=\"noopener noreferrer\">imię</a> żeńskie pochodzenia <a href=\"https://pl.wikipedia.org/wiki/J%C4%99zyk_grecki\" target=\"_blank\" rel=\"noopener noreferrer\">greckiego</a>, od gr. <i>Ανθουσα (Anthousa)</i>, które pochodzi od słowa <i>ανθος (anthos)</i> – „kwiat”. Patronką tego imienia jest św. Antuza (ur. 751 w <a href=\"https://pl.wikipedia.org/wiki/Konstantynopol\" target=\"_blank\" rel=\"noopener noreferrer\">Konstantynopolu</a>, zm. 801 także).", "Ariela": "<b>Ariela</b> – żeński odpowiednik imienia <a href=\"https://pl.wikipedia.org/wiki/Ariel_(imi%C4%99)\" target=\"_blank\" rel=\"noopener noreferrer\">Ariel</a>. Posiadaczka imienia <a href=\"https://pl.wikipedia.org/wiki/Imieniny\" target=\"_blank\" rel=\"noopener noreferrer\">imieniny</a> obchodzi <a href=\"https://pl.wikipedia.org/wiki/16_listopada\" target=\"_blank\" rel=\"noopener noreferrer\">16 listopada</a>.", "Adolfa": "<b>Adolfa</b> – żeński odpowiednik <a href=\"https://pl.wikipedia.org/wiki/Imi%C4%99\" target=\"_blank\" rel=\"noopener noreferrer\">imienia</a> <a href=\"https://pl.wikipedia.org/wiki/Adolf\" target=\"_blank\" rel=\"noopener noreferrer\">Adolf</a> (o znaczeniu „szlachetny wilk”).", "Anabella": "<b>Anabella</b> — <a href=\"https://pl.wikipedia.org/wiki/Imi%C4%99\" target=\"_blank\" rel=\"noopener noreferrer\">imię</a> utworzone wtórnie na gruncie anglosaskim spopularyzowane w literaturze i mediach. Imię to pochodzi od złożenia dwóch innych: Anny, z hebrajskiego <i>hannah</i> – pełna łaski i Izabeli – hiszpańskiej wersji imienia Isabel - (Jezabel) pochodzącej od hebrajskiego Eliszebeth od którego pochodzi także Elżbieta. W Polsce imię to pojawiło się razem z wpływami francuskimi (Izabelle) - <i>belle</i> po francusku znaczy piękna.", "Areta": "<b>Areta</b> – <a href=\"https://pl.wikipedia.org/wiki/Imi%C4%99\" target=\"_blank\" rel=\"noopener noreferrer\">imię</a> żeńskie niejasnego pochodzenia. <a href=\"https://pl.wikipedia.org/wiki/J%C3%B3zef_Bubak\" target=\"_blank\" rel=\"noopener noreferrer\">Józef Bubak</a> łączy je ze skróconą formą <a href=\"https://pl.wikipedia.org/wiki/Ma%C5%82gorzata_(imi%C4%99)\" target=\"_blank\" rel=\"noopener noreferrer\">Małgorzaty</a> (niem. <i>Margareta</i>), powstałą na gruncie <a href=\"https://pl.wikipedia.org/wiki/J%C4%99zyk_niemiecki\" target=\"_blank\" rel=\"noopener noreferrer\">niemieckim</a>. Imię to nosiła także <a href=\"https://pl.wikipedia.org/wiki/Arete_(mitologia)\" target=\"_blank\" rel=\"noopener noreferrer\">postać z mitologii greckiej</a>, królowa <a href=\"https://pl.wikipedia.org/wiki/Feakowie\" target=\"_blank\" rel=\"noopener noreferrer\">Feaków</a>, której imię stanowi przymiotnik odczasownikowy od wyrazu <i>αραομαι (araomai)</i> („modlę się o coś, gorąco pragnę”) i oznacza „dziecko upragnione”(por. <a href=\"https://pl.wikipedia.org/wiki/Dezyderia\" target=\"_blank\" rel=\"noopener noreferrer\">Dezyderia</a>, <a href=\"https://pl.wikipedia.org/wiki/Aspazja_(imi%C4%99)\" target=\"_blank\" rel=\"noopener noreferrer\">Aspazja</a>). Można także spotkać się z poglądem, iż imię to pochodzi od greckiego słowa <i>αρετη (<a href=\"https://pl.wikipedia.org/wiki/Aret%C3%A9\" target=\"_blank\" rel=\"noopener noreferrer\">areté</a>)</i> oznaczającego „cnotę”, „męstwo”; Areta stanowiłaby wówczas żeński odpowiednik męskiego imienia <a href=\"https://pl.wikipedia.org/wiki/Aretas\" target=\"_blank\" rel=\"noopener noreferrer\">Aretas</a>.", "Alexa": "<b>Alexa Internet</b>, <b>Alexa</b> – <a href=\"https://pl.wikipedia.org/wiki/Stany_Zjednoczone\" target=\"_blank\" rel=\"noopener noreferrer\">amerykańska</a> spółka, funkcjonująca w latach 1996–2022, kontrolowana przez <a href=\"https://pl.wikipedia.org/wiki/Amazon.com\" target=\"_blank\" rel=\"noopener noreferrer\">Amazon.com</a>, prowadząca witrynę <i>Alexa</i>, która dostarczała informacje na temat ruchu sieciowego na stronach internetowych oraz udostępniała rankingi najpopularniejszych serwisów ostatniego miesiąca. Sam serwis był notowany w tym rankingu na miejscu 3195 (czerwiec 2020).", "Antonella": "<b>Antonella</b> – imię żeńskie, będące <a href=\"https://pl.wikipedia.org/wiki/J%C4%99zyk_w%C5%82oski\" target=\"_blank\" rel=\"noopener noreferrer\">włoskim</a>, <a href=\"https://pl.wikipedia.org/wiki/J%C4%99zyk_hiszpa%C5%84ski\" target=\"_blank\" rel=\"noopener noreferrer\">hiszpańskim</a>, <a href=\"https://pl.wikipedia.org/wiki/J%C4%99zyk_du%C5%84ski\" target=\"_blank\" rel=\"noopener noreferrer\">duńskim</a>, <a href=\"https://pl.wikipedia.org/wiki/J%C4%99zyk_norweski\" target=\"_blank\" rel=\"noopener noreferrer\">norweskim</a> i <a href=\"https://pl.wikipedia.org/wiki/J%C4%99zyk_szwedzki\" target=\"_blank\" rel=\"noopener noreferrer\">szwedzkim</a> <a href=\"https://pl.wikipedia.org/wiki/Zdrobnienie\" target=\"_blank\" rel=\"noopener noreferrer\">zdrobnieniem</a> od imienia <a href=\"https://pl.wikipedia.org/wiki/Antonia\" target=\"_blank\" rel=\"noopener noreferrer\">Antonia</a>. Używane jest głównie w wielu krajach <a href=\"https://pl.wikipedia.org/wiki/Ameryka_Po%C5%82udniowa\" target=\"_blank\" rel=\"noopener noreferrer\">Ameryki Południowej</a> i <a href=\"https://pl.wikipedia.org/wiki/Ameryka_%C5%9Arodkowa\" target=\"_blank\" rel=\"noopener noreferrer\">Środkowej</a>, różnych częściach <a href=\"https://pl.wikipedia.org/wiki/Ameryka_P%C3%B3%C5%82nocna\" target=\"_blank\" rel=\"noopener noreferrer\">Ameryki Północnej</a>, a także we <a href=\"https://pl.wikipedia.org/wiki/W%C5%82ochy\" target=\"_blank\" rel=\"noopener noreferrer\">Włoszech</a>, <a href=\"https://pl.wikipedia.org/wiki/Hiszpania\" target=\"_blank\" rel=\"noopener noreferrer\">Hiszpanii</a> i <a href=\"https://pl.wikipedia.org/wiki/Skandynawia\" target=\"_blank\" rel=\"noopener noreferrer\">krajach skandynawskich</a>. Męskim odpowiednikiem tego imienia jest Antonello.", "Alojzja": "<b>Alojza</b>, <b>Alojzja</b> – imię żeńskie pochodzenia germańskiego.", "Arnika": "<b>Arnika</b> (<i>Arnica</i> <a href=\"https://pl.wikipedia.org/wiki/Karol_Linneusz\" target=\"_blank\" rel=\"noopener noreferrer\">L.</a>) – <a href=\"https://pl.wikipedia.org/wiki/Rodzaj_(biologia)\" target=\"_blank\" rel=\"noopener noreferrer\">rodzaj</a> roślin należących do rodziny <a href=\"https://pl.wikipedia.org/wiki/Astrowate\" target=\"_blank\" rel=\"noopener noreferrer\">astrowatych</a>. Należy do niego 31 gatunków roślin. Przedstawiciele tego rodzaju występują głównie na terenie <a href=\"https://pl.wikipedia.org/wiki/Ameryka_P%C3%B3%C5%82nocna\" target=\"_blank\" rel=\"noopener noreferrer\">Ameryki Północnej</a>, tylko dwa gatunki pochodzą z <a href=\"https://pl.wikipedia.org/wiki/Eurazja\" target=\"_blank\" rel=\"noopener noreferrer\">Eurazji</a> (<i>A. montana</i>, <i>A. angustifolia</i>). Rośliny te rosną głównie w górach, sięgają także strefy arktycznej na północy. We <a href=\"https://pl.wikipedia.org/wiki/Flora_ro%C5%9Blin_naczyniowych_Polski\" target=\"_blank\" rel=\"noopener noreferrer\">florze Polski</a> występuje tylko jeden gatunek – <a href=\"https://pl.wikipedia.org/wiki/Arnika_g%C3%B3rska\" target=\"_blank\" rel=\"noopener noreferrer\">arnika górska</a> <i>Arnica montana</i>.", "Anzelma": "<b>Anzelma</b> (znane też w formie <i>Selma</i>) – żeński odpowiednik <a href=\"https://pl.wikipedia.org/wiki/Imi%C4%99\" target=\"_blank\" rel=\"noopener noreferrer\">imienia</a> <a href=\"https://pl.wikipedia.org/wiki/Anzelm_(imi%C4%99)\" target=\"_blank\" rel=\"noopener noreferrer\">Anzelm</a>. W niektórych krajach jako zdrobnienie od tego imienia funkcjonuje forma Selma.", "Alodia": "<b>Alodia</b> – <a href=\"https://pl.wikipedia.org/wiki/Imi%C4%99\" target=\"_blank\" rel=\"noopener noreferrer\">imię</a> żeńskie, wywodzące się prawdopodobnie od <a href=\"https://pl.wikipedia.org/wiki/Frankowie\" target=\"_blank\" rel=\"noopener noreferrer\">frankońskiego</a> <i>al-ôd</i>, co oznacza \"dziedzictwo, pełne posiadanie\". Imię to łączy się także ze średniowiecznym <a href=\"https://pl.wikipedia.org/wiki/%C5%81acina\" target=\"_blank\" rel=\"noopener noreferrer\">łacińskim</a> wyrazem <i><a href=\"https://pl.wikipedia.org/wiki/Alodium\" target=\"_blank\" rel=\"noopener noreferrer\">allodium</a></i>, który oznaczał \"majątek ziemski wolny od ciężarów i powinności lennych\", a pochodzi również od tego samego wyrazu frankońskiego.", "Anka": "<b>Anna</b>, <b>Hanna</b> (<a href=\"https://pl.wikipedia.org/wiki/J%C4%99zyk_hebrajski\" target=\"_blank\" rel=\"noopener noreferrer\">hebr.</a>&#160;&#8207;חַנָּה&#8206; <i>hannāh</i> – „łaska”) – <a href=\"https://pl.wikipedia.org/wiki/Imi%C4%99\" target=\"_blank\" rel=\"noopener noreferrer\">imię</a> żeńskie pochodzenia <a href=\"https://pl.wikipedia.org/wiki/J%C4%99zyk_hebrajski\" target=\"_blank\" rel=\"noopener noreferrer\">hebrajskiego</a>, które tłumaczy się jako „pełna wdzięku, łaski”.", "Alida": "<b>Adelajda</b> – <a href=\"https://pl.wikipedia.org/wiki/Imi%C4%99\" target=\"_blank\" rel=\"noopener noreferrer\">imię</a> żeńskie pochodzenia <a href=\"https://pl.wikipedia.org/wiki/J%C4%99zyki_germa%C5%84skie\" target=\"_blank\" rel=\"noopener noreferrer\">germańskiego</a>. Składa się z elementów <i>adal</i> \"ród, ród szlachetny\" i <i>heit</i> \"osoba, stan, rodzaj\" i oznaczać mogło osobę wywodzącą się ze szlachetnego rodu.", "Astryda": "<b>Astryda</b> – <a href=\"https://pl.wikipedia.org/wiki/Imi%C4%99\" target=\"_blank\" rel=\"noopener noreferrer\">imię</a> żeńskie pochodzenia <a href=\"https://pl.wikipedia.org/wiki/J%C4%99zyki_germa%C5%84skie\" target=\"_blank\" rel=\"noopener noreferrer\">germańskiego</a>, złożone ze <a href=\"https://pl.wikipedia.org/wiki/J%C4%99zyk_staronordyjski\" target=\"_blank\" rel=\"noopener noreferrer\">staronorweskich</a> wyrazów <i>áss</i> – „bóg” i <i>fríðr</i> – „piękna” (mogło zatem oznaczać „piękna jak bóg”). Patronką tego imienia jest bł. Astryda.", "Alwina": "<b>Alwina</b> – imię żeńskie pochodzenia <a href=\"https://pl.wikipedia.org/wiki/J%C4%99zyki_germa%C5%84skie\" target=\"_blank\" rel=\"noopener noreferrer\">germańskiego</a>. Pochodzi od <a href=\"https://pl.wikipedia.org/wiki/J%C4%99zyk_staroangielski\" target=\"_blank\" rel=\"noopener noreferrer\">staroangielskiego</a> imienia <b>Ælfwine</b> (<i>przyjaciel <a href=\"https://pl.wikipedia.org/wiki/Elf_(fantastyka)\" target=\"_blank\" rel=\"noopener noreferrer\">elfów</a></i>). <b>Alwina</b> jest również skróconą formą imienia <a href=\"https://pl.wikipedia.org/wiki/Adalwina\" target=\"_blank\" rel=\"noopener noreferrer\">Adalwina</a>.", "Andrzeja": "<b>Andrzeja</b>, <b>Ondrzeja</b>, <b>Anda</b> – polskie <a href=\"https://pl.wikipedia.org/wiki/Imi%C4%99\" target=\"_blank\" rel=\"noopener noreferrer\">imię</a> żeńskie pochodzące od imienia męskiego <a href=\"https://pl.wikipedia.org/wiki/Andrzej\" target=\"_blank\" rel=\"noopener noreferrer\">Andrzej</a>. Dzisiaj raczej rzadko spotykane (według materiałów Instytutu Języka Polskiego <a href=\"https://pl.wikipedia.org/wiki/Polska_Akademia_Nauk\" target=\"_blank\" rel=\"noopener noreferrer\">PAN</a> w roku <a href=\"https://pl.wikipedia.org/wiki/1998\" target=\"_blank\" rel=\"noopener noreferrer\">1998</a> imię to nosiło 78 mieszkanek Polski). Imię było bardziej popularne w <a href=\"https://pl.wikipedia.org/wiki/%C5%9Aredniowiecze\" target=\"_blank\" rel=\"noopener noreferrer\">średniowieczu</a>.", "Anda": "<b>Andrzeja</b>, <b>Ondrzeja</b>, <b>Anda</b> – polskie <a href=\"https://pl.wikipedia.org/wiki/Imi%C4%99\" target=\"_blank\" rel=\"noopener noreferrer\">imię</a> żeńskie pochodzące od imienia męskiego <a href=\"https://pl.wikipedia.org/wiki/Andrzej\" target=\"_blank\" rel=\"noopener noreferrer\">Andrzej</a>. Dzisiaj raczej rzadko spotykane (według materiałów Instytutu Języka Polskiego <a href=\"https://pl.wikipedia.org/wiki/Polska_Akademia_Nauk\" target=\"_blank\" rel=\"noopener noreferrer\">PAN</a> w roku <a href=\"https://pl.wikipedia.org/wiki/1998\" target=\"_blank\" rel=\"noopener noreferrer\">1998</a> imię to nosiło 78 mieszkanek Polski). Imię było bardziej popularne w <a href=\"https://pl.wikipedia.org/wiki/%C5%9Aredniowiecze\" target=\"_blank\" rel=\"noopener noreferrer\">średniowieczu</a>.", "Asenata": "<b>Asenata</b> – pochodzące z <a href=\"https://pl.wikipedia.org/wiki/Biblia\" target=\"_blank\" rel=\"noopener noreferrer\">Biblii</a> <a href=\"https://pl.wikipedia.org/wiki/Imi%C4%99\" target=\"_blank\" rel=\"noopener noreferrer\">imię</a> żeńskie pochodzenia egipskiego, oznaczające prawdopodobnie \"ta, która należy do swojego ojca\".", "Agrypina": "<b>Agrypina, Agryppina</b> (<a href=\"https://pl.wikipedia.org/wiki/J%C4%99zyk_grecki\" target=\"_blank\" rel=\"noopener noreferrer\">gr.</a> <i>Αγριππίνα)</i> – <a href=\"https://pl.wikipedia.org/wiki/Imi%C4%99\" target=\"_blank\" rel=\"noopener noreferrer\">imię</a> żeńskie pochodzenia <a href=\"https://pl.wikipedia.org/wiki/J%C4%99zyk_grecki\" target=\"_blank\" rel=\"noopener noreferrer\">greckiego</a>. Oznacza 'należąca do <a href=\"https://pl.wikipedia.org/wiki/Agryppa_(imi%C4%99)\" target=\"_blank\" rel=\"noopener noreferrer\">Agryppy</a>'. Żeński odpowiednik imienia <a href=\"https://pl.wikipedia.org/wiki/Agrypin\" target=\"_blank\" rel=\"noopener noreferrer\">Agrypin</a>. Wśród świętych m.in. <a href=\"https://pl.wikipedia.org/wiki/Agrypina_(%C5%9Bwi%C4%99ta)\" target=\"_blank\" rel=\"noopener noreferrer\">św. Agrypina</a>, męczennica, z <a href=\"https://pl.wikipedia.org/wiki/III_wiek\" target=\"_blank\" rel=\"noopener noreferrer\">III wieku</a>.", "Aranka": "<b>Aurelia</b> – imię żeńskie pochodzące od nazwy rzymskiego rodu Aurelia, która z kolei pochodzi od <a href=\"https://pl.wikipedia.org/wiki/%C5%81acina\" target=\"_blank\" rel=\"noopener noreferrer\">łac.</a>&#160;<em>aureolus</em> – „złocisty, złoty”, co mogło znaczyć także „wspaniały”.", "Amrita": "<b>Amryta</b> (<a href=\"https://pl.wikipedia.org/wiki/Pismo_dewanagari\" target=\"_blank\" rel=\"noopener noreferrer\">dewanagari</a> अमृत, pali amata; tyb. dutsi; jap. kanro, <a href=\"https://pl.wikipedia.org/wiki/J%C4%99zyk_angielski\" target=\"_blank\" rel=\"noopener noreferrer\">ang.</a> amrita) – w <a href=\"https://pl.wikipedia.org/wiki/Hinduizm\" target=\"_blank\" rel=\"noopener noreferrer\">hinduizmie</a> boski napój dający pijącemu nieśmiertelność; <a href=\"https://pl.wikipedia.org/wiki/Indie\" target=\"_blank\" rel=\"noopener noreferrer\">indyjski</a> odpowiednik greckiego <a href=\"https://pl.wikipedia.org/wiki/Nektar_(mitologia)\" target=\"_blank\" rel=\"noopener noreferrer\">nektaru</a>. Termin pojawiający się często w <a href=\"https://pl.wikipedia.org/wiki/Wedy\" target=\"_blank\" rel=\"noopener noreferrer\">Wedach</a> oraz tekstach buddyjskich. Niebiański napój <a href=\"https://pl.wikipedia.org/wiki/Dewa\" target=\"_blank\" rel=\"noopener noreferrer\">dewów</a> i <a href=\"https://pl.wikipedia.org/wiki/Dewi\" target=\"_blank\" rel=\"noopener noreferrer\">dewi</a> dający nieśmiertelność lub inne moce oraz usuwający cierpienie.", "Asteria": "<b>Asteria</b> – żeński odpowiednik łacińskiego <a href=\"https://pl.wikipedia.org/wiki/Imi%C4%99\" target=\"_blank\" rel=\"noopener noreferrer\">imienia</a> <a href=\"https://pl.wikipedia.org/wiki/Asteriusz\" target=\"_blank\" rel=\"noopener noreferrer\">Asteriusz</a>. Patronką tego imienia jest św. Asteria, zm. w 310 roku.", "Akiko": "<b>Akiko</b>&#32;(<a href=\"https://pl.wikipedia.org/wiki/J%C4%99zyk_japo%C5%84ski\" target=\"_blank\" rel=\"noopener noreferrer\">jap.</a>&#32;あきこ, アキコ) – żeńskie <a href=\"https://pl.wikipedia.org/wiki/Imiona_japo%C5%84skie\" target=\"_blank\" rel=\"noopener noreferrer\">imię japońskie</a>.", "Andromeda": "<b>Andromeda</b> – <a href=\"https://pl.wikipedia.org/wiki/Imi%C4%99\" target=\"_blank\" rel=\"noopener noreferrer\">imię</a> żeńskie pochodzenia <a href=\"https://pl.wikipedia.org/wiki/J%C4%99zyk_grecki\" target=\"_blank\" rel=\"noopener noreferrer\">greckiego</a>. Wywodzi się z <a href=\"https://pl.wikipedia.org/wiki/Mitologia_grecka\" target=\"_blank\" rel=\"noopener noreferrer\">mitologii greckiej</a>. Pochodzi od słów <i>andros</i> „człowiek” i <i>medesthai</i> „myśleć”.", "Amadea": "<b>Amadea</b> – żeński odpowiednik <a href=\"https://pl.wikipedia.org/wiki/%C5%81acina\" target=\"_blank\" rel=\"noopener noreferrer\">łacińskiego</a> <a href=\"https://pl.wikipedia.org/wiki/Imi%C4%99\" target=\"_blank\" rel=\"noopener noreferrer\">imienia</a> <a href=\"https://pl.wikipedia.org/wiki/Amadeusz_(imi%C4%99)\" target=\"_blank\" rel=\"noopener noreferrer\">Amadeusz</a>, powstałego w kręgach zakonnych w <a href=\"https://pl.wikipedia.org/wiki/%C5%9Aredniowiecze\" target=\"_blank\" rel=\"noopener noreferrer\">średniowieczu</a>. Oznacza „kochającą Boga”. Podobne znaczenie ma imię <a href=\"https://pl.wikipedia.org/wiki/Teofila\" target=\"_blank\" rel=\"noopener noreferrer\">Teofila</a>.", "Anitta": "Imię Anitty pojawia się w dokumentach pochodzących z asyryjskiej kolonii kupieckiej w Kanesz (hetycka Nesa, obecnie stanowisko Kültepe w <a href=\"https://pl.wikipedia.org/wiki/Turcja\" target=\"_blank\" rel=\"noopener noreferrer\">Turcji</a>). W jednym z tekstów, wymieniającym jako władcę Kanesz/Nesy jego ojca Pithanę, Anitta występuje jako następca tronu i nosi akadyjski tytuł <i>rabi simmiltim</i>. W innym sam nosi już tytuł „władcy” (<a href=\"https://pl.wikipedia.org/wiki/J%C4%99zyk_akadyjski\" target=\"_blank\" rel=\"noopener noreferrer\">akad</a>. <i>rubā'um</i>), a jako <i>rabi simmiltim</i> występuje jego syn <a href=\"https://pl.wikipedia.org/wiki/Peruwa\" target=\"_blank\" rel=\"noopener noreferrer\">Peruwa</a>. Imię Anitty pojawia się też w tekstach z <a href=\"https://pl.wikipedia.org/wiki/Ankuwa\" target=\"_blank\" rel=\"noopener noreferrer\">Ankuwy</a>, w których nosi on tytuł „władcy” (<i>rubā'um</i>) i „wielkiego władcy” (<i>rubā'um rabium</i>), co sugeruje, że zarówno Nesa, jak i Ankuwa znajdowały się pod jego kontrolą. Siedziba Anitty mogła znajdować się w Nesie – wskazują na to zarówno pochodzące stąd teksty, jak i odnaleziony tu sztylet z brązu noszący inskrypcję „pałac Anitty, księcia”.", "Aditi": "W <i>Bryhadajranjakopaniszad</i> (1.2.5) określenie dla oznaczenia <a href=\"https://pl.wikipedia.org/wiki/Absolut\" target=\"_blank\" rel=\"noopener noreferrer\">bytu absolutnego</a>.", "Arietta": "<b>Arietta</b> – <a href=\"https://pl.wikipedia.org/wiki/Forma_muzyczna\" target=\"_blank\" rel=\"noopener noreferrer\">forma muzyczna</a>, <a href=\"https://pl.wikipedia.org/wiki/Aria\" target=\"_blank\" rel=\"noopener noreferrer\">aria</a> o mniejszych rozmiarach, zwykle w formie 2-częściowej lub utwór instrumentalny.", "Adelgunda": "<b>Adalgunda</b>, <b>Adelgunda</b> – <a href=\"https://pl.wikipedia.org/wiki/Imi%C4%99\" target=\"_blank\" rel=\"noopener noreferrer\">imię</a> żeńskie pochodzenia <a href=\"https://pl.wikipedia.org/wiki/J%C4%99zyki_germa%C5%84skie\" target=\"_blank\" rel=\"noopener noreferrer\">germańskiego</a>, składające się z członów <i>adal-</i> // <i>adel-</i> // <i>edel-</i> — \"szlachetny ród\" oraz <i>-gund</i> // <i>-gunt</i> — \"walka, bitwa\". Patronką tego imienia jest <a href=\"https://pl.wikipedia.org/wiki/%C5%9Awi%C4%99ta_Adelgunda\" target=\"_blank\" rel=\"noopener noreferrer\">św. Adelgunda (Aldegunda)</a> — według niektórych źródeł <a href=\"https://pl.wikipedia.org/wiki/Aldegunda\" target=\"_blank\" rel=\"noopener noreferrer\">Aldegunda</a>, imię notowane w Polsce od <a href=\"https://pl.wikipedia.org/wiki/1320\" target=\"_blank\" rel=\"noopener noreferrer\">1320</a> roku, jest wariantem imienia Adalgunda, według innych zaś — odrębnym imieniem o odmiennym znaczeniu.", "Awa": "<b>Ewa</b> – <a href=\"https://pl.wikipedia.org/wiki/Imi%C4%99\" target=\"_blank\" rel=\"noopener noreferrer\">imię</a> żeńskie, które pierwszy raz pojawia się 2000 lat p.n.e. w <a href=\"https://pl.wikipedia.org/wiki/J%C4%99zyk_sumeryjski\" target=\"_blank\" rel=\"noopener noreferrer\">języku sumeryjskim</a> jako „Awa” gdzie oznacza „życie”. W języku hebrajskim, który zapożyczył to imię od Sumerów wywodzi się od rdzenia חוה <i>hajja</i> lub hawwa – i również oznacza ‘dająca życie’. Imię wyprowadzane też z arabskiego słowa <i>hajja</i> ‘wąż’.", "Azalia": "<b>Różanecznik</b>, azalia, rododendron (<i>Rhododendron</i> L.) – <a href=\"https://pl.wikipedia.org/wiki/Rodzaj_(biologia)\" target=\"_blank\" rel=\"noopener noreferrer\">rodzaj</a> <a href=\"https://pl.wikipedia.org/wiki/Ro%C5%9Bliny\" target=\"_blank\" rel=\"noopener noreferrer\">roślin</a> z rodziny <a href=\"https://pl.wikipedia.org/wiki/Wrzosowate\" target=\"_blank\" rel=\"noopener noreferrer\">wrzosowatych</a> (<i>Ericaceae</i>). Obejmuje ponad tysiąc <a href=\"https://pl.wikipedia.org/wiki/Gatunek_(biologia)\" target=\"_blank\" rel=\"noopener noreferrer\">gatunków</a>. W stanie naturalnym występują głównie w <a href=\"https://pl.wikipedia.org/wiki/Azja\" target=\"_blank\" rel=\"noopener noreferrer\">Azji</a>, w mniejszej liczbie gatunków w obydwu <a href=\"https://pl.wikipedia.org/wiki/Ameryka\" target=\"_blank\" rel=\"noopener noreferrer\">Amerykach</a> i w <a href=\"https://pl.wikipedia.org/wiki/Europa\" target=\"_blank\" rel=\"noopener noreferrer\">Europie</a>. Rosną zwykle na obszarach górskich, na glebach próchnicznych i kwaśnych, często także na <a href=\"https://pl.wikipedia.org/wiki/Torfowisko\" target=\"_blank\" rel=\"noopener noreferrer\">torfowiskach</a> i na glebach oraz skałach wapiennych. Zasiedlają lasy, formacje krzewiaste i wrzosowiska. Nieliczne gatunki są <a href=\"https://pl.wikipedia.org/wiki/Epifit\" target=\"_blank\" rel=\"noopener noreferrer\">epifitami</a>. Kwiaty są u części gatunków wonne, u innych nie. <a href=\"https://pl.wikipedia.org/wiki/Zapylenie\" target=\"_blank\" rel=\"noopener noreferrer\">Zapylane</a> są przez <a href=\"https://pl.wikipedia.org/wiki/Owady\" target=\"_blank\" rel=\"noopener noreferrer\">owady</a>, niektóre gatunki w Himalajach także przez <a href=\"https://pl.wikipedia.org/wiki/Ptaki\" target=\"_blank\" rel=\"noopener noreferrer\">ptaki</a>.", "Anahita": "<b>Anahita</b> (آناهیتا, <a href=\"https://pl.wikipedia.org/wiki/J%C4%99zyk_awestyjski\" target=\"_blank\" rel=\"noopener noreferrer\">awest.</a> <i>Aredwi Sura Anahita</i> \"Wilgotna Jaśniejąca Nietykalna\", <a href=\"https://pl.wikipedia.org/wiki/J%C4%99zyk_perski\" target=\"_blank\" rel=\"noopener noreferrer\">npers.</a> <i>Nahid</i>) – w <a href=\"https://pl.wikipedia.org/wiki/Zaratusztrianizm\" target=\"_blank\" rel=\"noopener noreferrer\">dawnej religii irańskiej</a> bogini, później jazata, słodkiej wody i płodności oraz porządku społecznego, zwana też Naną (Piastunką). Imię Anahita wzięła od mitycznej rzeki.", "Aspazja": "Starożytni pisarze wspominają również, że Aspazja prowadziła dom publiczny i sama była <a href=\"https://pl.wikipedia.org/wiki/Prostytucja\" target=\"_blank\" rel=\"noopener noreferrer\">nierządnicą</a>, jednakże współcześni naukowcy kwestionują te relacje, które miałyby pochodzić od komediopisarzy zainteresowanych zniesławianiem Peryklesa. Niektórzy badacze kwestionują nawet historyczną tradycję, zgodnie z którą miała być ona <a href=\"https://pl.wikipedia.org/wiki/Hetera\" target=\"_blank\" rel=\"noopener noreferrer\">heterą</a> albo <a href=\"https://pl.wikipedia.org/wiki/Kurtyzana\" target=\"_blank\" rel=\"noopener noreferrer\">kurtyzaną</a>. Zasugerowali, że w rzeczywistości mogła być żoną Peryklesa. Aspazja miała z Peryklesem syna, <a href=\"https://pl.wikipedia.org/wiki/Perykles_M%C5%82odszy\" target=\"_blank\" rel=\"noopener noreferrer\">Peryklesa Młodszego</a>, który później, będąc strategiem w armii greckiej, został stracony po <a href=\"https://pl.wikipedia.org/wiki/Bitwa_pod_Arginuzami\" target=\"_blank\" rel=\"noopener noreferrer\">bitwie pod Arginuzami</a>. Przyjmuje się, że po śmierci Peryklesa Starszego została kurtyzaną Lizyklesa, innego ateńskiego dowódcy i męża stanu.", "Adila": "<b>Adila</b> – arabskie <a href=\"https://pl.wikipedia.org/wiki/Imi%C4%99\" target=\"_blank\" rel=\"noopener noreferrer\">imię</a>, żeńska forma imienia <a href=\"https://pl.wikipedia.org/wiki/Adil\" target=\"_blank\" rel=\"noopener noreferrer\">Adil</a>. Imię Adila jest oboczną formą <a href=\"https://pl.wikipedia.org/wiki/Adela\" target=\"_blank\" rel=\"noopener noreferrer\">Adeli</a> pochodzącą od <i>Athala</i>, gdzie wyraz <i>athal</i> oznacza \"szlachetny\". W IV wieku, na ówczesnych terenach Francji, przybrało formę <i>Adèle</i>.", "Afra": "<b>Afra</b> – <a href=\"https://pl.wikipedia.org/wiki/Imi%C4%99\" target=\"_blank\" rel=\"noopener noreferrer\">imię</a> żeńskie pochodzenia <a href=\"https://pl.wikipedia.org/wiki/%C5%81acina\" target=\"_blank\" rel=\"noopener noreferrer\">łacińskiego</a>, utworzone od nazwy <i>Afri</i>, oznaczającej osobę pochodzącą z <a href=\"https://pl.wikipedia.org/wiki/Afryka\" target=\"_blank\" rel=\"noopener noreferrer\">Afryki</a>. Było to imię dwóch świętych we wczesnym okresie chrześcijaństwa (<a href=\"https://pl.wikipedia.org/wiki/Afra_z_Augsburga\" target=\"_blank\" rel=\"noopener noreferrer\">Afry z Augsburga</a>, zm. ok. 304 i Afry, męczennicy w <a href=\"https://pl.wikipedia.org/wiki/Brescia\" target=\"_blank\" rel=\"noopener noreferrer\">Brescii</a> za cesarza <a href=\"https://pl.wikipedia.org/wiki/Lucjusz_Domicjusz_Aurelian\" target=\"_blank\" rel=\"noopener noreferrer\">Aureliana</a>).", "Alfonsa": "<b>Alfonsa, Alfonsyna</b> – <a href=\"https://pl.wikipedia.org/wiki/Imi%C4%99\" target=\"_blank\" rel=\"noopener noreferrer\">imię</a> żeńskie pochodzenia <a href=\"https://pl.wikipedia.org/wiki/J%C4%99zyki_germa%C5%84skie\" target=\"_blank\" rel=\"noopener noreferrer\">germańskiego</a>, żeński odpowiednik imienia <a href=\"https://pl.wikipedia.org/wiki/Alfons\" target=\"_blank\" rel=\"noopener noreferrer\">Alfons</a>, powstałe ze złożenia członów <i>al</i> (\"cały\") lub <i>adal</i> (\"szlachetny ród\") oraz <i>funs</i> (\"szybka, chętna, życzliwa\"). Patronką tego imienia jest św. Alfonsa od Niepokalanego Poczęcia zm. w Muttathupadam (w <a href=\"https://pl.wikipedia.org/wiki/1946\" target=\"_blank\" rel=\"noopener noreferrer\">1946</a> roku) oraz czcigodna Alfonsa Eppinger. Imię to występuje również bardzo rzadko w wersji Alfonsyna, stanowiącej spolszczenie zdrobnienia imienia Alfonsa, powstałego na gruncie romańskim.", "Ai": "<b>Ai</b>&#32;(<a href=\"https://pl.wikipedia.org/wiki/J%C4%99zyk_japo%C5%84ski\" target=\"_blank\" rel=\"noopener noreferrer\">jap.</a>&#32;愛, 藍, あい, アイ) – popularne żeńskie <a href=\"https://pl.wikipedia.org/wiki/Imiona_japo%C5%84skie\" target=\"_blank\" rel=\"noopener noreferrer\">imię japońskie</a>. Jest ono skróconą, nowocześniejszą formą <a href=\"https://pl.wikipedia.org/wiki/Imi%C4%99\" target=\"_blank\" rel=\"noopener noreferrer\">imienia</a> <a href=\"https://pl.wikipedia.org/wiki/Aiko_(imi%C4%99)\" target=\"_blank\" rel=\"noopener noreferrer\">Aiko</a> (w latach 80. XX wieku żeńskie imiona z końcówką 子 <i>ko</i> wyszły z mody).", "Ayako": "<b>Ayako</b>&#32;(<a href=\"https://pl.wikipedia.org/wiki/J%C4%99zyk_japo%C5%84ski\" target=\"_blank\" rel=\"noopener noreferrer\">jap.</a>&#32;あやこ, アヤコ) – żeńskie <a href=\"https://pl.wikipedia.org/wiki/Imiona_japo%C5%84skie\" target=\"_blank\" rel=\"noopener noreferrer\">imię japońskie</a>.", "Ayaka": "<b>Ayaka</b>&#32;(<a href=\"https://pl.wikipedia.org/wiki/J%C4%99zyk_japo%C5%84ski\" target=\"_blank\" rel=\"noopener noreferrer\">jap.</a>&#32;あやか, アヤカ) – żeńskie <a href=\"https://pl.wikipedia.org/wiki/Imiona_japo%C5%84skie\" target=\"_blank\" rel=\"noopener noreferrer\">imię japońskie</a>.", "Aisling": "<b>Aisling</b> – <a href=\"https://pl.wikipedia.org/wiki/Irlandia\" target=\"_blank\" rel=\"noopener noreferrer\">irlandzkie</a> <a href=\"https://pl.wikipedia.org/wiki/Imi%C4%99\" target=\"_blank\" rel=\"noopener noreferrer\">imię</a> żeńskie, oznaczające <i>sen</i> lub <i>wizję</i>.", "Abigajl": "<b>Abigail</b>, <b>Abigajl</b> – <a href=\"https://pl.wikipedia.org/wiki/Imi%C4%99\" target=\"_blank\" rel=\"noopener noreferrer\">imię</a> żeńskie pochodzenia <a href=\"https://pl.wikipedia.org/wiki/Biblia\" target=\"_blank\" rel=\"noopener noreferrer\">biblijnego</a>. Wywodzi się od hebrajskiego imienia אביגיל <i>Awigajil</i> znaczącego „radość ojca”, „mój ojciec się uradował”.", "Arieta": "<b>Arietta</b> – <a href=\"https://pl.wikipedia.org/wiki/Forma_muzyczna\" target=\"_blank\" rel=\"noopener noreferrer\">forma muzyczna</a>, <a href=\"https://pl.wikipedia.org/wiki/Aria\" target=\"_blank\" rel=\"noopener noreferrer\">aria</a> o mniejszych rozmiarach, zwykle w formie 2-częściowej lub utwór instrumentalny.", "Aleksja": "<b>Aleksja</b> – imię żeńskie pochodzenia greckiego (od męskiego imienia Alexius), żeński odpowiednik imienia <a href=\"https://pl.wikipedia.org/wiki/Aleksy\" target=\"_blank\" rel=\"noopener noreferrer\">Aleksy</a>. Występuje również w formie <b>Aleksa</b>. Być może powiązane jest z imieniem <a href=\"https://pl.wikipedia.org/wiki/Alicja\" target=\"_blank\" rel=\"noopener noreferrer\">Alicja</a>.", "Andrzela": "<b>Angela</b> – imię pochodzi od <a href=\"https://pl.wikipedia.org/wiki/%C5%81acina\" target=\"_blank\" rel=\"noopener noreferrer\">łacińskiego</a> imienia <i>Angel</i>, które powstało od <a href=\"https://pl.wikipedia.org/wiki/J%C4%99zyk_grecki\" target=\"_blank\" rel=\"noopener noreferrer\">greckiego</a> słowa ángelos \"posłaniec\". Imię to też zostało przyswojone w postaci <a href=\"https://pl.wikipedia.org/wiki/Aniela\" target=\"_blank\" rel=\"noopener noreferrer\">Aniela</a>, od niego powstały też imiona <a href=\"https://pl.wikipedia.org/wiki/Angelika\" target=\"_blank\" rel=\"noopener noreferrer\">Angelika</a> i <a href=\"https://pl.wikipedia.org/wiki/Angelina\" target=\"_blank\" rel=\"noopener noreferrer\">Angelina</a>. Jest żeńskim odpowiednikiem imienia <a href=\"https://pl.wikipedia.org/wiki/Anio%C5%82_(imi%C4%99)\" target=\"_blank\" rel=\"noopener noreferrer\">Anioł (Angel)</a>. W ostatnich czasach zapis imienia Angela bywa spolszczany i występuje w formie Andżela lub nawet <i>Andrzela</i> (część osób błędnie wywodzi jej <a href=\"https://pl.wikipedia.org/wiki/Etymologia\" target=\"_blank\" rel=\"noopener noreferrer\">źródłosłów</a> od imienia męskiego <a href=\"https://pl.wikipedia.org/wiki/Andrzej\" target=\"_blank\" rel=\"noopener noreferrer\">Andrzej</a>). Ta druga wersja jest niepoprawna.", "Aurea": "<b>Aurea</b> – <a href=\"https://pl.wikipedia.org/wiki/Imi%C4%99\" target=\"_blank\" rel=\"noopener noreferrer\">imię</a> żeńskie pochodzenia <a href=\"https://pl.wikipedia.org/wiki/%C5%81acina\" target=\"_blank\" rel=\"noopener noreferrer\">łacińskiego</a>, oznaczające \"ukoronowana, uwieńczona\". Wśród patronek dwie święte: <a href=\"https://pl.wikipedia.org/wiki/Aurea_z_Ostii\" target=\"_blank\" rel=\"noopener noreferrer\">Aurea z Ostii</a>, męczennica (zm. ok. 253) oraz Aurea Paryska (ok. 633-666).", "Ayumi": "<b>Ayumi</b>&#32;(<a href=\"https://pl.wikipedia.org/wiki/J%C4%99zyk_japo%C5%84ski\" target=\"_blank\" rel=\"noopener noreferrer\">jap.</a>&#32;あゆみ, アユミ) – żeńskie <a href=\"https://pl.wikipedia.org/wiki/Imiona_japo%C5%84skie\" target=\"_blank\" rel=\"noopener noreferrer\">imię japońskie</a>.", "Amata": "<b>Amata</b> – żeński odpowiednik <a href=\"https://pl.wikipedia.org/wiki/Imi%C4%99\" target=\"_blank\" rel=\"noopener noreferrer\">imienia</a> <a href=\"https://pl.wikipedia.org/wiki/Amat\" target=\"_blank\" rel=\"noopener noreferrer\">Amat</a>. Francuskim odpowiednikiem tego imienia jest <i>Aimée</i>.", "Ambrozja": "<b>Ambrozja</b> – <a href=\"https://pl.wikipedia.org/wiki/Imi%C4%99\" target=\"_blank\" rel=\"noopener noreferrer\">imię</a> żeńskie pochodzenia <a href=\"https://pl.wikipedia.org/wiki/J%C4%99zyk_grecki\" target=\"_blank\" rel=\"noopener noreferrer\">greckiego</a>, od gr. <i>ambrósios</i> – boski, nieśmiertelny; żeński odpowiednik imienia <a href=\"https://pl.wikipedia.org/wiki/Ambro%C5%BCy\" target=\"_blank\" rel=\"noopener noreferrer\">Ambroży</a>. Według stanu na 17 stycznia 2015 r. imię to miało w Polsce 5 nadań.", "Apolina": "<b>Apollina</b>, <b>Apolina</b> – <a href=\"https://pl.wikipedia.org/wiki/Imi%C4%99\" target=\"_blank\" rel=\"noopener noreferrer\">imię</a> żeńskie pochodzenia <a href=\"https://pl.wikipedia.org/wiki/Gr.\" target=\"_blank\" rel=\"noopener noreferrer\">greckiego</a>, od <a href=\"https://pl.wikipedia.org/wiki/Apollo_(imi%C4%99)\" target=\"_blank\" rel=\"noopener noreferrer\">imienia boga Apollona</a>. Patronką tego imienia jest św. Apollina, zm. w <a href=\"https://pl.wikipedia.org/wiki/249\" target=\"_blank\" rel=\"noopener noreferrer\">249</a> roku w <a href=\"https://pl.wikipedia.org/wiki/Aleksandria\" target=\"_blank\" rel=\"noopener noreferrer\">Aleksandrii</a>.", "Arabela": "<b>Arabella</b>, <b>Arabela</b> – imię żeńskie, być może łacińskiego pochodzenia.", "Azucena": "Azucena jest <a href=\"https://pl.wikipedia.org/wiki/Romowie\" target=\"_blank\" rel=\"noopener noreferrer\">Cyganką</a>, córką kobiety, która spłonęła na stosie podejrzana o rzucenie uroków na dzieci hiszpańskiego hrabiego di Luna. Mszcząc się za śmierć matki, z maleńkim dzieckiem na ręku wdarła się do zamku hrabiego i wykradła jego synka. Gdy dogasał już stos starej Cyganki, Azucena rzuciła również dziecko w płomienie. Niestety dla niej, w szoku i w bólu spaliła własne dziecko, tym samym ratując życie synowi hrabiego. Kierowana sprzecznymi uczuciami – wyrzutami sumienia, litością, specyficzną miłością matki, ale też dalszą żądzą zemsty, wychowała chłopca jak własnego syna i nadała mu imię <a href=\"https://pl.wikipedia.org/wiki/Manrico\" target=\"_blank\" rel=\"noopener noreferrer\">Manrico</a>. Także on, żyjąc w nieświadomości swego pochodzenia, traktował ją jak matkę, a gdy dorósł, stał się stronnikiem księcia Urgel, podczas gdy drugi z braci wiernie służył królowi, szukając przy tym nadal zaginionego w dzieciństwie brata.", "Albana": "<b>Albana</b> – <a href=\"https://pl.wikipedia.org/wiki/Imi%C4%99\" target=\"_blank\" rel=\"noopener noreferrer\">imię</a> żeńskie pochodzenia <a href=\"https://pl.wikipedia.org/wiki/%C5%81acina\" target=\"_blank\" rel=\"noopener noreferrer\">łacińskiego</a>, żeński odpowiednik imienia <a href=\"https://pl.wikipedia.org/wiki/Alban_(imi%C4%99)\" target=\"_blank\" rel=\"noopener noreferrer\">Alban</a>. Wywodzi się od nazwiska rzymskiej rodziny <i>Albanus</i> oznaczającego \"pochodzący z Alby\".", "Assol": "Istnieją dwie wersje pochodzenia imienia. Według pierwszej pisarza natchnęło pytanie skierowane do kelnera: <i>А соль?</i> (pol. <i>A sól?</i>), według drugiej imię pochodzi od <a href=\"https://pl.wikipedia.org/wiki/J%C4%99zyk_hiszpa%C5%84ski\" target=\"_blank\" rel=\"noopener noreferrer\">hiszp.</a> <i>al sol</i> (pol. <i>ku słońcu</i>).", "Akane": "<b>Akane</b>&#32;(<a href=\"https://pl.wikipedia.org/wiki/J%C4%99zyk_japo%C5%84ski\" target=\"_blank\" rel=\"noopener noreferrer\">jap.</a>&#32;あかね, アカネ) – żeńskie <a href=\"https://pl.wikipedia.org/wiki/Imiona_japo%C5%84skie\" target=\"_blank\" rel=\"noopener noreferrer\">imię japońskie</a>.", "Aine": "Aine jest silnie powiązana z <a href=\"https://pl.wikipedia.org/wiki/Limerick_(hrabstwo)\" target=\"_blank\" rel=\"noopener noreferrer\">hrabstwem Limerick</a>. Wzgórze Knockainey, nazwane jej imieniem (po irlandzku: <i>Cnoc Áine</i>, „Wzgórze Aine”), było miejscem obrzędów na jej cześć, które miały miejsce jeszcze w 1879 roku. Jest również związana z takimi miejscami jak: Toberanna, w <a href=\"https://pl.wikipedia.org/wiki/Tyrone_(hrabstwo)\" target=\"_blank\" rel=\"noopener noreferrer\">hrabstwie Tyrone</a>; Dunany, w <a href=\"https://pl.wikipedia.org/wiki/Louth_(hrabstwo)\" target=\"_blank\" rel=\"noopener noreferrer\">hrabstwie Louth</a>; Lissan, w <a href=\"https://pl.wikipedia.org/wiki/Londonderry_(hrabstwo)\" target=\"_blank\" rel=\"noopener noreferrer\">hrabstwie Londonderry</a>; i Cnoc Áine koło Teelin, w <a href=\"https://pl.wikipedia.org/wiki/Donegal_(hrabstwo)\" target=\"_blank\" rel=\"noopener noreferrer\">hrabstwie Donegal</a>.", "Anizja": "<b>Anizja</b> – <a href=\"https://pl.wikipedia.org/wiki/Imi%C4%99\" target=\"_blank\" rel=\"noopener noreferrer\">imię</a> żeńskie, żeński odpowiednik imienia <a href=\"https://pl.wikipedia.org/wiki/Anizjusz\" target=\"_blank\" rel=\"noopener noreferrer\">Anizjusz</a> niejasnego pochodzenia. Według jednych źródeł pochodzi ono od <a href=\"https://pl.wikipedia.org/wiki/%C5%81acina\" target=\"_blank\" rel=\"noopener noreferrer\">łacińskiego</a> <a href=\"https://pl.wikipedia.org/wiki/Nazwisko#Nazwisko\" target=\"_blank\" rel=\"noopener noreferrer\">nazwiska</a> <i>Anisia</i>, <i>Anisii</i> niewiadomej proweniencji; według innych jego etymologia jest <a href=\"https://pl.wikipedia.org/wiki/J%C4%99zyk_grecki\" target=\"_blank\" rel=\"noopener noreferrer\">grecka</a>, od <i>anisos</i> – „niejednakowy”.", "Akemi": "<b>Akemi</b>&#32;(<a href=\"https://pl.wikipedia.org/wiki/J%C4%99zyk_japo%C5%84ski\" target=\"_blank\" rel=\"noopener noreferrer\">jap.</a>&#32;あけみ, アケミ) – żeńskie <a href=\"https://pl.wikipedia.org/wiki/Imiona_japo%C5%84skie\" target=\"_blank\" rel=\"noopener noreferrer\">imię japońskie</a>.", "Apolinaria": "<b>Apolinaria</b> – żeńska forma <a href=\"https://pl.wikipedia.org/wiki/Imi%C4%99\" target=\"_blank\" rel=\"noopener noreferrer\">imienia</a> <a href=\"https://pl.wikipedia.org/wiki/Apolinary\" target=\"_blank\" rel=\"noopener noreferrer\">Apolinary</a>. W <a href=\"https://pl.wikipedia.org/wiki/Rosja\" target=\"_blank\" rel=\"noopener noreferrer\">Rosji</a> i krajach wschodniosłowiańskich utworzono od Apolinarii skróconą formę Polina (możliwą też od <a href=\"https://pl.wikipedia.org/wiki/Pelagia\" target=\"_blank\" rel=\"noopener noreferrer\">Pelagii</a> lub współcześnie jako fonetyczne przeniesienie francuskiej <a href=\"https://pl.wikipedia.org/wiki/Paulina_(imi%C4%99)\" target=\"_blank\" rel=\"noopener noreferrer\">Pauline</a> na grunt rosyjski), która w 2007 roku imię była drugim pod względem liczby nadań wśród noworodków imieniem żeńskim w okręgu moskiewskim w Rosji. Według stanu na 17 stycznia 2015 imię to miało w Polsce 5 nadań.", "Amaranta": "<b>Amaranta</b> – <a href=\"https://pl.wikipedia.org/wiki/Imi%C4%99\" target=\"_blank\" rel=\"noopener noreferrer\">imię</a> żeńskie, żeński odpowiednik imienia Amarant/Amarantus, pochodzące od <a href=\"https://pl.wikipedia.org/wiki/J%C4%99zyk_grecki\" target=\"_blank\" rel=\"noopener noreferrer\">gr.</a>&#160;αμάραντος (<i>amarantos</i>), co oznacza \"niezatarty\", \"niewygasający\". Patronem tego imienia jest św. Amarant(us) z <a href=\"https://pl.wikipedia.org/wiki/Albi\" target=\"_blank\" rel=\"noopener noreferrer\">Albi</a> (<a href=\"https://pl.wikipedia.org/wiki/VI_wiek\" target=\"_blank\" rel=\"noopener noreferrer\">VI wiek</a>).", "Amaris": "Obszar doradztwa obejmuje sektor <a href=\"https://pl.wikipedia.org/wiki/Technologia_informacyjna\" target=\"_blank\" rel=\"noopener noreferrer\">IT</a>, strategii oraz usług <a href=\"https://pl.wikipedia.org/wiki/Outsourcing\" target=\"_blank\" rel=\"noopener noreferrer\">outsourcingowych</a> zawierających się w następujących pionach biznesowych: technologie informacyjne oraz biznesowe <a href=\"https://pl.wikipedia.org/wiki/System_informacyjny\" target=\"_blank\" rel=\"noopener noreferrer\">systemy informacyjne</a> zarządzania, inżynieria w zakresie zaawansowanych technologii, <a href=\"https://pl.wikipedia.org/wiki/Telekomunikacja\" target=\"_blank\" rel=\"noopener noreferrer\">telekomunikacja</a>, <a href=\"https://pl.wikipedia.org/wiki/Biotechnologia\" target=\"_blank\" rel=\"noopener noreferrer\">biotechnologia</a> oraz <a href=\"https://pl.wikipedia.org/wiki/Farmacja\" target=\"_blank\" rel=\"noopener noreferrer\">farmacja</a>.", "Akwilina": "<b>Akwilina</b> – <a href=\"https://pl.wikipedia.org/wiki/Imi%C4%99\" target=\"_blank\" rel=\"noopener noreferrer\">imię</a> żeńskie pochodzenia łacińskiego. Patronką tego imienia jest św. Akwilina (III wiek).", "Atsuko": "<b>Atsuko</b>&#32;(<a href=\"https://pl.wikipedia.org/wiki/J%C4%99zyk_japo%C5%84ski\" target=\"_blank\" rel=\"noopener noreferrer\">jap.</a>&#32;あつこ, アツコ) – żeńskie <a href=\"https://pl.wikipedia.org/wiki/Imiona_japo%C5%84skie\" target=\"_blank\" rel=\"noopener noreferrer\">imię japońskie</a>.", "Adelinda": "<b>Adelinda</b> – <a href=\"https://pl.wikipedia.org/wiki/Imi%C4%99\" target=\"_blank\" rel=\"noopener noreferrer\">imię</a> żeńskie pochodzenia <a href=\"https://pl.wikipedia.org/wiki/J%C4%99zyki_germa%C5%84skie\" target=\"_blank\" rel=\"noopener noreferrer\">germańskiego</a>. Składa się z członów <i>adal</i> – \"szlachetny ród\" (por. <a href=\"https://pl.wikipedia.org/wiki/Adalgunda\" target=\"_blank\" rel=\"noopener noreferrer\">Adalgunda</a>, <a href=\"https://pl.wikipedia.org/wiki/Adalbert\" target=\"_blank\" rel=\"noopener noreferrer\">Adalbert</a>, <a href=\"https://pl.wikipedia.org/wiki/Adelajda_(imi%C4%99)\" target=\"_blank\" rel=\"noopener noreferrer\">Adelajda</a>) i <i>lind</i> – \"miękka, łagodna\" (por. <a href=\"https://pl.wikipedia.org/wiki/Rozalinda\" target=\"_blank\" rel=\"noopener noreferrer\">Rozalinda</a>). W Kościele katolickim patronką tego imienia jest Adelinda z <a href=\"https://pl.wikipedia.org/wiki/Bad_Buchau\" target=\"_blank\" rel=\"noopener noreferrer\">Buchau</a>.", "Apollina": "<b>Apollina</b>, <b>Apolina</b> – <a href=\"https://pl.wikipedia.org/wiki/Imi%C4%99\" target=\"_blank\" rel=\"noopener noreferrer\">imię</a> żeńskie pochodzenia <a href=\"https://pl.wikipedia.org/wiki/Gr.\" target=\"_blank\" rel=\"noopener noreferrer\">greckiego</a>, od <a href=\"https://pl.wikipedia.org/wiki/Apollo_(imi%C4%99)\" target=\"_blank\" rel=\"noopener noreferrer\">imienia boga Apollona</a>. Patronką tego imienia jest św. Apollina, zm. w <a href=\"https://pl.wikipedia.org/wiki/249\" target=\"_blank\" rel=\"noopener noreferrer\">249</a> roku w <a href=\"https://pl.wikipedia.org/wiki/Aleksandria\" target=\"_blank\" rel=\"noopener noreferrer\">Aleksandrii</a>.", "Ayano": "<b>Ayano</b>&#32;(<a href=\"https://pl.wikipedia.org/wiki/J%C4%99zyk_japo%C5%84ski\" target=\"_blank\" rel=\"noopener noreferrer\">jap.</a>&#32;あやの, アヤノ) – żeńskie <a href=\"https://pl.wikipedia.org/wiki/Imiona_japo%C5%84skie\" target=\"_blank\" rel=\"noopener noreferrer\">imię japońskie</a>.", "Anuncjata": "<b>Anuncjata</b> – <a href=\"https://pl.wikipedia.org/wiki/Imi%C4%99\" target=\"_blank\" rel=\"noopener noreferrer\">imię</a> żeńskie, wywodzące się z <a href=\"https://pl.wikipedia.org/wiki/%C5%81acina\" target=\"_blank\" rel=\"noopener noreferrer\">łac.</a>&#160;<em>annuntio</em>, które oznacza „ogłaszać, obwieszczać, zapowiadać, zwiastować”. Początkowo imię nadawane dla upamiętnienia <a href=\"https://pl.wikipedia.org/wiki/Zwiastowanie_Pa%C5%84skie\" target=\"_blank\" rel=\"noopener noreferrer\">Zwiastowania Najświętszej Maryi Pannie</a>.", "Adiba": "<b>Adiba</b> (<a href=\"https://pl.wikipedia.org/wiki/J%C4%99zyk_arabski\" target=\"_blank\" rel=\"noopener noreferrer\">arab.</a>&#160;&#8207;أديبة&#8206;) – arabskie <a href=\"https://pl.wikipedia.org/wiki/Imi%C4%99\" target=\"_blank\" rel=\"noopener noreferrer\">imię</a> żeńskie. Jego znaczenie to „kulturalna, wyrafinowana”. Żeńska wersja imienia Adib. W języku arabskim słowo <i>adiba</i> oznacza również <a href=\"https://pl.wikipedia.org/wiki/Pisarz\" target=\"_blank\" rel=\"noopener noreferrer\">pisarkę</a>.", "Aika": "<b>Aika</b>&#32;(<a href=\"https://pl.wikipedia.org/wiki/J%C4%99zyk_japo%C5%84ski\" target=\"_blank\" rel=\"noopener noreferrer\">jap.</a>&#32;あいか, アイカ) – żeńskie <a href=\"https://pl.wikipedia.org/wiki/Imiona_japo%C5%84skie\" target=\"_blank\" rel=\"noopener noreferrer\">imię japońskie</a>.", "Artemia": "<b>Artemia</b> – <a href=\"https://pl.wikipedia.org/wiki/Imi%C4%99\" target=\"_blank\" rel=\"noopener noreferrer\">imię</a> żeńskie pochodzenia <a href=\"https://pl.wikipedia.org/wiki/Gr.\" target=\"_blank\" rel=\"noopener noreferrer\">greckiego</a>, wywodzące się od imienia bogini <a href=\"https://pl.wikipedia.org/wiki/Artemida\" target=\"_blank\" rel=\"noopener noreferrer\">Artemidy</a>, a oznaczające „zdrowa” lub „należąca do Artemidy, poświęcona Artemidzie”.", "Artemizja": "<b>Artemizja</b> – greckie <a href=\"https://pl.wikipedia.org/wiki/Imi%C4%99\" target=\"_blank\" rel=\"noopener noreferrer\">imię</a> żeńskie.", "Akacja": "Akacje występują na <a href=\"https://pl.wikipedia.org/wiki/Sawanna\" target=\"_blank\" rel=\"noopener noreferrer\">sawannach</a>, w okresowo suchych formacjach leśnych i zaroślowych oraz na pustyniach. Stanowią kluczowy składnik takich australijskich formacji jak <a href=\"https://pl.wikipedia.org/wiki/Mulga\" target=\"_blank\" rel=\"noopener noreferrer\">mulga</a> czy <a href=\"https://pl.wikipedia.org/wiki/Brigalow\" target=\"_blank\" rel=\"noopener noreferrer\">brigalow</a>.", "Antea": "<b>Antea</b> – imię <a href=\"https://pl.wikipedia.org/wiki/Kobieta\" target=\"_blank\" rel=\"noopener noreferrer\">żeńskie</a> pochodzenia <a href=\"https://pl.wikipedia.org/wiki/W%C4%99gry\" target=\"_blank\" rel=\"noopener noreferrer\">węgierskiego</a>. Pochodzi od imienia \"Anteo\" czyli <a href=\"https://pl.wikipedia.org/wiki/Antoni_(imi%C4%99)\" target=\"_blank\" rel=\"noopener noreferrer\">Antoni</a>. Może też pochodzić od imienia greckiej bogini <a href=\"https://pl.wikipedia.org/wiki/Atena\" target=\"_blank\" rel=\"noopener noreferrer\">Ateny</a>. Imię to nosiła główna bohaterka powieści \"<a href=\"https://pl.wikipedia.org/wiki/Pi%C4%99cioro_dzieci_i_co%C5%9B\" target=\"_blank\" rel=\"noopener noreferrer\">Pięcioro dzieci i coś</a>\" autorstwa <a href=\"https://pl.wikipedia.org/wiki/Edith_Nesbit\" target=\"_blank\" rel=\"noopener noreferrer\">Edith Nesbit</a>. W <a href=\"https://pl.wikipedia.org/wiki/Polska\" target=\"_blank\" rel=\"noopener noreferrer\">Polsce</a> imię rzadko spotykane.", "Aino": "Motyw młodej dziewczyny wydanej za mąż wbrew woli jest typowy dla romantyzmu lub średniowiecza. Elias Lönnrot spisywał Kalevalę na podstawie starych ludowych wierszy i pieśni (<i>fin. runo </i>) Niewątpliwie uległ jednak inspiracji wieloma innymi motywami literackimi pochodzącymi z innych epok i kultur. Postać Aino przypomina np. polską legendę o \"<a href=\"https://pl.wikipedia.org/wiki/Wanda_(legendarna_ksi%C4%99%C5%BCniczka)\" target=\"_blank\" rel=\"noopener noreferrer\">Wandzie, co nie chciała Niemca</a>\"", "Ariena": "Imiona wszystkich Majarów pochodzą z quenyi.", "Arystyda": "<b>Arystyda</b> – <a href=\"https://pl.wikipedia.org/wiki/Imi%C4%99\" target=\"_blank\" rel=\"noopener noreferrer\">imię</a> żeńskie pochodzenia <a href=\"https://pl.wikipedia.org/wiki/Gr.\" target=\"_blank\" rel=\"noopener noreferrer\">greckiego</a>, od gr. <i>Αριστειδης (Aristeides)</i>, co oznacza \"najlepszy rodzaj\", stanowiąc złożenie członów <i>αριστος (aristos)</i> – \"najlepszy\" i <i>ειδος (eidos)</i> – \"rodzaj, gatunek\". Żeński odpowiednik imienia <a href=\"https://pl.wikipedia.org/wiki/Arystydes_(imi%C4%99)\" target=\"_blank\" rel=\"noopener noreferrer\">Arystydes</a>, którego patronem w Kościele katolickim jest św. Arystydes Marcjanus (<a href=\"https://pl.wikipedia.org/wiki/II_wiek\" target=\"_blank\" rel=\"noopener noreferrer\">II wiek</a>).", "Asami": "<b>Asami</b>&#32;(<a href=\"https://pl.wikipedia.org/wiki/J%C4%99zyk_japo%C5%84ski\" target=\"_blank\" rel=\"noopener noreferrer\">jap.</a>&#32;あさみ, アサミ) – żeńskie <a href=\"https://pl.wikipedia.org/wiki/Imiona_japo%C5%84skie\" target=\"_blank\" rel=\"noopener noreferrer\">imię japońskie</a>, może być używane także jako nazwisko.", "Azalea": "<b>Różanecznik</b>, azalia, rododendron (<i>Rhododendron</i> L.) – <a href=\"https://pl.wikipedia.org/wiki/Rodzaj_(biologia)\" target=\"_blank\" rel=\"noopener noreferrer\">rodzaj</a> <a href=\"https://pl.wikipedia.org/wiki/Ro%C5%9Bliny\" target=\"_blank\" rel=\"noopener noreferrer\">roślin</a> z rodziny <a href=\"https://pl.wikipedia.org/wiki/Wrzosowate\" target=\"_blank\" rel=\"noopener noreferrer\">wrzosowatych</a> (<i>Ericaceae</i>). Obejmuje ponad tysiąc <a href=\"https://pl.wikipedia.org/wiki/Gatunek_(biologia)\" target=\"_blank\" rel=\"noopener noreferrer\">gatunków</a>. W stanie naturalnym występują głównie w <a href=\"https://pl.wikipedia.org/wiki/Azja\" target=\"_blank\" rel=\"noopener noreferrer\">Azji</a>, w mniejszej liczbie gatunków w obydwu <a href=\"https://pl.wikipedia.org/wiki/Ameryka\" target=\"_blank\" rel=\"noopener noreferrer\">Amerykach</a> i w <a href=\"https://pl.wikipedia.org/wiki/Europa\" target=\"_blank\" rel=\"noopener noreferrer\">Europie</a>. Rosną zwykle na obszarach górskich, na glebach próchnicznych i kwaśnych, często także na <a href=\"https://pl.wikipedia.org/wiki/Torfowisko\" target=\"_blank\" rel=\"noopener noreferrer\">torfowiskach</a> i na glebach oraz skałach wapiennych. Zasiedlają lasy, formacje krzewiaste i wrzosowiska. Nieliczne gatunki są <a href=\"https://pl.wikipedia.org/wiki/Epifit\" target=\"_blank\" rel=\"noopener noreferrer\">epifitami</a>. Kwiaty są u części gatunków wonne, u innych nie. <a href=\"https://pl.wikipedia.org/wiki/Zapylenie\" target=\"_blank\" rel=\"noopener noreferrer\">Zapylane</a> są przez <a href=\"https://pl.wikipedia.org/wiki/Owady\" target=\"_blank\" rel=\"noopener noreferrer\">owady</a>, niektóre gatunki w Himalajach także przez <a href=\"https://pl.wikipedia.org/wiki/Ptaki\" target=\"_blank\" rel=\"noopener noreferrer\">ptaki</a>.", "Agape": "<b>Agape</b> (<a href=\"https://pl.wikipedia.org/wiki/J%C4%99zyk_grecki_klasyczny\" target=\"_blank\" rel=\"noopener noreferrer\">stgr.</a>&#160;<a href=\"https://pl.wiktionary.org/wiki/%E1%BC%80%CE%B3%CE%AC%CF%80%CE%B7\" target=\"_blank\" rel=\"noopener noreferrer\">ἀγάπη</a> <i>agápē</i>) – „miłość: najwyższa forma miłości, zwłaszcza miłość braterska, dobroczynność, miłość Boga do ludzi i ludzi do Boga”. Nie należy mylić z <i>philēo</i> – miłością braterską – agápē unosi uniwersalną, bezwarunkową, transcendentalną (wszechobecną) miłość, która istnieje niezależnie od sytuacji. Rzeczownik ten pierwszy raz występuje w <a href=\"https://pl.wikipedia.org/wiki/Septuaginta\" target=\"_blank\" rel=\"noopener noreferrer\">Septuagincie</a>, a w formie czasownika zapisana już przez <a href=\"https://pl.wikipedia.org/wiki/Homer\" target=\"_blank\" rel=\"noopener noreferrer\">Homera</a> – dosłownie tłumacząc, jest to afekt, życzliwość, szacunek, np. „witać z uczuciem” i „okazywać uczucie martwym.” Inni starożytni autorzy używali tego słowa jako symbol miłości małżonka lub rodziny albo uczucie do konkretnej czynności, w kontraście do <i>philia</i> (przyjaźń, miłość braterska) i <i>eros</i> (miłość intymna).", "Amaryllis": "<b>Amarylis nadobny</b> (<i>Amaryllis belladonna</i> L.) – <a href=\"https://pl.wikipedia.org/wiki/Rodzaj_(biologia)\" target=\"_blank\" rel=\"noopener noreferrer\">gatunek</a> rośliny z rodzaju <a href=\"https://pl.wikipedia.org/wiki/Amarylis\" target=\"_blank\" rel=\"noopener noreferrer\">amarylis</a> z <a href=\"https://pl.wikipedia.org/wiki/Rodzina_(biologia)\" target=\"_blank\" rel=\"noopener noreferrer\">rodziny</a> <a href=\"https://pl.wikipedia.org/wiki/Amarylkowate\" target=\"_blank\" rel=\"noopener noreferrer\">amarylkowatych</a>, pochodzący z <a href=\"https://pl.wikipedia.org/wiki/Afryka_Po%C5%82udniowa\" target=\"_blank\" rel=\"noopener noreferrer\">Afryki Południowej</a>, <a href=\"https://pl.wikipedia.org/wiki/Introdukcja\" target=\"_blank\" rel=\"noopener noreferrer\">introdukowany</a> do <a href=\"https://pl.wikipedia.org/wiki/Ameryka_P%C3%B3%C5%82nocna\" target=\"_blank\" rel=\"noopener noreferrer\">Ameryki Północnej</a>, <a href=\"https://pl.wikipedia.org/wiki/Ameryka_%C5%9Arodkowa\" target=\"_blank\" rel=\"noopener noreferrer\">Ameryki Środkowej</a>, <a href=\"https://pl.wikipedia.org/wiki/Europa\" target=\"_blank\" rel=\"noopener noreferrer\">Europy</a>, <a href=\"https://pl.wikipedia.org/wiki/Australia\" target=\"_blank\" rel=\"noopener noreferrer\">Australii</a> i <a href=\"https://pl.wikipedia.org/wiki/Nowa_Zelandia\" target=\"_blank\" rel=\"noopener noreferrer\">Nowej Zelandii</a>.", "Atanazja": "<b>Atanazja</b> – żeński odpowiednik <a href=\"https://pl.wikipedia.org/wiki/Imi%C4%99\" target=\"_blank\" rel=\"noopener noreferrer\">imienia</a> <a href=\"https://pl.wikipedia.org/wiki/Atanazy\" target=\"_blank\" rel=\"noopener noreferrer\">Atanazy</a>. Patronką tego imienia jest <a href=\"https://pl.wikipedia.org/wiki/Atanazja_(%C5%9Bwi%C4%99ta)\" target=\"_blank\" rel=\"noopener noreferrer\">św. Atanazja</a>, żyjąca w <a href=\"https://pl.wikipedia.org/wiki/IX_wiek\" target=\"_blank\" rel=\"noopener noreferrer\">IX wieku</a>.", "Akwila": "<b>Akwila</b> – <a href=\"https://pl.wikipedia.org/wiki/Imi%C4%99\" target=\"_blank\" rel=\"noopener noreferrer\">imię</a> męskie pochodzenia <a href=\"https://pl.wikipedia.org/wiki/%C5%81acina\" target=\"_blank\" rel=\"noopener noreferrer\">łacińskiego</a>, wywodzące się od <i>Aquila</i> (słowa oznaczającego \"orzeł\"). W <a href=\"https://pl.wikipedia.org/wiki/Nowy_Testament\" target=\"_blank\" rel=\"noopener noreferrer\">Nowym Testamencie</a> opisany jest <a href=\"https://pl.wikipedia.org/wiki/Akwila_i_Pryska\" target=\"_blank\" rel=\"noopener noreferrer\">Akwila</a>. Wśród znanych nosicieli tego imienia byli też św. Akwila, męczennik oraz tłumacz <a href=\"https://pl.wikipedia.org/wiki/Akwila_z_Synopy\" target=\"_blank\" rel=\"noopener noreferrer\">Akwila z Synopy</a>.", "Abra": "<b>Abra</b> – <a href=\"https://pl.wikipedia.org/wiki/Imi%C4%99\" target=\"_blank\" rel=\"noopener noreferrer\">imię</a> żeńskie pochodzenia hebrajskiego i arabskiego, spokrewnione z imieniem <a href=\"https://pl.wikipedia.org/wiki/Abraham_(imi%C4%99)\" target=\"_blank\" rel=\"noopener noreferrer\">Abraham</a> o znaczeniu \"ojciec wielu\". Warianty to Abame, <a href=\"https://pl.wikipedia.org/wiki/Abarrane\" target=\"_blank\" rel=\"noopener noreferrer\">Abarrane</a>, Abrah i Abrahana.", "Amane": "<b>Amane</b>&#32;(<a href=\"https://pl.wikipedia.org/wiki/J%C4%99zyk_japo%C5%84ski\" target=\"_blank\" rel=\"noopener noreferrer\">jap.</a>&#32;あまね, アマネ) – żeńskie <a href=\"https://pl.wikipedia.org/wiki/Imiona_japo%C5%84skie\" target=\"_blank\" rel=\"noopener noreferrer\">imię japońskie</a>, może być używane także jako nazwisko.", "Akina": "<b>Akina</b>&#32;(<a href=\"https://pl.wikipedia.org/wiki/J%C4%99zyk_japo%C5%84ski\" target=\"_blank\" rel=\"noopener noreferrer\">jap.</a>&#32;あきな, アキナ) – głównie <a href=\"https://pl.wikipedia.org/wiki/Imiona_japo%C5%84skie\" target=\"_blank\" rel=\"noopener noreferrer\">żeńskie imię japońskie</a>, rzadko noszone przez mężczyzn.", "Ayame": "<b>Ayame</b>&#32;(<a href=\"https://pl.wikipedia.org/wiki/J%C4%99zyk_japo%C5%84ski\" target=\"_blank\" rel=\"noopener noreferrer\">jap.</a>&#32;あやめ, アヤメ) – głównie żeńskie <a href=\"https://pl.wikipedia.org/wiki/Imiona_japo%C5%84skie\" target=\"_blank\" rel=\"noopener noreferrer\">imię japońskie</a>, rzadko noszone przez mężczyzn.", "Asana": "<b>Asana</b> (<a href=\"https://pl.wikipedia.org/wiki/Pismo_dewanagari\" target=\"_blank\" rel=\"noopener noreferrer\">dewanagari</a> योगासन, <a href=\"https://pl.wikipedia.org/wiki/Transliteracja\" target=\"_blank\" rel=\"noopener noreferrer\">transliteracja</a> yogāsana) – dosłownie: \"siedzenie\". Pojęcie używane w dwóch znaczeniach:", "Akasha": "<b> Akaśa, akasza</b> (<a href=\"https://pl.wikipedia.org/wiki/Pismo_dewanagari\" target=\"_blank\" rel=\"noopener noreferrer\">dewanagari</a> आकाश, <a href=\"https://pl.wikipedia.org/wiki/Transliteracja\" target=\"_blank\" rel=\"noopener noreferrer\">trl.</a> <i>ākāśa</i>, <a href=\"https://pl.wikipedia.org/wiki/J%C4%99zyk_angielski\" target=\"_blank\" rel=\"noopener noreferrer\">ang.</a> <i>akasha</i>) – słowo pochodzące z <a href=\"https://pl.wikipedia.org/wiki/Sanskryt\" target=\"_blank\" rel=\"noopener noreferrer\">sanskrytu</a> oznaczające <i><a href=\"https://pl.wikipedia.org/wiki/Eter_(filozofia)\" target=\"_blank\" rel=\"noopener noreferrer\">eter</a></i> rozpatrywany w dwóch znaczeniach: w sensie <a href=\"https://pl.wikipedia.org/wiki/Mitologia\" target=\"_blank\" rel=\"noopener noreferrer\">mitologicznym</a> i jako jeden z <a href=\"https://pl.wikipedia.org/wiki/%C5%BBywio%C5%82y\" target=\"_blank\" rel=\"noopener noreferrer\">żywiołów</a>. Eter jest piątym, podstawowym elementem, który obejmuje pozostałe cztery <a href=\"https://pl.wikipedia.org/wiki/%C5%BBywio%C5%82y\" target=\"_blank\" rel=\"noopener noreferrer\">żywioły</a>: vata – powietrze, ap – woda, agni – ogień i prithivi – ziemia.", "Annapurna": "Miejscowa nazwa góry jest połączeniem <a href=\"https://pl.wikipedia.org/wiki/Sanskryt\" target=\"_blank\" rel=\"noopener noreferrer\">sanskryckich</a> słów „anna” (pożywienie) i „purna” (wypełniona) i oznacza <i>Wypełnioną Pożywieniem</i>. Imieniem <a href=\"https://pl.wikipedia.org/wiki/Annapurna_(bogini)\" target=\"_blank\" rel=\"noopener noreferrer\">Annapurna</a> nazywana jest <a href=\"https://pl.wikipedia.org/wiki/Hinduizm\" target=\"_blank\" rel=\"noopener noreferrer\">hinduistyczna</a> bogini, jedno z wcieleń <a href=\"https://pl.wikipedia.org/wiki/Parwati\" target=\"_blank\" rel=\"noopener noreferrer\">Parwati</a>, towarzyszki <a href=\"https://pl.wikipedia.org/wiki/%C5%9Aiwa\" target=\"_blank\" rel=\"noopener noreferrer\">Śiwy</a>, czczonej za moc dostarczania pożywienia. Według innej wersji połączenie tych dwóch słów jest przydomkiem bogini <a href=\"https://pl.wikipedia.org/wiki/Durga\" target=\"_blank\" rel=\"noopener noreferrer\">Durgi</a> lub <a href=\"https://pl.wikipedia.org/wiki/Kali\" target=\"_blank\" rel=\"noopener noreferrer\">Kali</a> i mogłoby mieć znaczenie <i>Żywicielka</i>.", "Aloysia": "<b>Miłowonka</b> (<i>Aloysia</i>) – <a href=\"https://pl.wikipedia.org/wiki/Rodzaj_(biologia)\" target=\"_blank\" rel=\"noopener noreferrer\">rodzaj</a> roślin należących do rodziny <a href=\"https://pl.wikipedia.org/wiki/Werbenowate\" target=\"_blank\" rel=\"noopener noreferrer\">werbenowatych</a> (<i>Verbenaceae</i>). Obejmuje 41 gatunków. Rośliny te występują w strefie tropikalnej i subtropikalnej obu kontynentów amerykańskich od <a href=\"https://pl.wikipedia.org/wiki/Kalifornia\" target=\"_blank\" rel=\"noopener noreferrer\">Kalifornii</a>, <a href=\"https://pl.wikipedia.org/wiki/Utah\" target=\"_blank\" rel=\"noopener noreferrer\">Utah</a> i <a href=\"https://pl.wikipedia.org/wiki/Teksas\" target=\"_blank\" rel=\"noopener noreferrer\">Teksasu</a> po północną część <a href=\"https://pl.wikipedia.org/wiki/Chile\" target=\"_blank\" rel=\"noopener noreferrer\">Chile</a> i <a href=\"https://pl.wikipedia.org/wiki/Argentyna\" target=\"_blank\" rel=\"noopener noreferrer\">Argentyny</a>. Rośliny te występują zwykle w formacjach suchych, zaroślowych, często rosną na terenach skalistych.", "Arena": "<b>Arena</b> (z <a href=\"https://pl.wikipedia.org/wiki/%C5%81acina\" target=\"_blank\" rel=\"noopener noreferrer\">łac.</a> <i>harena</i>, <i>arena</i> - <a href=\"https://pl.wikipedia.org/wiki/Piasek\" target=\"_blank\" rel=\"noopener noreferrer\">piasek</a>) – usytuowany w centrum obiektu i wysypany piaskiem plac w kształcie koła lub elipsy. Miejsce walk, turniejów, popisów, igrzysk i widowisk. Wywodzi się ze <a href=\"https://pl.wikipedia.org/wiki/Staro%C5%BCytno%C5%9B%C4%87\" target=\"_blank\" rel=\"noopener noreferrer\">starożytnego</a> teatru greckiego i rzymskiego oraz cyrku rzymskiego.", "Alkmena": "Imię jej oznacza „silna w gniewie”. <a href=\"https://pl.wikipedia.org/wiki/Robert_Graves\" target=\"_blank\" rel=\"noopener noreferrer\">Robert Graves</a> uważa je za tytuł księżyca lub przydomek Hery.", "Adalberta": "<b>Adalberta</b> – <a href=\"https://pl.wikipedia.org/wiki/Imi%C4%99\" target=\"_blank\" rel=\"noopener noreferrer\">imię</a> pochodzenia <a href=\"https://pl.wikipedia.org/wiki/J%C4%99zyki_germa%C5%84skie\" target=\"_blank\" rel=\"noopener noreferrer\">germańskiego</a>. Żeński odpowiednik imienia <a href=\"https://pl.wikipedia.org/wiki/Adalbert\" target=\"_blank\" rel=\"noopener noreferrer\">Adalbert</a>. W Polsce spotykane bardzo rzadko, choć notowane już w średniowieczu.", "Agora": "Od V wieku p.n.e. „agora jońska”, zakładana według <a href=\"https://pl.wikipedia.org/wiki/System_hippodamejski\" target=\"_blank\" rel=\"noopener noreferrer\">systemu hippodamejskiego</a>, miała najczęściej kształt prostokąta, który - począwszy od <a href=\"https://pl.wikipedia.org/wiki/Sztuka_grecka_w_okresie_klasycznym\" target=\"_blank\" rel=\"noopener noreferrer\">okresu klasycznego</a> - otaczały <a href=\"https://pl.wikipedia.org/wiki/Portyk\" target=\"_blank\" rel=\"noopener noreferrer\">portyki</a> kolumnowe (<a href=\"https://pl.wikipedia.org/wiki/Stoa\" target=\"_blank\" rel=\"noopener noreferrer\">stoa</a>). Przez jej środek z reguły przechodziła główna ulica miasta. Na agorze znajdowały się zazwyczaj budowle o przeznaczeniu religijnym i publicznym, mównice i siedzenia dla urzędników, studnie/fontanny oraz pomniki.", "Analisa": "Nakład „Analisa” wynosi ponad 300 tys. egzemplarzy. Obok gazety powstał pokrewny serwis informacyjny analisadaily.com.", "Adelisa": "<b>Adelisa</b> – <a href=\"https://pl.wikipedia.org/wiki/Imi%C4%99\" target=\"_blank\" rel=\"noopener noreferrer\">imię</a> żeńskie pochodzenia <a href=\"https://pl.wikipedia.org/wiki/J%C4%99zyk_francuski\" target=\"_blank\" rel=\"noopener noreferrer\">francuskiego</a>. Powstało na skutek <a href=\"https://pl.wikipedia.org/wiki/Kontaminacja_(j%C4%99zykoznawstwo)\" target=\"_blank\" rel=\"noopener noreferrer\">kontaminacji</a> imion <a href=\"https://pl.wikipedia.org/wiki/Adela\" target=\"_blank\" rel=\"noopener noreferrer\">Adela</a> i Lisa. Można je spotkać także w formach Adalicia, Adaliz i Adeliza.", "Aula": "<b>Aula</b> – pojęcie o kilku znaczeniach:", "Agnetta": "<b>Agnieszka</b> – imię żeńskie, jedno z najpopularniejszych w Polsce, gdzie pojawiło się wraz z chrześcijaństwem. Pochodzi od <a href=\"https://pl.wikipedia.org/wiki/J%C4%99zyk_grecki\" target=\"_blank\" rel=\"noopener noreferrer\">gr.</a>&#160;Αγνή – „czysta”, „dziewicza”, „nieskalana”. Może również pochodzić od <a href=\"https://pl.wikipedia.org/wiki/%C5%81acina\" target=\"_blank\" rel=\"noopener noreferrer\">łac.</a>&#160;<em>agnus</em> – „baranek” (to jednocześnie rodzaj męski greckiej „h-agne”). Do Czech imię to dotarło w formie <a href=\"https://pl.wikipedia.org/wiki/%C5%81acina\" target=\"_blank\" rel=\"noopener noreferrer\">łac.</a>&#160;<em>Agnes</em>, następnie zostało zaadaptowane do języka polskiego w obecnej formie. Imię to funkcjonuje również w języku polskim w formie Inka, początkowo było ono polskim zdrobnieniem imienia Inez — francusko-iberyjskiej formy imienia Agnieszka (Inês, Inés, Inès) — z czasem jednak zaczęło funkcjonować w Polsce jako samodzielne imię.", "Ametyst": "<b>Ametyst</b> – <a href=\"https://pl.wikipedia.org/wiki/Minera%C5%82\" target=\"_blank\" rel=\"noopener noreferrer\">minerał</a>, fioletowa i przezroczysta do przeświecającej odmiana <a href=\"https://pl.wikipedia.org/wiki/Kwarc\" target=\"_blank\" rel=\"noopener noreferrer\">kwarcu</a>. Kamień półszlachetny, używany w <a href=\"https://pl.wikipedia.org/wiki/Z%C5%82otnictwo\" target=\"_blank\" rel=\"noopener noreferrer\">jubilerstwie</a>. Jego nazwa pochodzi z <a href=\"https://pl.wikipedia.org/wiki/J%C4%99zyk_grecki\" target=\"_blank\" rel=\"noopener noreferrer\">języka greckiego</a> i oznacza „trzeźwy” (ἀ- <i>a</i> – ‘nie’, μέθυστος <i>méthystos</i> – ‘pijany’), gdyż według greckich wierzeń, picie <a href=\"https://pl.wikipedia.org/wiki/Wino\" target=\"_blank\" rel=\"noopener noreferrer\">wina</a> z czar ametystowych zabezpieczało pijącego przed upiciem się.", "Adana": "<b>Adana</b> – żeńskie <a href=\"https://pl.wikipedia.org/wiki/Imi%C4%99\" target=\"_blank\" rel=\"noopener noreferrer\">imię</a> pochodzenia hebrajskiego o znaczeniu \"ziemia\". Obecnie rzadko jest nadawane.", "Asumpta": "<b>Asumpta</b> – <a href=\"https://pl.wikipedia.org/wiki/Imi%C4%99\" target=\"_blank\" rel=\"noopener noreferrer\">imię</a> żeńskie pochodzenia <a href=\"https://pl.wikipedia.org/wiki/%C5%81ac.\" target=\"_blank\" rel=\"noopener noreferrer\">łacińskiego</a>, nadawane w nawiązaniu do wniebowzięcia Marii, Matki Boskiej.", "Arlanda": "W marcu 2026 roku lotnisko Arlanda w Sztokholmie obsłużyło prawie 1,9 mln pasażerów, co oznacza wzrost o około 5 proc. w porównaniu z analogicznym miesiącem rok wcześniej. Jak podała Swedavia&#65279;<a href=\"https://www.wikidata.org/wiki/Q1571428#sitelinks-wikipedia\" target=\"_blank\" rel=\"noopener noreferrer\">(inne języki)</a>, wzrost objął zarówno ruch międzynarodowy, jak i krajowy. W segmencie zagranicznym obsłużono nieco ponad 1,5 mln pasażerów, a w krajowym blisko 378 tys. osób. Według tych samych danych przez dziesięć lotnisk spółki przewinęło się w marcu około 2,6 mln pasażerów, co również oznacza wzrost o nieco ponad 5 proc. w ujęciu rocznym."};
